// Handler pentru Unhandled Promise Rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('❌ [UNHANDLED REJECTION] Serverul a prins o eroare necaptată:');
  console.error('📍 Promise:', promise);
  console.error('⚠️ Motiv:', reason);
  
  // Log stack trace dacă există
  if (reason && reason.stack) {
    console.error('📚 Stack Trace:', reason.stack);
  }
  
  // NU oprim serverul - continuăm să rulăm
  console.log('✅ Serverul continuă să ruleze (eroarea a fost logată)');
});

// Handler pentru Uncaught Exceptions
process.on('uncaughtException', (error) => {
  console.error('❌ [UNCAUGHT EXCEPTION] Serverul a prins o excepție necaptată:');
  console.error('⚠️ Eroare:', error.message);
  console.error('📚 Stack Trace:', error.stack);
  
  // Pentru erori critice (ex: EADDRINUSE), oprim serverul
  if (error.code === 'EADDRINUSE' || error.code === 'EACCES') {
    console.error('🔴 Eroare critică - serverul trebuie repornit');
    process.exit(1);
  }
  
  // Pentru alte erori (ex: SQLite), continuăm
  console.log('✅ Serverul continuă să ruleze (eroarea a fost logată)');
});

// Handler pentru Warning-uri
process.on('warning', (warning) => {
  if (warning.name !== 'DeprecationWarning') {
    console.warn('⚠️ [WARNING]', warning.name, '-', warning.message);
  }
});

