/**
 * Invalidare centralizată a cache-ului
 * @param {string|string[]} entities - Entități de invalidat ('menu', 'ingredients', 'recipes', 'all')
 * @param {boolean} reload - Dacă true, reîncarcă cache-ul imediat după invalidare
 */
async function invalidateCache(entities = 'all', reload = false) {
  const entitiesToInvalidate = Array.isArray(entities) ? entities : [entities];
  
  console.log(`🔄 [CACHE INVALIDATION] Invalidare cache: ${entitiesToInvalidate.join(', ')}`);
  
  if (entitiesToInvalidate.includes('all')) {
    menuCache.lastUpdated = 0;
    console.log('   ✅ Cache complet invalidat');
  } else {
    // Invalidare selectivă - setăm timestamp la 0 pentru forțarea reîncărcării
    menuCache.lastUpdated = 0;
    console.log(`   ✅ Cache invalidat pentru: ${entitiesToInvalidate.join(', ')}`);
  }
  
  // 🔔 Emite eveniment WebSocket pentru invalidare cache
  if (typeof io !== 'undefined' && io) {
    try {
      io.emit('cache-invalidated', {
        entities: entitiesToInvalidate,
        timestamp: new Date().toISOString(),
        reload: reload
      });
      console.log('   📡 Eveniment WebSocket emis: cache-invalidated');
    } catch (wsError) {
      console.warn('   ⚠️ Eroare la emit WebSocket:', wsError.message);
    }
  }
  
  if (reload) {
    await loadMenuCache();
    console.log('   ✅ Cache reîncărcat automat');
    
    // 🔔 Emite eveniment WebSocket pentru reîncărcare cache
    if (typeof io !== 'undefined' && io) {
      try {
        io.emit('cache-reloaded', {
          entities: entitiesToInvalidate,
          timestamp: new Date().toISOString(),
          productCount: menuCache.products?.length || 0
        });
        console.log('   📡 Eveniment WebSocket emis: cache-reloaded');
      } catch (wsError) {
        console.warn('   ⚠️ Eroare la emit WebSocket:', wsError.message);
      }
    }
  }
}

// Export pentru utilizare în alte module
global.invalidateCache = invalidateCache;

// Funcție pentru încărcarea cache-ului
async function loadMenuCache() {
  const now = Date.now();
  
  // FIX: Verifică dacă menuCache există și e valid
  if (menuCache && menuCache.lastUpdated && now - menuCache.lastUpdated < CACHE_LIFETIME && menuCache.products.length > 0) {
    return menuCache; // Cache-ul este încă valid
  }

  console.log('🔄 Reîncarc cache-ul meniului...');
  const db = await dbPromise;
  
  try {
    // Încarcă produsele
    const products = await new Promise((resolve, reject) => {
      db.all(`SELECT id, name, category, price, description, weight, is_vegetarian, is_spicy, is_takeout_only, allergens, name_en, description_en, category_en, allergens_en, info, ingredients, prep_time, spice_level, calories, protein, carbs, fat, fiber, sodium, sugar, salt, image_url, stock_management, preparation_section FROM menu WHERE is_sellable = 1 ORDER BY category, name`, (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });

    // Încarcă categoriile unice
    const categories = [...new Set(products.map(p => p.category))].sort();

    // Încarcă meniul zilei
    const today = new Date().toISOString().split('T')[0];
    const dailyMenu = await new Promise((resolve, reject) => {
      db.get(`SELECT * FROM daily_menu WHERE date = ?`, [today], (err, row) => {
        if (err) reject(err);
        else resolve(row);
      });
    });

    // Încarcă ingredientele (cu TOATE coloanele nutriționale) - ETAPA 1: adăugat location_id
    const ingredients = await new Promise((resolve, reject) => {
      db.all(`SELECT id, name, unit, current_stock, min_stock, cost_per_unit, supplier, category, is_available, is_hidden, name_en, category_en, description, energy_kcal, fat, saturated_fat, carbs, sugars, protein, salt, fiber, allergens, additives, potential_allergens, location_id FROM ingredients ORDER BY category, name`, (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });

    // Încarcă rețetele (inclusiv coloanele F.T.P.)
    const recipes = await new Promise((resolve, reject) => {
      db.all(`SELECT r.id, r.product_id, r.ingredient_id, r.quantity_needed, r.unit, r.waste_percentage, r.variable_consumption, r.item_type, r.created_at, m.name as product_name, i.name as ingredient_name, i.unit as ingredient_unit FROM recipes r LEFT JOIN menu m ON r.product_id = m.id LEFT JOIN ingredients i ON r.ingredient_id = i.id ORDER BY r.product_id`, (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });

    // Actualizează cache-ul
    menuCache = {
      products,
      categories,
      dailyMenu,
      ingredients,
      recipes,
      lastUpdated: now
    };

    console.log(`✅ Cache reîncărcat: ${products.length} produse, ${categories.length} categorii, ${ingredients.length} ingrediente, ${recipes.length} rețete`);
    
    // 🔔 Emite eveniment WebSocket când cache-ul se reîncarcă automat
    if (typeof io !== 'undefined' && io) {
      try {
        io.emit('cache-reloaded', {
          entities: ['all'],
          timestamp: new Date().toISOString(),
          productCount: products.length,
          categoryCount: categories.length,
          autoReload: true
        });
      } catch (wsError) {
        // Ignoră eroarea dacă WebSocket nu este inițializat încă
      }
    }
    
    return menuCache;
  } catch (error) {
    console.error('❌ Eroare la încărcarea cache-ului:', error);
    return menuCache; // Returnează cache-ul vechi în caz de eroare
  }
}

