/**
 * Mapare preparation_section → location_id
 * @param {string} preparationSection - Secțiunea de preparare (ex: "Bucătărie", "Bar", "Pizzerie")
 * @returns {number|null} - ID-ul gestiunii corespunzătoare sau null pentru global
 */
async function getLocationIdFromPreparationSection(preparationSection) {
  if (!preparationSection) return 1; // Default: Gestiune Principal\u0103 (warehouse)
  
  const db = await dbPromise;
  
  // Mapare directă pentru valori cunoscute
  const sectionMapping = {
    'bucatarie': 'Bucătărie',
    'bar': 'Bar',
    'pizzerie': 'Pizzerie',
    'kitchen': 'Bucătărie',
    'grill': 'Grill'
  };
  
  // Normalizează secțiunea pentru căutare
  const normalizedSection = preparationSection.toLowerCase().trim();
  const mappedName = sectionMapping[normalizedSection] || preparationSection;
  
  try {
    // Caută gestiunea în baza de date
    const location = await new Promise((resolve, reject) => {
      db.get(`
        SELECT id, name, type 
        FROM management_locations 
        WHERE LOWER(name) LIKE ? AND is_active = 1
        LIMIT 1
      `, [`%${mappedName}%`], (err, row) => {
        if (err) reject(err);
        else resolve(row);
      });
    });
    
    if (location) {
      console.log(`✅ [ETAPA 4] Mapare: "${preparationSection}" → Location ID ${location.id} (${location.name})`);
      return location.id;
    }
    
    // Fallback: Gestiune Principală
    console.warn(`⚠️ [ETAPA 4] Nu s-a găsit gestiune pentru "${preparationSection}", folosim gestiunea principală`);
    return 1;
    
  } catch (error) {
    console.error(`❌ [ETAPA 4] Eroare la mapare preparation_section:`, error);
    return 1; // Fallback la gestiunea principală
  }
}

// Helper functions for dashboard metrics
async function getTodayOrders(today) {
    const db = await dbPromise;
    return new Promise((resolve, reject) => {
        // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
        const now = new Date();
        const currentHour = now.getHours();
        
        let startTime, endTime;
        if (currentHour >= 8) {
            // Dacă este după 08:00, intervalul este de azi 08:00 la mâine 03:00
            startTime = new Date(now);
            startTime.setHours(8, 0, 0, 0);
            endTime = new Date(now);
            endTime.setDate(endTime.getDate() + 1);
            endTime.setHours(3, 0, 0, 0);
        } else {
            // Dacă este înainte de 08:00, intervalul este de ieri 08:00 la azi 03:00
            startTime = new Date(now);
            startTime.setDate(startTime.getDate() - 1);
            startTime.setHours(8, 0, 0, 0);
            endTime = new Date(now);
            endTime.setHours(3, 0, 0, 0);
        }
        
        db.get('SELECT COUNT(*) as count FROM orders WHERE created_at >= ? AND created_at <= ?', 
            [startTime.toISOString(), endTime.toISOString()], (err, row) => {
            if (err) reject(err);
            else resolve(row.count);
        });
    });
}

