async function getRevenueHistory() {
    const db = await dbPromise;
    return new Promise((resolve, reject) => {
        // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
        const now = new Date();
        const currentHour = now.getHours();
        
        let startTime, endTime;
        if (currentHour >= 8) {
            // Dacă este după 08:00, intervalul este de azi 08:00 la mâine 03:00
            startTime = new Date(now);
            startTime.setHours(8, 0, 0, 0);
            endTime = new Date(now);
            endTime.setDate(endTime.getDate() + 1);
            endTime.setHours(3, 0, 0, 0);
        } else {
            // Dacă este înainte de 08:00, intervalul este de ieri 08:00 la azi 03:00
            startTime = new Date(now);
            startTime.setDate(startTime.getDate() - 1);
            startTime.setHours(8, 0, 0, 0);
            endTime = new Date(now);
            endTime.setHours(3, 0, 0, 0);
        }
        
        db.all(`
            SELECT 
                strftime('%H', created_at) as hour,
                SUM(total) as revenue
            FROM orders 
            WHERE created_at >= ? AND created_at <= ? AND is_paid = 1
            GROUP BY strftime('%H', created_at)
            ORDER BY hour
        `, [startTime.toISOString(), endTime.toISOString()], (err, rows) => {
            if (err) reject(err);
            else {
                const history = [];
                for (let i = 0; i < 24; i++) {
                    const hour = i.toString().padStart(2, '0');
                    const data = rows.find(r => r.hour === hour);
                    history.push({
                        time: hour + ':00',
                        revenue: data ? data.revenue : 0
                    });
                }
                resolve(history);
            }
        });
    });
}

