// ==================== FUNCȚII UTITARE APLICAȚIE RESTAURANT (NIR, FISCALE, STOC) ====================

/**
 * Funcție helper pentru parsing-ul sigur al JSON-ului din items
 * @param {string} itemsString - String-ul JSON cu items
 * @returns {Array} Array-ul de items sau array gol în caz de eroare
 */
function safeParseItems(itemsString) {
  try {
    if (!itemsString) return [];
    
    // Încearcă parsing-ul direct
    return JSON.parse(itemsString);
  } catch (error) {
    try {
      // Dacă eșuează, încearcă să curățe caracterele problematice
      let cleaned = itemsString;
      
      // Gestionare caractere escape invalide - înlocuiește cu escape corect
      cleaned = cleaned
        .replace(/\\/g, '\\\\')  // Escape backslashes
        .replace(/"/g, '\\"')    // Escape quotes
        .replace(/\n/g, '\\n')   // Escape newlines
        .replace(/\r/g, '\\r')  // Escape carriage returns
        .replace(/\t/g, '\\t');  // Escape tabs
      
      return JSON.parse(cleaned);
    } catch (secondError) {
      try {
        // Al treilea încercare - curățare mai agresivă
        let cleaned = itemsString;
        
        // Înlocuiește caracterele problematice cu versiuni sigure
        cleaned = cleaned
          .replace(/\\"/g, '"')  // Fix escaped quotes
          .replace(/\\n/g, ' ')  // Replace newlines with spaces
          .replace(/\\r/g, ' ')  // Replace carriage returns with spaces
          .replace(/\\t/g, ' ')  // Replace tabs with spaces
          .replace(/\\/g, '')    // Remove remaining backslashes
          .replace(/\s+/g, ' ')  // Normalize whitespace
          .trim();
        
        return JSON.parse(cleaned);
      } catch (thirdError) {
        try {
          // Ultima încercare - parsing manual pentru cazuri extreme
          console.warn('⚠️ Încercare parsing manual pentru items JSON');
          
          // Încearcă să extrage doar datele esențiale
          const items = [];
          const matches = itemsString.match(/\{[^}]*\}/g);
          
          if (matches) {
            matches.forEach(match => {
              try {
                const item = JSON.parse(match);
                items.push(item);
              } catch (e) {
                // Ignoră items-urile care nu pot fi parsate
              }
            });
          }
          
          return items;
        } catch (finalError) {
          console.warn('⚠️ Eroare la parsarea items JSON:', finalError.message);
          console.warn('⚠️ Items string:', itemsString.substring(0, 200) + '...');
          return [];
        }
      }
    }
  }
}

// ==================== FUNCȚII UTITARE RAPOARTE ====================

/**
 * Agreghează o listă de bonuri fiscale pentru a genera sumarul necesar (Venit, TVA, Defalcare).
 * @param {sqlite3.Database} db - Instanța bazei de date.
 * @param {Array<object>} receipts - Lista de bonuri fiscale.
 * @returns {object} Sumarul agregat.
 */
async function aggregateReceipts(db, receipts) {
    console.log(`📊 [aggregateReceipts] Procesare ${receipts?.length || 0} bonuri...`);
    
    // Validare input
    if (!receipts || !Array.isArray(receipts)) {
        console.warn('⚠️ [aggregateReceipts] Input invalid - receipts nu este array');
        receipts = [];
    }
    
    let totalRevenue = 0;
    let totalVat = 0;
    // Inițializare standard pentru cotele de TVA din România
    const vatBreakdown = { '21': 0, '11': 0, '5': 0, '0': 0 };
    const paymentMethods = {}; // { cash: { amount: 0, count: 0 }, card: { amount: 0, count: 0 }, ... }
    
    let processedCount = 0;
    let errorCount = 0;

    for (const receipt of receipts) {
        try {
            // Validare date bon nefiscal
            if (!receipt || typeof receipt !== 'object') {
                console.warn('⚠️ [aggregateReceipts] Bon invalid (nu este obiect):', receipt);
                errorCount++;
                continue;
            }
            
            // Validare și conversie total_amount
            const amount = parseFloat(receipt.total_amount);
            if (isNaN(amount) || amount < 0) {
                console.warn(`⚠️ [aggregateReceipts] Bon ${receipt.id}: total_amount invalid (${receipt.total_amount})`);
                errorCount++;
                continue;
            }
            
            // Validare și conversie vat_amount
            const vatAmount = parseFloat(receipt.vat_amount || 0);
            if (isNaN(vatAmount) || vatAmount < 0) {
                console.warn(`⚠️ [aggregateReceipts] Bon ${receipt.id}: vat_amount invalid (${receipt.vat_amount})`);
                errorCount++;
                continue;
            }
            
            totalRevenue += amount;
            totalVat += vatAmount;
            
            // Defalcare pe metode de plată
            const method = receipt.payment_method || 'unknown';
            if (!paymentMethods[method]) {
                paymentMethods[method] = { amount: 0, count: 0 };
            }
            paymentMethods[method].amount += amount;
            paymentMethods[method].count += 1;

            // Defalcare pe cote de TVA
            try {
                // Presupunem că bonul are detalii TVA (vat_details) stocate ca JSON
                if (receipt.vat_details && typeof receipt.vat_details === 'string') {
                    const vatDetails = JSON.parse(receipt.vat_details);
                    if (vatDetails && typeof vatDetails === 'object') {
                        for (const rateKey in vatBreakdown) {
                            // Adunăm TVA-ul colectat pe fiecare cotă (ex: vat_details.vat21_amount)
                            const vatValue = parseFloat(vatDetails[`vat${rateKey}_amount`] || 0);
                            if (!isNaN(vatValue) && vatValue >= 0) {
                                vatBreakdown[rateKey] += vatValue;
                            }
                        }
                    } else {
                        // Fallback: atribuim tot TVA-ul pe cota de 21% dacă detaliile nu sunt valide
                        vatBreakdown['21'] += vatAmount;
                    }
                } else {
                    // Fallback: atribuim tot TVA-ul pe cota de 21% dacă lipsesc detaliile
                    vatBreakdown['21'] += vatAmount;
                }
            } catch (e) {
                console.error(`❌ [aggregateReceipts] Bon ${receipt.id}: Eroare parsare vat_details:`, e.message);
                // Dacă eșuează, folosim fallback-ul
                vatBreakdown['21'] += vatAmount;
            }
            
            processedCount++;
        } catch (receiptError) {
            console.error(`❌ [aggregateReceipts] Eroare procesare bon ${receipt?.id}:`, receiptError);
            errorCount++;
        }
    }
    
    // Validare finală și protecție împotriva NaN
    const safeTotalRevenue = isNaN(totalRevenue) ? 0 : totalRevenue;
    const safeTotalVat = isNaN(totalVat) ? 0 : totalVat;
    
    // Asigurare că toate valorile din vatBreakdown sunt valide
    for (const key in vatBreakdown) {
        if (isNaN(vatBreakdown[key]) || vatBreakdown[key] < 0) {
            console.warn(`⚠️ [aggregateReceipts] Corecție VAT ${key}%: ${vatBreakdown[key]} → 0`);
            vatBreakdown[key] = 0;
        }
    }
    
    console.log(`✅ [aggregateReceipts] Procesare completă: ${processedCount} bonuri procesate, ${errorCount} erori`);
    console.log(`💰 [aggregateReceipts] Total: ${safeTotalRevenue.toFixed(2)} RON, TVA: ${safeTotalVat.toFixed(2)} RON`);
    
    return {
        totalRevenue: parseFloat(safeTotalRevenue.toFixed(2)),
        totalVat: parseFloat(safeTotalVat.toFixed(2)),
        vatBreakdown: vatBreakdown,
        paymentMethods: paymentMethods,
        count: processedCount,
        errors: errorCount
    };
}

/**
 * Generează numere secvențiale unice pentru NIR, Facturi și Bonuri de Casă (RC) pe baza anului curent.
 * Format: PREFIX-AN-NUMĂR (ex: NIR-2025-0001)
 */
async function generateFiscalNumber(type) {
    const db = await dbPromise;
    const currentYear = new Date().getFullYear();
    let prefix, tableName, numberColumn;

    switch (type) {
        case 'NIR':
            prefix = 'NIR';
            tableName = 'nir_documents';
            numberColumn = 'nir_number';
            break;
        case 'INVOICE':
            prefix = 'INV';
            tableName = 'invoices';
            numberColumn = 'invoice_number';
            break;
        case 'RECEIPT':
        default:
            prefix = 'RC';
            tableName = 'fiscal_receipts';
            numberColumn = 'receipt_number';
            break;
    }

    try {
        // Folosește timestamp + MODERNecunde pentru a evita duplicatele
        const now = new Date();
        const timestamp = now.getTime().toString().slice(-8); // Ultimele 8 cifre
        const MODERNeconds = now.getMilliseconds().toString().padStart(3, '0');
        const randomSuffix = Math.floor(Math.random() * 1000).toString().padStart(3, '0');
        const newNumber = `${prefix}-${currentYear}-${timestamp}${MODERNeconds}${randomSuffix}`;
        
        console.log(`🔢 Generat număr fiscal ${type}: ${newNumber} (cu timestamp + MODERNecunde + random)`);
        return newNumber;

    } catch (error) {
        console.error(`Eroare la generarea numărului fiscal (${type}):`, error);
        // Fallback cu timestamp + random pentru a evita duplicatele
        const timestamp = Date.now().toString().slice(-8);
        const randomSuffix = Math.floor(Math.random() * 10000).toString().padStart(4, '0');
        return `${prefix}-${currentYear}-${timestamp}${randomSuffix}`;
    }
}

/**
 * Calculează Costul Mediu Ponderat (CAMP) după o intrare NIR și actualizează stocul și costul.
 * @param {string} product_type - 'menu_product' (marfă) sau 'ingredient' (materie primă)
 * @param {number} product_id - ID-ul produsului sau ingredientului
 * @param {number} quantity_added - Cantitatea primită pe NIR
 * @param {number} purchase_price_unit - Prețul de achiziție unitar (fără TVA)
 */
async function calculateCAMP(product_type, product_id, quantity_added, purchase_price_unit) {
    const db = await dbPromise;
    const isMenuProduct = product_type === 'menu_product';

    try {
        let currentData;
        let currentStock;
        let oldUnitCost;
        
        if (isMenuProduct) {
            // Pentru produse meniu: folosim stock_management pentru stoc și menu pentru cost
            let stockData = await new Promise((resolve, reject) => {
                db.get('SELECT current_stock FROM stock_management WHERE product_id = ?', [product_id], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });
            
            // Dacă nu există în stock_management, creează intrarea
            if (!stockData) {
                console.log(`🆕 Creez intrare în stock_management pentru produsul ${product_id}`);
                await new Promise((resolve, reject) => {
                    db.run('INSERT INTO stock_management (product_id, current_stock, daily_stock, min_stock_alert, is_available) VALUES (?, 0, 0, 5, 1)', [product_id], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
                stockData = { current_stock: 0 };
            }
            
            const costData = await new Promise((resolve, reject) => {
                db.get('SELECT cost_price FROM menu WHERE id = ?', [product_id], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });
            
            currentStock = stockData?.current_stock || 0;
            oldUnitCost = costData?.cost_price || 0;
        } else {
            // Pentru ingrediente: folosim ingredients
            currentData = await new Promise((resolve, reject) => {
                db.get('SELECT current_stock, cost_per_unit FROM ingredients WHERE id = ?', [product_id], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });
            
            currentStock = currentData?.current_stock || 0;
            oldUnitCost = currentData?.cost_per_unit || 0;
        }
        
        // Valoarea totală veche = Stoc curent × Cost vechi
        const oldTotalValue = currentStock * oldUnitCost;

        // 2. Calculează Noile Valori (adăugând intrarea NIR)
        const newTotalValue = oldTotalValue + (quantity_added * purchase_price_unit);
        const newTotalQuantity = currentStock + quantity_added;

        if (newTotalQuantity <= 0) {
            // Dacă stocul devine zero sau negativ (ajustare), setăm costul la zero și actualizăm cantitatea
            if (isMenuProduct) {
                await new Promise((resolve, reject) => {
                    db.run('UPDATE stock_management SET current_stock = ? WHERE product_id = ?', [newTotalQuantity, product_id], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
                await new Promise((resolve, reject) => {
                    db.run('UPDATE menu SET cost_price = 0.00 WHERE id = ?', [product_id], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
            } else {
                await new Promise((resolve, reject) => {
                    db.run('UPDATE ingredients SET current_stock = ?, cost_per_unit = 0.00 WHERE id = ?', [newTotalQuantity, product_id], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
            }
            return 0.00;
        }

        // 3. Calculează Noul CAMP
        const newCAMP = newTotalValue / newTotalQuantity;

        // 4. Actualizează Tabelele
        if (isMenuProduct) {
            // Actualizează stocul în stock_management și costul în menu
            await new Promise((resolve, reject) => {
                db.run('UPDATE stock_management SET current_stock = ? WHERE product_id = ?', [newTotalQuantity, product_id], (err) => {
                    if (err) reject(err);
                    else resolve();
                });
            });
            await new Promise((resolve, reject) => {
                db.run('UPDATE menu SET cost_price = ? WHERE id = ?', [newCAMP, product_id], (err) => {
                    if (err) reject(err);
                    else resolve();
                });
            });
        } else {
            // Actualizează în ingredients
            await new Promise((resolve, reject) => {
                db.run('UPDATE ingredients SET current_stock = ?, cost_per_unit = ? WHERE id = ?', [newTotalQuantity, newCAMP, product_id], (err) => {
                    if (err) reject(err);
                    else resolve();
                });
            });
        }
        
        console.log(`[CAMP] Actualizat pentru ID ${product_id} (${product_type}): ${oldUnitCost.toFixed(2)} -> ${newCAMP.toFixed(2)} RON`);
        return newCAMP;

    } catch (error) {
        console.error(`❌ Eroare la calculul CAMP pentru ${product_type} ID ${product_id}:`, error);
        return 0.00;
    }
}

/**
 * Scade stocurile pentru o comandă finalizată (la plată)
 * @param {number} orderId - ID-ul comenzii
 * @returns {Promise<{success: boolean, decremented: Array, warnings: Array}>}
 */
async function decrementStockForOrder(orderId) {
    const db = await dbPromise;
    const decrementedItems = [];
    const warnings = [];
    
    try {
        console.log(`🔍 [DECREMENT STOCK] Începe scăderea stocurilor pentru comanda #${orderId}`);
        
        // 1. Obține comanda și items
        const order = await new Promise((resolve, reject) => {
            db.get('SELECT items, table_number FROM orders WHERE id = ?', [orderId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!order) {
            throw new Error(`Comanda ${orderId} nu a fost găsită`);
        }
        
        const items = JSON.parse(order.items || '[]');
        console.log(`📦 [DECREMENT STOCK] Comanda #${orderId} are ${items.length} produse`);
        
        // 2. Pentru fiecare produs din comandă
        for (const item of items) {
            const productId = item.productId;
            const quantity = item.quantity;
            const productName = item.name || 'Produs necunoscut';
            
            if (!productId || !quantity) {
                warnings.push(`Produs fără ID sau cantitate: ${productName}`);
                continue;
            }
            
            // Skip produse gratuite (dar NU ambalaje - ambalajele trebuie scăzute)
            if (item.isFree && !item.isPackaging) {
                console.log(`🎁 [DECREMENT STOCK] Skip produs gratuit: ${productName}`);
                continue;
            }
            
            // 3. Obține rețeta produsului
            const recipes = await new Promise((resolve, reject) => {
                db.all(`
                    SELECT r.ingredient_id, r.quantity_needed, i.name, i.unit, i.current_stock
                    FROM recipes r
                    JOIN ingredients i ON r.ingredient_id = i.id
                    WHERE r.product_id = ?
                `, [productId], (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows || []);
                });
            });
            
            if (recipes.length === 0) {
                warnings.push(`Produsul "${productName}" (ID: ${productId}) nu are rețetă definită - stocul NU se scade`);
                console.warn(`⚠️ [DECREMENT STOCK] ${warnings[warnings.length - 1]}`);
                continue;
            }
            
            console.log(`📋 [DECREMENT STOCK] Produs "${productName}" × ${quantity} → ${recipes.length} ingrediente în rețetă`);
            
            // 4. Scade fiecare ingredient din rețetă
            for (const recipe of recipes) {
                const quantityToDecrement = recipe.quantity_needed * quantity;
                const newStock = recipe.current_stock - quantityToDecrement;
                
                // Verifică dacă există stoc suficient (doar avertizare, nu blocare)
                if (recipe.current_stock < quantityToDecrement) {
                    warnings.push(`Stoc insuficient pentru "${recipe.name}": disponibil ${recipe.current_stock.toFixed(2)}, necesar ${quantityToDecrement.toFixed(2)} ${recipe.unit}`);
                    console.warn(`⚠️ [DECREMENT STOCK] ${warnings[warnings.length - 1]}`);
                }
                
                // Scade stocul (permite stoc negativ pentru tracking)
                await new Promise((resolve, reject) => {
                    db.run(`
                        UPDATE ingredients 
                        SET current_stock = current_stock - ? 
                        WHERE id = ?
                    `, [quantityToDecrement, recipe.ingredient_id], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
                
                // Creează audit trail în stock_movements
                await new Promise((resolve, reject) => {
                    db.run(`
                        INSERT INTO stock_movements (
                            ingredient_id,
                            quantity_change,
                            movement_type,
                            reference_id,
                            notes,
                            created_at
                        ) VALUES (?, ?, 'sale', ?, ?, datetime('now', 'localtime'))
                    `, [
                        recipe.ingredient_id,
                        -quantityToDecrement, // Negativ pentru scădere
                        orderId.toString(),
                        `Vânzare: ${productName} × ${quantity} (Comandă #${orderId}, Masă ${order.table_number || 'N/A'})`
                    ], (err) => {
                        if (err) reject(err);
                        else resolve();
                    });
                });
                
                decrementedItems.push({
                    product: productName,
                    ingredient: recipe.name,
                    quantity: quantityToDecrement,
                    unit: recipe.unit,
                    oldStock: recipe.current_stock,
                    newStock: newStock
                });
                
                console.log(`✅ [DECREMENT STOCK] ${recipe.name}: ${recipe.current_stock.toFixed(2)} → ${newStock.toFixed(2)} ${recipe.unit} (-${quantityToDecrement.toFixed(2)})`);
            }
        }
        
        console.log(`✅ [DECREMENT STOCK] Finalizat pentru comanda #${orderId}: ${decrementedItems.length} ingrediente scăzute, ${warnings.length} avertizări`);
        
        return { 
            success: true, 
            decremented: decrementedItems,
            warnings: warnings,
            orderId: orderId
        };
        
    } catch (error) {
        console.error(`❌ [DECREMENT STOCK] Eroare la scăderea stocurilor pentru comanda ${orderId}:`, error);
        throw error;
    }
}

/**
 * Generează un PDF de Factură (sau Chitanță) bazat pe o comandă finalizată.
 * @param {object} documentData - Datele documentului (Factură sau Fiscal Receipt)
 * @param {Array} orderItems - Produsele din comanda aferentă
 * @param {string} type - 'invoice' sau 'receipt'
 * @returns {string} Calea către fișierul PDF generat.
 */
async function generateFiscalPDF(documentData, orderItems, type = 'invoice') {
    try {
        console.log('🔄 Încep generarea PDF-ului pentru:', documentData.receipt_number || documentData.invoice_number);
        console.log('📊 Date primite:', JSON.stringify(documentData, null, 2));
        console.log('📦 Items primite:', orderItems ? orderItems.length : 0);
        
        // Bon termic cu dimensiuni specifice (80mm x 200mm)
        const doc = new PDFDocument({ 
            size: [226.77, 566.93], // 80mm x 200mm în puncte (1mm = 2.834645669 points)
            margins: { top: 5, bottom: 5, left: 5, right: 5 }
        });
        const docPath = path.join(__dirname, 'public', 'documents', `${type}_${documentData.invoice_number || documentData.receipt_number}.pdf`);
        
        console.log('📁 Calea PDF:', docPath);
        
        // Asigură-te că directorul există
        const documentsDir = path.join(__dirname, 'public', 'documents');
        if (!fs.existsSync(documentsDir)) {
            console.log('📁 Creez directorul documents:', documentsDir);
            fs.mkdirSync(documentsDir, { recursive: true });
        }

        console.log('📄 Creez stream-ul pentru PDF...');
        // Setările de bază ale documentului
        const writeStream = fs.createWriteStream(docPath);
        doc.pipe(writeStream);
        
        console.log('✅ Stream-ul PDF creat cu succes');
    
    // ==================== FUNCȚIE PENTRU CONVERSIA CARACTERELOR ROMÂNEȘTI ====================
    // (definiția funcției se află mai sus în același scope)
    
    // ==================== ÎNCĂRCARE CONFIGURAȚIE RESTAURANT ====================
    let restaurantConfig = {
        restaurant_name: 'RESTAURANT TRATTORIA',
        restaurant_address: 'Strada Principala 123, Sector 1, Bucuresti',
        restaurant_phone: '021.123.4567',
        restaurant_cui: 'RO12345678',
        vat_food: '11',
        vat_drinks: '21'
    };
    
    try {
        const db = await dbPromise;
        const config = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM app_settings WHERE key = ?', ['restaurant_config'], (err, row) => {
                if (err) {
                    console.error('❌ Eroare la query configurație restaurant:', err);
                    reject(err);
                } else {
                    resolve(row);
                }
            });
        });
        
        if (config && config.value) {
            restaurantConfig = JSON.parse(config.value);
            // Aplică convertRomanianChars la toate textele din configurație
            restaurantConfig.restaurant_name = convertRomanianChars(restaurantConfig.restaurant_name);
            restaurantConfig.restaurant_address = convertRomanianChars(restaurantConfig.restaurant_address);
            if (restaurantConfig.restaurant_phone) {
                restaurantConfig.restaurant_phone = convertRomanianChars(restaurantConfig.restaurant_phone);
            }
            console.log('✅ Configurația restaurantului încărcată pentru PDF');
        } else {
            console.log('ℹ️ Se folosește configurația implicită pentru PDF');
        }
    } catch (error) {
        console.error('❌ Eroare la încărcarea configurației pentru PDF:', error);
        console.log('ℹ️ Se folosește configurația implicită pentru PDF');
    }
    
    // ==================== FUNCȚIE PENTRU CONVERSIA CARACTERELOR ROMÂNEȘTI ====================
    function convertRomanianChars(text) {
        if (!text) return '';
        return text
            .replace(/ă/g, 'a').replace(/Ă/g, 'A')
            .replace(/â/g, 'a').replace(/Â/g, 'A')
            .replace(/î/g, 'i').replace(/Î/g, 'I')
            .replace(/ș/g, 's').replace(/Ș/g, 'S')
            .replace(/ț/g, 't').replace(/Ț/g, 'T')
            .replace(/ţ/g, 't').replace(/Ţ/g, 'T')  // Adaugă și varianta cu cedilă
            .replace(/ş/g, 's').replace(/Ş/g, 'S'); // Adaugă și varianta cu cedilă
    }
    
    // ==================== 1. DENUMIREA FIRMEI, ADRESA, COD FISCAL ====================
    // Folosește font monospaced pentru aliniere corectă
    doc.font('Courier').fontSize(10).text(convertRomanianChars(restaurantConfig.restaurant_name), { align: 'center' });
    doc.moveDown(0.3);
    
    // Adresa postala
    doc.fontSize(8).text(convertRomanianChars(restaurantConfig.restaurant_address), { align: 'center' });
    doc.moveDown(0.2);
    
    // Cod postal (daca exista)
    if (restaurantConfig.restaurant_postal_code) {
        doc.fontSize(8).text(convertRomanianChars(restaurantConfig.restaurant_postal_code), { align: 'center' });
        doc.moveDown(0.2);
    }
    
    // Cod fiscal C.I.F.
    doc.fontSize(8).text(`C.I.F.: ${restaurantConfig.restaurant_cui}`, { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== INFORMATII COMANDA ====================
    doc.fontSize(8).text(`Comanda Nr: ${documentData.order_id || 'N/A'}`, { align: 'center' });
    
    // Masa (daca exista)
    if (documentData.table_number) {
        doc.fontSize(8).text(`Masa: ${documentData.table_number}`, { align: 'center' });
    }
    
    // Tip comanda (daca exista)
    if (documentData.order_type) {
        const orderTypeText = documentData.order_type === 'takeout' ? 'Comanda la pachet' : 
                              documentData.order_type === 'delivery' ? 'Comanda la domiciliu' : 
                              'Comanda impreuna';
        doc.fontSize(8).text(`Tip: ${orderTypeText}`, { align: 'center' });
    }
    
    // Data si ora
    const orderDate = documentData.order_date || documentData.issue_date || new Date();
    const orderDateTime = new Date(orderDate).toLocaleString('ro-RO');
    doc.fontSize(8).text(`Data: ${orderDateTime}`, { align: 'center' });
    
    doc.moveDown(0.3);
    doc.text('--------------------------------', { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 2. SECTIUNEA DE PRODUSE (LAYOUT PE O LINIE) ====================
    let subtotal = 0;
    let totalVAT11 = 0; // TVA 11% pentru alimente
    let totalVAT21 = 0; // TVA 21% pentru băuturi alcoolice
    
    // Categorii cu TVA 11% (alimente)
    const foodCategories = [
        'Aperitive', 'Aperitive Calde', 'Aperitive Reci', 'Burgeri', 'Ciorbe', 
        'Deserturi', 'Fel Principal', 'Garnituri', 'Mic Dejun', 'Paste', 
        'Paste Fresca', 'Penne Al Forno', 'Peste Fructe de Mare', 'Pizza', 
        'Platouri', 'Salate', 'Salate Însoțitoare'
    ];
    
    // Categorii cu TVA 21% (băuturi alcoolice și alte produse)
    const alcoholCategories = ['Băuturi și Coctailuri'];
    
    orderItems.forEach(item => {
        // Layout compact pentru bon termic
        const itemPrice = item.finalPrice || item.price || 0;
        const itemQuantity = item.quantity || 1;
        const itemTotal = item.total_price || (itemPrice * itemQuantity);
        const nameText = `${itemQuantity}x ${convertRomanianChars(item.name || 'Produs necunoscut')}`;
        const priceStr = `${(itemTotal || 0).toFixed(2)} RON`;
        
        // Pentru bon termic, folosește layout simplu pe o linie
        const lineText = `${nameText.padEnd(35)} ${priceStr}`;
        doc.fontSize(7).text(lineText);
        
        // Afișează customizările dacă există
        if (item.customizations && item.customizations.length > 0) {
            item.customizations.forEach(custom => {
                doc.fontSize(6).text(`  - ${convertRomanianChars(custom.name)}`);
            });
        }
        
        // Determină categoria TVA pe baza categoriei produsului
        const vatFoodRate = parseFloat(restaurantConfig.vat_food || '11') / 100;
        const vatDrinksRate = parseFloat(restaurantConfig.vat_drinks || '21') / 100;
        
        let vatRate = vatFoodRate; // Default pentru alimente
        if (alcoholCategories.includes(item.category)) {
            vatRate = vatDrinksRate; // Băuturi alcoolice
        } else if (item.category === 'Cafea/Ciocolată/Ceai' || item.category === 'Răcoritoare') {
            vatRate = vatDrinksRate; // Băuturi non-alcoolice
        }
        
        // Calculeaza subtotal si TVA pe categorii
        const unitPrice = itemPrice / (1 + vatRate);
        const itemVAT = itemTotal - (unitPrice * itemQuantity);
        
        subtotal += unitPrice * itemQuantity;
        
        if (vatRate === vatFoodRate) {
            totalVAT11 += itemVAT;
        } else {
            totalVAT21 += itemVAT;
        }
        
        doc.moveDown(0.2); // Spațiere redusă între produse
    });
    
    doc.moveDown(0.3);
    doc.text('--------------------------------', { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 3. SUBTOTAL ====================
    doc.fontSize(7).text(`Subtotal: ${subtotal.toFixed(2)} RON`, { align: 'center' });
    doc.moveDown(0.2);
    
    // ==================== 4. TOTAL ====================
    const totalAmount = documentData.total_amount || subtotal + totalVAT11 + totalVAT21;
    doc.fontSize(8).text(`Total: ${totalAmount.toFixed(2)} RON`, { align: 'center' });
    doc.moveDown(0.2);
    
    // ==================== 5. TOTAL TVA ====================
    const totalVAT = totalVAT11 + totalVAT21;
    doc.fontSize(7).text(`Total TVA: ${totalVAT.toFixed(2)} RON`, { align: 'center' });
    doc.moveDown(0.2);
    
    // ==================== 6. TVA A (ALIMENTE) ====================
    if (totalVAT11 > 0) {
        doc.fontSize(7).text(`TVA A ${restaurantConfig.vat_food || '11'}%: ${totalVAT11.toFixed(2)} RON`, { align: 'center' });
        doc.moveDown(0.2);
    }
    
    // ==================== 7. TVA B (BAUTURI) ====================
    if (totalVAT21 > 0) {
        doc.fontSize(7).text(`TVA B ${restaurantConfig.vat_drinks || '21'}%: ${totalVAT21.toFixed(2)} RON`, { align: 'center' });
        doc.moveDown(0.2);
    }
    
    doc.text('--------------------------------', { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 7. METODA DE PLATA ====================
    const paymentMethod = documentData.payment_method || 'cash';
    const paymentText = paymentMethod === 'cash' ? 'NUMERAR' : 'CARD';
    doc.fontSize(7).text(`Metoda de plata: ${paymentText}`, { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 8. CHITANTA CLIENT ====================
    doc.fontSize(7).text('Chitanta client', { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 9. ID:XXXXX, MID:XXXXXX etc. ====================
    doc.fontSize(6).text(`ID: ${documentData.receipt_number || documentData.invoice_number}`, { align: 'center' });
    doc.fontSize(6).text(`MID: ${restaurantConfig.restaurant_cui}`, { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 10. DETALIILE CASA 01 ====================
    doc.fontSize(6).text('Detaliile casa 01', { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 11. DATA SI ORA ====================
    const now = new Date();
    const currentDateTime = now.toLocaleString('ro-RO');
    doc.fontSize(6).text(`Data si ora: ${currentDateTime}`, { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 12. BON NEFISCAL ====================
    const receiptTitle = type === 'invoice' ? 'FACTURA FISCALA' : 'BON NEFISCAL';
    doc.fontSize(8).text(receiptTitle, { align: 'center' });
    doc.moveDown(0.3);
    
    // ==================== 13. COD QR ====================
    try {
        // Creează datele pentru codul QR
        const receiptNumber = documentData.receipt_number || documentData.invoice_number;
        const qrData = {
            receipt_number: receiptNumber,
            restaurant_name: restaurantConfig.restaurant_name,
            restaurant_cui: restaurantConfig.restaurant_cui,
            total_amount: documentData.total_amount,
            date: documentData.order_date || documentData.issue_date || new Date().toISOString(),
            type: type,
            // Adaugă link-ul către bonul fiscal
            pdf_url: `http://localhost:3000/documents/${type}_${receiptNumber}.pdf`,
            // Adaugă link-ul către API pentru detalii
            api_url: `http://localhost:3000/api/fiscal/receipt-details/${receiptNumber}`
        };
        
        // Generează codul QR ca string JSON
        const qrString = JSON.stringify(qrData);
        
        // Generează codul QR ca buffer - dimensiuni optimizate pentru citire mobilă
        const qrBuffer = await QRCode.toBuffer(qrString, {
            width: 200, // Dimensiune mărită pentru citire mai ușoară
            margin: 4, // Margin mărit pentru separare mai bună
            color: {
                dark: '#000000',
                light: '#FFFFFF'
            },
            errorCorrectionLevel: 'M' // Nivel de corecție erori pentru citire mai bună
        });
        
        // Adaugă codul QR în PDF - centrat și dimensionat corespunzător
        doc.image(qrBuffer, {
            width: 80, // Dimensiune mărită pentru citire mai ușoară
            height: 80,
            align: 'center'
        });
        
        doc.moveDown(0.2);
        doc.fontSize(6).text('Cod QR pentru verificare', { align: 'center' });
        doc.fontSize(5).text('Scanează cu telefonul pentru detalii', { align: 'center' });
        doc.moveDown(0.3);
        
    } catch (error) {
        console.error('Eroare la generarea codului QR:', error);
        // Continuă fără codul QR dacă apare o eroare
    }
    
    // ==================== 14. VA MULTUMIM ====================
    doc.fontSize(7).text('VA MULTUMIM', { align: 'center' });
       
        console.log('🔄 Finalizez PDF-ul...');
        doc.end();
        
        // Așteaptă ca stream-ul să se închidă complet
        await new Promise((resolve, reject) => {
            writeStream.on('finish', resolve);
            writeStream.on('error', reject);
        });

        console.log(`📄 PDF generat cu succes: ${docPath}`);
        
        // Verifică dacă fișierul există
        if (fs.existsSync(docPath)) {
            console.log(`✅ Fișierul PDF există: ${docPath}`);
            const stats = fs.statSync(docPath);
            console.log(`📊 Dimensiunea fișierului: ${stats.size} bytes`);
        } else {
            console.error(`❌ Fișierul PDF nu există: ${docPath}`);
        }
        
        return docPath;
        
    } catch (error) {
        console.error('❌ Eroare la generarea PDF-ului:', error);
        console.error('❌ Stack trace:', error.stack);
        throw error;
    }
}

