// Funcție pentru a determina ospătarul responsabil pentru o masă
function getWaiterIdForTable(tableNumber) {
  const tableNum = parseInt(tableNumber);
  if (isNaN(tableNum)) return null;
  
  // Verifică în alocările implicite
  for (const [waiterId, tables] of Object.entries(DEFAULT_TABLE_ALLOCATIONS)) {
    if (tables.includes(tableNum)) {
      return parseInt(waiterId);
    }
  }
  
  return null;
}

// Funcție îmbunătățită pentru a determina ospătarul responsabil pentru o masă (cu verificare admin)
async function getWaiterIdForTableAsync(tableNumber) {
  const tableNum = parseInt(tableNumber);
  if (isNaN(tableNum)) return null;
  
  try {
    // Verifică mai întâi în baza de date (setările din admin)
    const db = await dbPromise;
    const waiters = await new Promise((resolve, reject) => {
      db.all('SELECT * FROM waiters', (err, rows) => {
        if (err) reject(err);
        else resolve(rows);
      });
    });
    
    // Caută în setările din admin
    for (const waiter of waiters) {
      if (waiter.tables) {
        const tables = JSON.parse(waiter.tables || '[]');
        if (tables.includes(tableNum)) {
          return parseInt(waiter.id);
        }
      }
    }
    
    // Dacă nu găsește în admin, folosește alocările implicite
    for (const [waiterId, tables] of Object.entries(DEFAULT_TABLE_ALLOCATIONS)) {
      if (tables.includes(tableNum)) {
        return parseInt(waiterId);
      }
    }
    
    return null;
  } catch (error) {
    console.error('Eroare la verificarea ospătarului pentru masa:', tableNumber, error);
    // În caz de eroare, folosește funcția sincronă
    return getWaiterIdForTable(tableNumber);
  }
}

// Funcție pentru formatarea timpului în fusul orar al României
function formatToLocalTime(date) {
  const options = { 
    timeZone: 'Europe/Bucharest', 
    hour12: false, 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit', 
    hour: '2-digit', 
    minute: '2-digit', 
    second: '2-digit' 
  };
  return new Date(date).toLocaleString('ro-RO', options);
}

