// 1. HELMET - Security Headers (Protecție XSS, Clickjacking, etc.)
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'", "https://cdn.jsdelivr.net", "https://unpkg.com"],
      scriptSrcAttr: ["'unsafe-inline'"], // ✅ PERMITE onclick, onload, etc.
      styleSrc: ["'self'", "'unsafe-inline'", "https://cdn.jsdelivr.net", "https://fonts.googleapis.com", "https://cdnjs.cloudflare.com"],
      fontSrc: ["'self'", "https://fonts.gstatic.com", "https://cdnjs.cloudflare.com", "data:"],
      imgSrc: ["'self'", "data:", "https:", "blob:"],
      connectSrc: ["'self'", "https://api.openai.com", "https://cdn.jsdelivr.net"],
      frameSrc: ["'self'"],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: []
    }
  },
  crossOriginEmbedderPolicy: false, // Permite încărcare resurse cross-origin
  crossOriginResourcePolicy: { policy: "cross-origin" }
}));
console.log('🛡️ Helmet security headers activate');

// 2. COMPRESSION - Compresie gzip pentru răspunsuri
app.use(compression({
  filter: (req, res) => {
    if (req.headers['x-no-compression']) {
      return false;
    }
    return compression.filter(req, res);
  },
  level: 6 // Nivel compresie (0-9, 6 = default balanced)
}));
console.log('⚡ Response compression activată');

// 3. CORS - Cross-Origin Resource Sharing
app.use(cors({
  origin: ['http://localhost:3001', 'http://127.0.0.1:3001'],
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  credentials: true
}));
console.log('🌐 CORS configurat');

// 4. JSON Parser cu limită de mărime
app.use(express.json({ limit: '10mb' }));
app.use(express.urlencoded({ extended: true, limit: '10mb' }));

// 5. Static Files cu cache control
app.use(express.static('public', {
  maxAge: '1h', // Cache 1 oră pentru fișiere statice
  etag: true,
  lastModified: true,
  setHeaders: (res, path) => {
    if (path.endsWith('.html')) {
      // HTML nu se cache-ază
      res.setHeader('Cache-Control', 'no-cache, no-store, must-revalidate');
    } else if (path.match(/\.(jpg|jpeg|png|gif|webp|svg)$/)) {
      // Imagini cache 1 an
      res.setHeader('Cache-Control', 'public, max-age=31536000, immutable');
    } else if (path.match(/\.(css|js)$/)) {
      // CSS/JS cache 1 zi
      res.setHeader('Cache-Control', 'public, max-age=86400');
    }
  }
}));

