// ==================== GESTIONARE SESIUNI CLIENT (PRIORITATE ÎNALTĂ) ====================
// Gestionare sesiuni client
const clientSessions = new Map(); // tableNumber -> { clients: Map(clientToken -> clientIdentifier), nextId: number }

app.post('/api/session/start', (req, res) => {
  const { tableNumber, clientToken, socketId } = req.body;
  
  if (!tableNumber || !clientToken) {
    return res.status(400).json({ error: 'TableNumber și clientToken sunt obligatorii.' });
  }
  
  // Inițializează sesiunea pentru masa respectivă dacă nu există
  if (!clientSessions.has(tableNumber)) {
    clientSessions.set(tableNumber, {
      clients: new Map(),
      nextId: 1
    });
  }
  
  const tableSession = clientSessions.get(tableNumber);
  
  // Verifică dacă clientToken-ul există deja
  if (tableSession.clients.has(clientToken)) {
    const clientIdentifier = tableSession.clients.get(clientToken);
    
    // Actualizează socketId-ul în activeClientSessions
    if (socketId) {
      if (!activeClientSessions[tableNumber]) {
        activeClientSessions[tableNumber] = [];
      }
      // Șterge sesiunea veche dacă există
      activeClientSessions[tableNumber] = activeClientSessions[tableNumber].filter(s => s.identifier !== clientIdentifier);
      // Adaugă sesiunea nouă
      activeClientSessions[tableNumber].push({ identifier: clientIdentifier, socketId });
    }
    
    return res.json({ 
      success: true, 
      clientIdentifier: clientIdentifier,
      message: 'Client re-identificat cu succes'
    });
  }
  
  // Generează un nou clientIdentifier - reciclează identificatorii disponibili
  let clientIdentifier;
  
  // Găsește primul identificator disponibil
  const usedIdentifiers = new Set(Array.from(tableSession.clients.values()));
  
  // Caută primul identificator liber (A, B, C, ..., Z, apoi AB, AC, etc.)
  for (let id = 1; id <= 26; id++) {
    const identifier = String.fromCharCode(64 + id); // A, B, C, ..., Z
    if (!usedIdentifiers.has(identifier)) {
      clientIdentifier = identifier;
      break;
    }
  }
  
  // Dacă toate sunt ocupate, folosește numărul
  if (!clientIdentifier) {
    clientIdentifier = `Client${tableSession.nextId}`;
    tableSession.nextId++;
  }
  
  // Salvează clientToken -> clientIdentifier
  tableSession.clients.set(clientToken, clientIdentifier);
  
  // Salvează în activeClientSessions
  if (socketId) {
    if (!activeClientSessions[tableNumber]) {
      activeClientSessions[tableNumber] = [];
    }
    activeClientSessions[tableNumber].push({ identifier: clientIdentifier, socketId });
  }
  
  res.json({ 
    success: true, 
    clientIdentifier: clientIdentifier,
    message: 'Client identificat cu succes'
  });
});

