// 1. CONNECTION LIMITER - PREVINE OVERLOAD (PRIORITATEA #1)
app.use((req, res, next) => {
    if (activeConnections >= MAX_CONNECTIONS) {
        console.log(`🚨 CONNECTION LIMIT REACHED: ${activeConnections}/${MAX_CONNECTIONS}`);
        return res.status(503).json({
            error: 'Server ocupat. Încercați în 10-20 secunde.',
            activeConnections,
            maxConnections: MAX_CONNECTIONS,
            retryAfter: 20
        });
    }
    
    activeConnections++;
    // console.log(`📊 Conexiuni active: ${activeConnections}/${MAX_CONNECTIONS}`);
    
    // Folosim o singură funcție de cleanup pentru a evita decrementarea dublă
    let cleanedUp = false;
    const cleanup = () => {
        if (!cleanedUp) {
            cleanedUp = true;
            activeConnections = Math.max(0, activeConnections - 1); // Previne valori negative
            // console.log(`📊 Conexiuni active: ${activeConnections}/${MAX_CONNECTIONS}`);
        }
    };
    
    res.on('finish', cleanup);
    res.on('close', cleanup);
    next();
});

