// WebSocket Events
io.on('connection', (socket) => {
  console.log('Client conectat:', socket.id);

  // Înregistrare client într-o cameră specifică (kitchen, bar, waiter_1, etc.)
  socket.on('register', (data) => {
    if (data && data.role && data.id) {
      const roomName = `${data.role}_${data.id}`;
      socket.join(roomName);
      console.log(`Clientul ${socket.id} s-a înregistrat și a intrat în camera: ${roomName}`);
    }
  });

  // Dashboard subscription
  socket.on('subscribe-dashboard', (widgets) => {
    socket.join('admin-dashboard');
    console.log('Dashboard client subscris:', socket.id, widgets);
  });
  
  socket.on('disconnect', () => {
    console.log('Client deconectat:', socket.id);
    // Șterge socket-ul din activeClientSessions
    for (const tableNumber in activeClientSessions) {
      activeClientSessions[tableNumber] = activeClientSessions[tableNumber].filter(s => s.socketId !== socket.id);
    }
  });

  socket.on('callWaiter', async (data) => {
    console.log(`Masa ${data.tableNumber} (Client ${data.clientIdentifier || 'N/A'}) cere: ${data.requestType}`);
    
    // Dacă este cerere de notă, calculează totalul
    if (data.requestType === 'bill' && data.clientIdentifier) {
      try {
        const db = await dbPromise; // ✅ Obține conexiunea la baza de date
        
        db.all('SELECT * FROM orders WHERE table_number = ? AND client_identifier = ? AND is_paid = 0', 
          [data.tableNumber, data.clientIdentifier], (err, orders) => {
          if (err) {
            console.error('Eroare la calcularea totalului:', err);
            return;
          }
          
          let totalAmount = 0;
          let itemCount = 0;
          
          orders.forEach(order => {
            try {
              const items = safeParseItems(order.items);
              items.forEach(item => {
                totalAmount += item.finalPrice * item.quantity;
                itemCount += item.quantity;
              });
            } catch (e) {
              console.error('Eroare la parsarea items:', e);
            }
          });
          
          // Emite notificarea cu totalul calculat
          const enhancedData = {
            ...data,
            totalAmount: totalAmount,
            itemCount: itemCount
          };
          
          io.emit('waiterCalled', enhancedData);
          
          // Salvează notificarea în baza de date
          const type = 'bill';
          const title = 'Solicitare notă de plată';
          const title_en = 'Bill Request';
          const details = data.paymentMethod ? ` (${data.paymentMethod})` : '';
          const clientInfo = ` - Client ${data.clientIdentifier}`;
          const message = `Masă ${data.tableNumber}${clientInfo}${details} - Total: ${totalAmount.toFixed(2)} RON (${itemCount} produse)`;
          const message_en = `Table ${data.tableNumber}${clientInfo}${details} - Total: ${totalAmount.toFixed(2)} RON (${itemCount} items)`;
          
          db.run(
            'INSERT INTO notifications (type, table_number, order_id, title, message, status) VALUES (?, ?, NULL, ?, ?, ?)',
            [type, String(data.tableNumber || ''), title, message, 'unread'],
            function(err) {
              if (!err) {
              io.emit('notification:new', {
                id: this.lastID,
                type,
                table_number: String(data.tableNumber || ''),
                client_identifier: data.clientIdentifier,
                order_id: null,
                title,
                title_en,
                message,
                message_en,
                totalAmount: totalAmount,
                itemCount: itemCount,
                status: 'unread',
                created_at: new Date().toISOString(),
              });
            } else {
              console.error('Eroare la inserarea notificării:', err);
            }
          }
        );
        });
      } catch (error) {
        console.error('Eroare la obținerea conexiunii la baza de date:', error);
      }
    } else {
      // Pentru cereri de asistență sau cereri fără clientIdentifier
      io.emit('waiterCalled', data);
      
      try {
        const db = await dbPromise; // ✅ Obține conexiunea la baza de date
        
        const type = data.requestType === 'bill' ? 'bill' : (data.requestType === 'order' ? 'order' : 'assistance');
        const title = type === 'bill' ? 'Solicitare notă de plată' : (type === 'order' ? 'Solicitare Comandă' : 'Solicitare asistență');
        const title_en = type === 'bill' ? 'Bill Request' : (type === 'order' ? 'Order Request' : 'Assistance Request');
        const details = data.paymentMethod ? ` (${data.paymentMethod})` : '';
        const clientInfo = data.clientIdentifier ? ` - Client ${data.clientIdentifier}` : '';
        const message = data.requestType === 'order' ? 
            `Masa ${data.tableNumber} solicită comandă la ospătar` :
            (data.requestType === 'assistance' ? 
                `Masa ${data.tableNumber} solicită asistență` :
                `Masă ${data.tableNumber}${clientInfo}${details}`);
        const message_en = data.requestType === 'order' ? 
            `Table ${data.tableNumber} requests order with waiter` :
            (data.requestType === 'assistance' ? 
                `Table ${data.tableNumber} requests assistance` :
                `Table ${data.tableNumber}${clientInfo}${details}`);
        
        db.run(
          'INSERT INTO notifications (type, table_number, order_id, title, message, status) VALUES (?, ?, NULL, ?, ?, ?)',
          [type, String(data.tableNumber || ''), title, message, 'unread'],
          function(err) {
            if (!err) {
              io.emit('notification:new', {
                id: this.lastID,
                type,
                table_number: String(data.tableNumber || ''),
                client_identifier: data.clientIdentifier || null,
                order_id: null,
                title,
                title_en,
                message,
                message_en,
                status: 'unread',
                created_at: new Date().toISOString(),
              });
            } else {
              console.error('Eroare la inserarea notificării:', err);
            }
          }
        );
      } catch (error) {
        console.error('Eroare la obținerea conexiunii la baza de date:', error);
      }
    }
  });
});

