// Helper pentru a formata data pe server in format ro-RO
function formatOrderTimestamps(order) {
    order.timestamp_ro = formatToLocalTime(new Date(order.timestamp));
    if (order.completed_timestamp) {
        order.completed_timestamp_ro = formatToLocalTime(new Date(order.completed_timestamp));
    }
    if (order.delivered_timestamp) {
        order.delivered_timestamp_ro = formatToLocalTime(new Date(order.delivered_timestamp));
    }
    if (order.cancelled_timestamp) {
        order.cancelled_timestamp_ro = formatToLocalTime(new Date(order.cancelled_timestamp));
    }
    return order;
}

function formatOrderTimestampsLang(order, lang) {
  const out = { ...order };
  if (order.timestamp) out.timestamp_formatted = formatToLocalTime(new Date(order.timestamp));
  if (order.completed_timestamp) out.completed_timestamp_formatted = formatToLocalTime(new Date(order.completed_timestamp));
  if (order.delivered_timestamp) out.delivered_timestamp_formatted = formatToLocalTime(new Date(order.delivered_timestamp));
  return out;
}

