    // VERIFICARE STOC ÎNAINTE DE VÂNZARE - ETAPA 4: Include location_id
    const checkStockAvailability = async (items) => {
      try {
        const db = await dbPromise;
        const stockIssues = [];
        
        for (const item of items) {
          const productId = item.productId || item.id;
          if (!productId) continue;
          
          // ETAPA 4: Obține preparation_section pentru produs
          const product = await new Promise((resolve, reject) => {
            db.get(`SELECT preparation_section FROM menu WHERE id = ?`, [productId], (err, row) => {
              if (err) reject(err);
              else resolve(row);
            });
          });
          
          // ETAPA 4: Determină location_id din preparation_section
          const locationId = product && product.preparation_section 
            ? await getLocationIdFromPreparationSection(product.preparation_section)
            : 1; // Default: Gestiune Principală
          
          console.log(`🔍 [Check Stock] Produs #${productId} → Location ID: ${locationId}`);
          
          // Obține rețeta pentru produs
          const recipes = await new Promise((resolve, reject) => {
            db.all(`
              SELECT r.ingredient_id, r.quantity_needed, i.name as ingredient_name, i.current_stock, i.min_stock, i.unit, i.location_id
              FROM recipes r
              JOIN ingredients i ON r.ingredient_id = i.id
              WHERE r.product_id = ?
            `, [productId], (err, rows) => {
              if (err) reject(err);
              else resolve(rows || []);
            });
          });
          
          if (recipes.length === 0) {
            console.warn(`⚠️ Produsul ${item.name} (ID: ${productId}) nu are rețetă definită`);
            continue;
          }
          
          // Verifică fiecare ingredient din rețetă
          // ETAPA 4: Filtrează doar ingredientele din gestiunea corespunzătoare
          for (const recipe of recipes) {
            // Doar ingredientele din gestiunea corectă
            if (recipe.location_id !== locationId) {
              console.log(`⚠️ Skip ingredient ${recipe.ingredient_name} (în location ${recipe.location_id}, nu ${locationId})`);
              continue;
            }
            
            const neededQuantity = recipe.quantity_needed * item.quantity;
            const availableStock = recipe.current_stock;
            
            if (availableStock < neededQuantity) {
              const shortage = neededQuantity - availableStock;
              stockIssues.push({
                productName: item.name,
                ingredientName: recipe.ingredient_name,
                needed: neededQuantity,
                available: availableStock,
                shortage: shortage,
                unit: recipe.unit,
                minStock: recipe.min_stock,
                locationId: locationId // ETAPA 4: Include location_id în problema
              });
            }
          }
        }
        
        return stockIssues;
      } catch (error) {
        console.error('❌ Eroare la verificarea stocului:', error);
        return [];
      }
    };

