  app.get('/api/allergens/by-product/:productId', async (req, res) => {
    try {
      const { productId } = req.params;
      
      // Verifică dacă produsul are allergens_computed
      db.get('SELECT allergens_computed FROM menu WHERE id = ?', [productId], (err, product) => {
        if (err || !product) {
          return res.status(404).json({ error: 'Produs negăsit' });
        }
        
        let allergenCodes = [];
        try {
          allergenCodes = JSON.parse(product.allergens_computed || '[]');
        } catch (e) {
          allergenCodes = [];
        }
        
        if (allergenCodes.length === 0) {
          return res.json({ success: true, data: [] });
        }
        
        // Obține detalii alergeni
        const placeholders = allergenCodes.map(() => '?').join(',');
        const query = `SELECT * FROM allergens WHERE code IN (${placeholders}) AND is_active = 1 ORDER BY sort_order ASC`;
        
        db.all(query, allergenCodes, (err, rows) => {
          if (err) {
            console.error('❌ Error fetching allergens for product:', err);
            return res.status(500).json({ error: err.message });
          }
          
          console.log(`✅ GET /api/allergens/by-product/${productId}: ${rows.length} alergeni`);
          res.json({ success: true, data: rows || [] });
        });
      });
    } catch (error) {
      console.error('❌ Error in GET /api/allergens/by-product:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
