  // ==================== HELPER FUNCTIONS ====================
  
  // Recalculare alergeni pentru toate produsele care conțin un ingredient
  function recalculateProductAllergens(ingredientId) {
    // Găsește toate produsele care au acest ingredient în rețetă
    db.all(
      `SELECT DISTINCT r.menu_item_id 
       FROM recipes r 
       WHERE r.ingredient_id = ?`,
      [ingredientId],
      (err, products) => {
        if (err || !products || products.length === 0) return;
        
        products.forEach(product => {
          updateProductAllergensComputed(product.menu_item_id);
        });
      }
    );
  }
  
  // Actualizare coloana allergens_computed pentru un produs
  function updateProductAllergensComputed(productId) {
    // Găsește toți alergenii din ingredientele rețetei
    const query = `
      SELECT DISTINCT a.code
      FROM allergens a
      INNER JOIN ingredient_allergens ia ON a.id = ia.allergen_id
      INNER JOIN recipes r ON ia.ingredient_id = r.ingredient_id
      WHERE r.menu_item_id = ? AND a.is_active = 1
      ORDER BY a.sort_order ASC
    `;
    
    db.all(query, [productId], (err, allergens) => {
      if (err) {
        console.error('❌ Error calculating allergens for product:', err);
        return;
      }
      
      const allergenCodes = allergens.map(a => a.code);
      const allergensJSON = JSON.stringify(allergenCodes);
      
      db.run(
        'UPDATE menu SET allergens_computed = ? WHERE id = ?',
        [allergensJSON, productId],
        function(err) {
          if (err) {
            console.error('❌ Error updating allergens_computed:', err);
          } else {
            console.log(`✅ Alergeni actualizați pentru produs ${productId}: ${allergensJSON}`);
          }
        }
      );
    });
  }
  
  // POST /api/allergens/recalculate-all - Recalculare alergeni pentru toate produsele
  app.post('/api/allergens/recalculate-all', checkAdminAuth, async (req, res) => {
    try {
      // Găsește toate produsele cu rețete
      db.all('SELECT DISTINCT menu_item_id FROM recipes', [], (err, products) => {
        if (err) {
          console.error('❌ Error fetching products:', err);
          return res.status(500).json({ error: err.message });
        }
        
        let processed = 0;
        products.forEach(product => {
          updateProductAllergensComputed(product.menu_item_id);
          processed++;
        });
        
        console.log(`✅ Recalculare alergeni pentru ${processed} produse`);
        res.json({ success: true, processed: processed });
      });
    } catch (error) {
      console.error('❌ Error in POST /api/allergens/recalculate-all:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
