  // POST /api/suppliers/:id/rate - Evaluare furnizor
  app.post('/api/suppliers/:id/rate', checkAdminAuth, async (req, res) => {
    try {
      const { id } = req.params;
      const { quality, delivery, price, service } = req.body;
      
      if (!quality || !delivery || !price || !service) {
        return res.status(400).json({ error: 'Toate rating-urile sunt obligatorii (1-5 stele)' });
      }
      
      // Calculare medie
      const avg = (parseFloat(quality) + parseFloat(delivery) + parseFloat(price) + parseFloat(service)) / 4;
      
      db.run(
        `UPDATE suppliers 
         SET rating_quality = ?, rating_delivery = ?, rating_price = ?, rating_service = ?, 
             rating_avg = ?, total_reviews = total_reviews + 1, updated_at = datetime('now', 'localtime')
         WHERE id = ?`,
        [quality, delivery, price, service, avg, id],
        function(err) {
          if (err) {
            console.error('❌ Error rating supplier:', err);
            return res.status(500).json({ error: err.message });
          }
          
          console.log(`✅ Furnizor evaluat: ID ${id} - Rating mediu: ${avg.toFixed(1)}`);
          res.json({ success: true, rating_avg: avg });
        }
      );
    } catch (error) {
      console.error('❌ Error in POST /api/suppliers/:id/rate:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
