  // GET /api/waste - Listă pierderi
  app.get('/api/waste', async (req, res) => {
    try {
      const { startDate, endDate, waste_type, location_id, limit } = req.query;
      
      let query = 'SELECT * FROM waste_logs WHERE 1=1';
      const params = [];
      
      if (startDate && endDate) {
        query += ' AND DATE(waste_date) BETWEEN ? AND ?';
        params.push(startDate, endDate);
      }
      
      if (waste_type) {
        query += ' AND waste_type = ?';
        params.push(waste_type);
      }
      
      if (location_id) {
        query += ' AND location_id = ?';
        params.push(location_id);
      }
      
      query += ' ORDER BY waste_date DESC, reported_at DESC';
      
      if (limit) {
        query += ` LIMIT ${parseInt(limit)}`;
      } else {
        query += ' LIMIT 500';
      }
      
      db.all(query, params, (err, rows) => {
        if (err) {
          console.error('❌ Error fetching waste logs:', err);
          return res.status(500).json({ error: err.message });
        }
        
        console.log(`✅ GET /api/waste: ${rows.length} pierderi`);
        res.json({ success: true, data: rows || [] });
      });
    } catch (error) {
      console.error('❌ Error in GET /api/waste:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // POST /api/waste - Raportare pierdere nouă
  app.post('/api/waste', checkAdminAuth, async (req, res) => {
    try {
      const { waste_type, waste_reason, item_type, item_id, item_name, quantity, unit_of_measure, unit_cost, location_id, description, reported_by, waste_date } = req.body;
      
      if (!waste_type || !waste_reason || !item_name || !quantity || !waste_date) {
        return res.status(400).json({ error: 'Câmpuri obligatorii lipsă' });
      }
      
      const total_cost = (unit_cost || 0) * quantity;
      
      db.run(
        `INSERT INTO waste_logs (waste_type, waste_reason, item_type, item_id, item_name, quantity, unit_of_measure, unit_cost, total_cost, location_id, reported_by, description, waste_date)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [waste_type, waste_reason, item_type || 'ingredient', item_id || null, item_name, quantity, unit_of_measure || 'buc', unit_cost || 0, total_cost, location_id || null, reported_by || 'Admin', description || null, waste_date],
        function(err) {
          if (err) {
            console.error('❌ Error creating waste log:', err);
            return res.status(500).json({ error: err.message });
          }
          
          console.log(`✅ Waste raportată: ${item_name} - ${quantity} ${unit_of_measure || 'buc'} - ${total_cost.toFixed(2)} RON`);
          res.json({ success: true, id: this.lastID });
        }
      );
    } catch (error) {
      console.error('❌ Error in POST /api/waste:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
  // GET /api/waste/dashboard - Dashboard statistics
  app.get('/api/waste/dashboard', async (req, res) => {
    try {
      const { period } = req.query; // 'today', 'week', 'month'
      
      let dateFilter = '';
      const params = [];
      
      if (period === 'today') {
        dateFilter = 'AND DATE(waste_date) = DATE("now", "localtime")';
      } else if (period === 'week') {
        dateFilter = 'AND DATE(waste_date) >= DATE("now", "localtime", "-7 days")';
      } else if (period === 'month') {
        dateFilter = 'AND DATE(waste_date) >= DATE("now", "localtime", "-30 days")';
      }
      
      // Total waste value
      db.get(`SELECT SUM(total_cost) as total_waste FROM waste_logs WHERE 1=1 ${dateFilter}`, params, (err, totalRow) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        // Waste per type
        db.all(`SELECT waste_type, COUNT(*) as count, SUM(total_cost) as total FROM waste_logs WHERE 1=1 ${dateFilter} GROUP BY waste_type`, params, (err2, typeRows) => {
          if (err2) {
            return res.status(500).json({ error: err2.message });
          }
          
          // Top 10 produse cu waste
          db.all(`SELECT item_name, SUM(quantity) as total_quantity, SUM(total_cost) as total_cost, COUNT(*) as incidents FROM waste_logs WHERE 1=1 ${dateFilter} GROUP BY item_name ORDER BY total_cost DESC LIMIT 10`, params, (err3, topProducts) => {
            if (err3) {
              return res.status(500).json({ error: err3.message });
            }
            
            console.log(`✅ GET /api/waste/dashboard: Total waste = ${(totalRow.total_waste || 0).toFixed(2)} RON`);
            
            res.json({
              success: true,
              data: {
                total_waste: totalRow.total_waste || 0,
                by_type: typeRows || [],
                top_products: topProducts || []
              }
            });
          });
        });
      });
    } catch (error) {
      console.error('❌ Error in GET /api/waste/dashboard:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
