  // GET /api/export/orders - Export comenzi în JSON/CSV
  app.get('/api/export/orders', checkAdminAuth, async (req, res) => {
    try {
      const { format = 'json', startDate, endDate } = req.query;
      
      let query = 'SELECT * FROM orders WHERE 1=1';
      const params = [];
      
      if (startDate) {
        query += ' AND DATE(timestamp) >= ?';
        params.push(startDate);
      }
      
      if (endDate) {
        query += ' AND DATE(timestamp) <= ?';
        params.push(endDate);
      }
      
      query += ' ORDER BY timestamp DESC LIMIT 10000';
      
      db.all(query, params, (err, orders) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        if (format === 'csv') {
          // Generate CSV
          const headers = ['ID', 'Timestamp', 'Table', 'Total', 'Status', 'Is Paid'];
          const rows = orders.map(o => [
            o.id,
            o.timestamp,
            o.table_number || 'Takeout',
            o.total_price,
            o.status,
            o.is_paid ? 'DA' : 'NU'
          ]);
          
          const csv = [headers, ...rows].map(r => r.join(',')).join('\n');
          
          res.setHeader('Content-Type', 'text/csv');
          res.setHeader('Content-Disposition', `attachment; filename="orders-${new Date().toISOString().split('T')[0]}.csv"`);
          res.send(csv);
          
          console.log(`✅ Export CSV: ${orders.length} comenzi`);
        } else {
          // JSON
          res.json({ success: true, data: orders, count: orders.length });
          console.log(`✅ Export JSON: ${orders.length} comenzi`);
        }
      });
    } catch (error) {
      console.error('❌ Error in GET /api/export/orders:', error);
      res.status(500).json({ error: error.message });
    }
  });
  
