  // POST /api/fiscal/print-receipt - Emitere bon fiscal pentru comandă
  app.post('/api/fiscal/print-receipt', checkAdminAuth, async (req, res) => {
    try {
      const { order_id } = req.body;
      
      if (!order_id) {
        return res.status(400).json({ error: 'order_id este obligatoriu' });
      }
      
      // Obține comanda
      const order = await new Promise((resolve, reject) => {
        db.get('SELECT * FROM orders WHERE id = ?', [order_id], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      if (!order) {
        return res.status(404).json({ error: 'Comandă negăsită' });
      }
      
      // Parse items din JSON
      const items = JSON.parse(order.items || '[]');
      
      // Mapare comandă → bon fiscal
      const receipt = {
        order_id: order.id,
        table_number: order.table_number,
        timestamp: order.timestamp,
        total: parseFloat(order.total_price) || 0,
        payment_method: order.payment_method || 'cash',
        items: items.map(item => ({
          name: item.name || item.item,
          quantity: item.quantity || 1,
          unit_price: item.price || 0,
          vat_rate: 21, // Default: TVA 21%
          department: '1'
        }))
      };
      
      // Verifică dacă e conectat la casă fiscală
      if (!fiscalPrinter || !fiscalPrinter.isConnected) {
        console.log('⚠️ Casa fiscală nu e conectată - Simulare bon fiscal');
        
        // SIMULATE în sandbox mode
        const receiptNumber = 'BON-' + Date.now();
        
        // Salvează în fiscal_receipts
        db.run(
          `INSERT INTO fiscal_receipts (receipt_number, order_id, total_amount, vat_amount, payment_method, vat_21, waiter_id, is_fiscal)
           VALUES (?, ?, ?, ?, ?, ?, ?, 1)`,
          [
            receiptNumber,
            order.id,
            receipt.total,
            receipt.total * 0.21 / 1.21, // Aproximare TVA
            receipt.payment_method,
            receipt.total * 0.8, // Aproximare bază TVA 21%
            order.waiter_id || null
          ],
          function(err) {
            if (err) {
              return res.status(500).json({ error: err.message });
            }
            
            console.log(`✅ Bon fiscal SIMULAT: ${receiptNumber}`);
            
            res.json({
              success: true,
              simulated: true,
              receipt_number: receiptNumber,
              fiscal_id: this.lastID,
              message: 'Bon fiscal simulat (casă fiscală neconectată)'
            });
          }
        );
      } else {
        // REAL print la casa fiscală
        const result = await fiscalPrinter.printFiscalReceipt(receipt);
        
        // Salvează în DB
        db.run(
          `INSERT INTO fiscal_receipts (receipt_number, order_id, total_amount, vat_amount, payment_method, vat_21, waiter_id, is_fiscal, transmitted_to_anaf)
           VALUES (?, ?, ?, ?, ?, ?, ?, 1, 1)`,
          [
            result.receiptNumber,
            order.id,
            receipt.total,
            receipt.total * 0.21 / 1.21,
            receipt.payment_method,
            receipt.total * 0.8,
            order.waiter_id || null
          ],
          function(err) {
            if (err) {
              return res.status(500).json({ error: err.message });
            }
            
            console.log(`✅ Bon fiscal emis: ${result.receiptNumber}`);
            
            res.json({
              success: true,
              receipt_number: result.receiptNumber,
              fiscal_memory_number: result.fiscalMemoryNumber,
              fiscal_id: this.lastID,
              transmitted_to_anaf: true
            });
          }
        );
      }
      
    } catch (error) {
      console.error('❌ Error printing fiscal receipt:', error);
      res.status(500).json({
        success: false,
        error: 'Eroare la emiterea bonului fiscal',
        details: error.message
      });
    }
  });
  
