  // Obține mesele alocate pentru un ospătar (prin ID numeric)
  app.get('/api/waiter/:waiterId/tables', (req, res) => {
    const waiterId = parseInt(req.params.waiterId);
    
    if (waiterId < 1 || waiterId > 10) {
      return res.status(400).json({ error: 'ID ospătar invalid. Trebuie să fie între 1 și 10.' });
    }
    
    // Verifică mai întâi dacă există setări în baza de date din admin
    db.get('SELECT * FROM waiters WHERE id = ?', [waiterId], (err, waiter) => {
      if (err) {
        console.error('Eroare la verificarea ospătarului:', err);
        // În caz de eroare, folosește alocarea implicită
        const tables = DEFAULT_TABLE_ALLOCATIONS[waiterId] || [];
        return res.json({ 
          waiterId: waiterId,
          waiterName: `Ospătar ${waiterId}`,
          tables: tables,
          tableRange: tables.length > 0 ? `${tables[0]}-${tables[tables.length - 1]}` : 'Niciuna',
          source: 'default'
        });
      }
      
      if (waiter && waiter.tables) {
        // Folosește setările din admin
        const tables = JSON.parse(waiter.tables || '[]');
        return res.json({ 
          waiterId: waiterId,
          waiterName: waiter.name || `Ospătar ${waiterId}`,
          tables: tables,
          tableRange: tables.length > 0 ? `${tables[0]}-${tables[tables.length - 1]}` : 'Niciuna',
          source: 'admin'
        });
      } else {
        // Dacă nu există setări în admin, folosește alocarea implicită
        const tables = DEFAULT_TABLE_ALLOCATIONS[waiterId] || [];
        return res.json({ 
          waiterId: waiterId,
          waiterName: `Ospătar ${waiterId}`,
          tables: tables,
          tableRange: tables.length > 0 ? `${tables[0]}-${tables[tables.length - 1]}` : 'Niciuna',
          source: 'default'
        });
      }
    });
  });

  // Actualizează alocarea mesei pentru un ospătar (pentru admin)
  app.put('/api/waiter/:waiterId/tables', (req, res) => {
    const waiterId = parseInt(req.params.waiterId);
    const { tables } = req.body;
    
    if (waiterId < 1 || waiterId > 10) {
      return res.status(400).json({ error: 'ID ospătar invalid. Trebuie să fie între 1 și 10.' });
    }
    
    if (!Array.isArray(tables) || tables.length === 0) {
      return res.status(400).json({ error: 'Lista de mese este obligatorie și nu poate fi goală.' });
    }
    
    // Validează că toate mesele sunt între 1 și 200
    const invalidTables = tables.filter(table => !Number.isInteger(table) || table < 1 || table > 200);
    if (invalidTables.length > 0) {
      return res.status(400).json({ error: `Mese invalide: ${invalidTables.join(', ')}. Mesele trebuie să fie între 1 și 200.` });
    }
    
    // Verifică dacă ospătarul există în baza de date
    db.get('SELECT * FROM waiters WHERE id = ?', [waiterId], (err, waiter) => {
      if (err) {
        console.error('Eroare la verificarea ospătarului:', err);
        return res.status(500).json({ error: 'Eroare la verificarea ospătarului' });
      }
      
      if (waiter) {
        // Actualizează ospătarul existent
        db.run('UPDATE waiters SET tables = ? WHERE id = ?', 
          [JSON.stringify(tables), waiterId], 
          function(err) {
            if (err) {
              console.error('Eroare la actualizarea ospătarului:', err);
              return res.status(500).json({ error: 'Eroare la actualizarea ospătarului' });
            }
            
            // Actualizează și alocarea implicită în memorie ca backup
            DEFAULT_TABLE_ALLOCATIONS[waiterId] = tables;
            
            res.json({ 
              success: true,
              message: `Alocarea mesei pentru ospătarul ${waiterId} a fost actualizată în baza de date.`,
              waiterId: waiterId,
              tables: tables,
              tableRange: `${Math.min(...tables)}-${Math.max(...tables)}`
            });
          });
      } else {
        // Creează un ospătar nou cu mesele specificate
        db.run('INSERT INTO waiters (id, name, pin, tables, active) VALUES (?, ?, ?, ?, ?)',
          [waiterId, `Ospătar ${waiterId}`, '0000', JSON.stringify(tables), 1],
          function(err) {
            if (err) {
              console.error('Eroare la crearea ospătarului:', err);
              return res.status(500).json({ error: 'Eroare la crearea ospătarului' });
            }
            
            // Actualizează și alocarea implicită în memorie ca backup
            DEFAULT_TABLE_ALLOCATIONS[waiterId] = tables;
            
            res.json({ 
              success: true,
              message: `Ospătarul ${waiterId} a fost creat cu alocarea mesei specificată.`,
              waiterId: waiterId,
              tables: tables,
              tableRange: `${Math.min(...tables)}-${Math.max(...tables)}`
            });
          });
      }
    });
  });

  // Obține toate alocările mesei (pentru admin)
  app.get('/api/waiters/tables', (req, res) => {
    // Obține toate ospătarii din baza de date
    db.all('SELECT * FROM waiters ORDER BY id', (err, waiters) => {
      if (err) {
        console.error('Eroare la încărcarea ospătari:', err);
        return res.status(500).json({ error: 'Eroare la încărcarea ospătari' });
      }
      
      const allocations = {};
      
      // Procesează ospătarii din baza de date
      waiters.forEach(waiter => {
        const tables = JSON.parse(waiter.tables || '[]');
        allocations[waiter.id] = {
          waiterId: waiter.id,
          waiterName: waiter.name || `Ospătar ${waiter.id}`,
          tables: tables,
          tableRange: tables.length > 0 ? 
            `${tables[0]}-${tables[tables.length - 1]}` : 
            'Niciuna',
          source: 'admin'
        };
      });
      
      // Completează cu ospătarii care nu sunt în baza de date (folosește valorile implicite)
      for (let i = 1; i <= 10; i++) {
        if (!allocations[i]) {
          allocations[i] = {
            waiterId: i,
            waiterName: `Ospătar ${i}`,
            tables: DEFAULT_TABLE_ALLOCATIONS[i] || [],
            tableRange: DEFAULT_TABLE_ALLOCATIONS[i] ? 
              `${DEFAULT_TABLE_ALLOCATIONS[i][0]}-${DEFAULT_TABLE_ALLOCATIONS[i][DEFAULT_TABLE_ALLOCATIONS[i].length - 1]}` : 
              'Niciuna',
            source: 'default'
          };
        }
      }
      
      res.json({ allocations });
    });
  });

