  // Calculează reducerile Happy Hour pentru produsele din coș
  app.post('/api/happyhour/calculate-discounts', async (req, res) => {
    try {
      const { cartItems } = req.body;
      
      if (!cartItems || !Array.isArray(cartItems)) {
        return res.status(400).json({ error: 'Cart items sunt obligatorii.' });
      }

      const activeSettings = await getActiveHappyHourSettings();
      
      if (activeSettings.length === 0) {
        return res.json({ 
          hasDiscount: false,
          items: cartItems.map(item => ({
            ...item,
            originalPrice: item.finalPrice,
            finalPrice: item.finalPrice,
            discount: 0,
            discountType: null
          })),
          totalDiscount: 0
        });
      }

      // Obține categoriile produselor din baza de date
      const db = await dbPromise;
      const productCategories = {};
      
      for (const item of cartItems) {
        if (!productCategories[item.productId]) {
          const product = await new Promise((resolve, reject) => {
            db.get('SELECT category FROM menu WHERE id = ?', [item.productId], (err, row) => {
              if (err) reject(err);
              else resolve(row);
            });
          });
          productCategories[item.productId] = product?.category || 'Unknown';
        }
      }

      // Simulează structura necesară pentru applyHappyHourDiscount
      const enrichedItems = cartItems.map(item => ({
        productId: item.productId,
        finalPrice: item.finalPrice,
        quantity: item.quantity,
        category: productCategories[item.productId]
      }));

      const { discountedItems, totalDiscount } = await applyHappyHourDiscount(enrichedItems, activeSettings);
      
      // Mapăm rezultatul înapoi la structura frontend-ului
      const resultItems = cartItems.map((item, index) => {
        const discountedItem = discountedItems[index];
        return {
          ...item,
          originalPrice: discountedItem.originalPrice,
          finalPrice: discountedItem.finalPrice,
          discount: discountedItem.discount,
          discountType: discountedItem.discount > 0 ? 'Happy Hour' : null
        };
      });

      res.json({
        hasDiscount: totalDiscount > 0,
        items: resultItems,
        totalDiscount: totalDiscount,
        happyHourSettings: activeSettings
      });

    } catch (error) {
      console.error('❌ Eroare la calcularea reducerilor Happy Hour:', error);
      res.status(500).json({ error: 'Eroare la calcularea reducerilor.' });
    }
  });
  
