  // Verifică recompensele eligibile pentru o comandă
  app.post('/api/rewards/check', async (req, res) => {
    const { cartItems } = req.body;
    
    try {
      const db = await dbPromise;
      
      // Obține toate recompensele active
      db.all('SELECT * FROM rewards WHERE is_active = 1', (err, rewards) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        const eligibleRewards = [];
        
        rewards.forEach(reward => {
          try {
            const combinations = JSON.parse(reward.product_combinations);
            
            // Verifică fiecare combinație
            Object.keys(combinations).forEach(combinationKey => {
              const combination = combinations[combinationKey];
              let isEligible = true;
              
              // Verifică dacă toate produsele necesare sunt în coș
              Object.keys(combination.required_products).forEach(category => {
                const requiredQuantity = combination.required_products[category];
                const cartQuantity = cartItems.filter(item => item.category === category).length;
                
                if (cartQuantity < requiredQuantity) {
                  isEligible = false;
                }
              });
              
              if (isEligible) {
                eligibleRewards.push({
                  id: reward.id,
                  name: reward.name,
                  description: reward.description,
                  free_product_id: reward.free_product_id,
                  combination_key: combinationKey
                });
              }
            });
          } catch (parseError) {
            console.error('Eroare la parsarea combinațiilor:', parseError);
          }
        });
        
        res.json({ eligibleRewards });
      });
    } catch (error) {
      res.status(500).json({ error: 'Eroare la verificarea recompenselor.' });
    }
  });

