  // Obține statistici generale
  app.get('/api/dashboard/stats', async (req, res) => {
    try {
      const { start, end, period } = req.query;
      console.log('📊 Dashboard stats requested:', { start, end, period });
      
      const db = await dbPromise;
      
      // Folosim aceeași logică de filtrare ca în getFilteredOrdersForExport
      let whereClause = "WHERE 1=1";
      let params = [];

      if (period === 'today') {
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const startTime = new Date(today.getTime() + 8 * 60 * 60 * 1000); // 08:00
        const endTime = new Date(today.getTime() + 27 * 60 * 60 * 1000); // 03:00 următoarea zi
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
      } else if (period === 'yesterday') {
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const startTime = new Date(yesterday.getFullYear(), yesterday.getMonth(), yesterday.getDate(), 8, 0, 0);
        const endTime = new Date(yesterday.getFullYear(), yesterday.getMonth(), yesterday.getDate() + 1, 3, 0, 0);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
      } else if (period === 'last7days') {
        const endTime = new Date();
        const startTime = new Date(endTime.getTime() - 7 * 24 * 60 * 60 * 1000);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
      } else if (period === 'last30days') {
        const endTime = new Date();
        const startTime = new Date(endTime.getTime() - 30 * 24 * 60 * 60 * 1000);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
      } else if (start && end) {
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(start + 'T00:00:00.000Z');
        params.push(end + 'T23:59:59.999Z');
      } else {
        // Default: ultimele 30 zile
        const endTime = new Date();
        const startTime = new Date(endTime.getTime() - 30 * 24 * 60 * 60 * 1000);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
      }
      
      // Statistici generale cu filtrare
      const totalOrders = await new Promise((resolve, reject) => {
        db.get(`SELECT COUNT(*) as count FROM orders ${whereClause}`, params, (err, row) => {
          if (err) reject(err);
          else resolve(row.count);
        });
      });

      const totalRevenue = await new Promise((resolve, reject) => {
        db.get(`SELECT SUM(total) as total FROM orders ${whereClause}`, params, (err, row) => {
          if (err) reject(err);
          else resolve(row.total || 0);
        });
      });

      const avgOrderValue = await new Promise((resolve, reject) => {
        db.get(`SELECT AVG(total) as avg FROM orders ${whereClause}`, params, (err, row) => {
          if (err) reject(err);
          else resolve(row.avg || 0);
        });
      });

      const totalCustomers = await new Promise((resolve, reject) => {
        db.get(`SELECT COUNT(DISTINCT client_identifier) as count FROM orders ${whereClause} AND client_identifier IS NOT NULL`, params, (err, row) => {
          if (err) reject(err);
          else resolve(row.count);
        });
      });

      res.json({
        totalOrders,
        totalRevenue: Math.round(totalRevenue * 100) / 100,
        avgOrderValue: Math.round(avgOrderValue * 100) / 100,
        totalCustomers
      });
    } catch (error) {
      console.error('❌ Error in dashboard stats:', error);
      res.status(500).json({ error: 'Eroare la conectarea cu baza de date.' });
    }
  });

  // Obține statistici pe ore
  app.get('/api/dashboard/hourly', async (req, res) => {
    try {
      const db = await dbPromise;
      
      // 🚀 OPTIMIZARE: Folosește indexul pe timestamp și selectează doar câmpurile necesare
      const hourlyQuery = `
        SELECT 
          strftime('%H', timestamp) as hour,
          COUNT(*) as order_count,
          SUM(total) as total_revenue
        FROM orders 
        WHERE timestamp >= date('now', '-7 days')
          AND total IS NOT NULL
        GROUP BY strftime('%H', timestamp)
        ORDER BY hour
      `;
      
      db.all(hourlyQuery, (err, rows) => {
        if (err) {
          console.error('❌ Error in hourly stats:', err);
          return res.status(500).json({ error: err.message });
        }
        
        // Completăm orele lipsă cu 0
        const hourlyData = [];
        for (let i = 0; i < 24; i++) {
          const hour = i.toString().padStart(2, '0');
          const existingData = rows.find(row => row.hour === hour);
          hourlyData.push({
            hour: hour,
            order_count: existingData ? existingData.order_count : 0,
            total_revenue: existingData ? (existingData.total_revenue || 0) : 0
          });
        }
        
        res.json(hourlyData);
      });
    } catch (error) {
      console.error('❌ Error in hourly stats:', error);
      res.status(500).json({ error: 'Eroare la conectarea cu baza de date.' });
    }
  });

