  // Obține statistici feedback
  app.get('/api/dashboard/feedback', async (req, res) => {
    try {
      const db = await dbPromise;
      db.all(`SELECT 
        rating,
        COUNT(*) as count,
        AVG(rating) as avg_rating
      FROM feedback 
      WHERE timestamp >= date('now', '-30 days')
      GROUP BY rating
      ORDER BY rating`, (err, rows) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        const totalFeedback = rows.reduce((sum, row) => sum + row.count, 0);
        const avgRating = rows.length > 0 ? rows.reduce((sum, row) => sum + (row.rating * row.count), 0) / totalFeedback : 0;
        
        res.json({
          ratingDistribution: rows,
          totalFeedback,
          avgRating: Math.round(avgRating * 100) / 100
        });
      });
    } catch (error) {
      res.status(500).json({ error: 'Eroare la conectarea cu baza de date.' });
    }
  });

