  // Login utilizator
  app.post('/api/auth/login', async (req, res) => {
    try {
      const { username, password } = req.body;
      
      if (!username || !password) {
        return res.status(400).json({ error: 'Username și parola sunt obligatorii' });
      }
      
      const user = await getUserByUsername(username);
      if (!user) {
        return res.status(401).json({ error: 'Credențiale invalide' });
      }
      
      // Pentru demo, verifică parola simplă (în producție folosește bcrypt)
      if (user.password_hash !== password) {
        return res.status(401).json({ error: 'Credențiale invalide' });
      }
      
      // Generează token de sesiune
      const sessionToken = require('crypto').randomBytes(32).toString('hex');
      const expiresAt = new Date(Date.now() + 24 * 60 * 60 * 1000); // 24 ore
      
      await createSession(user.id, sessionToken, expiresAt);
      
      // Actualizează ultima autentificare
      const db = await dbPromise;
      db.run('UPDATE users SET last_login = CURRENT_TIMESTAMP WHERE id = ?', [user.id]);
      
      res.json({
        success: true,
        user: {
          id: user.id,
          username: user.username,
          email: user.email,
          role_name: user.role_name,
          role_description: user.role_description
        },
        sessionToken: sessionToken,
        expiresAt: expiresAt
      });
    } catch (error) {
      console.error('Eroare la login:', error);
      res.status(500).json({ error: 'Eroare la autentificare' });
    }
  });
  
