  // Generează factură pentru o comandă
  app.post('/api/admin/generate-invoice/:orderId', authenticateUser, requirePermission('orders.create'), auditLog('CREATE', 'invoice'), async (req, res) => {
    try {
      const { orderId } = req.params;
      const { customerCui, customerName, customerAddress } = req.body;
      
      if (!customerCui || !customerName) {
        return res.status(400).json({ error: 'CUI-ul și numele clientului sunt obligatorii pentru factură' });
      }
      
      // Obține datele comenzii
      const db = await dbPromise;
      const order = await new Promise((resolve, reject) => {
        db.get('SELECT * FROM orders WHERE id = ?', [orderId], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      if (!order) {
        return res.status(404).json({ error: 'Comanda nu a fost găsită' });
      }
      
      // Generează numărul facturii
      const fiscalConfig = await getFiscalConfig();
      const invoiceSeries = fiscalConfig.invoice_series.value;
      const invoiceNumber = `${invoiceSeries}${String(orderId).padStart(6, '0')}`;
      
      // Calculează TVA
      const vatRate = parseFloat(fiscalConfig.default_vat_rate.value) / 100;
      const netAmount = order.total_amount / (1 + vatRate);
      const vatAmount = order.total_amount - netAmount;
      
      // Creează documentul fiscal
      const documentData = {
        documentType: 'invoice',
        documentNumber: invoiceNumber,
        orderId: orderId,
        customerName: customerName,
        customerCui: customerCui,
        customerAddress: customerAddress,
        totalAmount: order.total_amount,
        vatAmount: vatAmount,
        netAmount: netAmount,
        issueDate: new Date().toISOString().split('T')[0],
        dueDate: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0], // 30 zile
        xmlContent: null, // Va fi generat de sistemul ANAF
        pdfPath: null // Va fi generat de sistemul ANAF
      };
      
      const documentId = await createFiscalDocument(documentData);
      
      res.json({
        success: true,
        documentId: documentId,
        invoiceNumber: invoiceNumber,
        message: 'Factura a fost generată cu succes'
      });
    } catch (error) {
      console.error('Eroare la generarea facturii:', error);
      res.status(500).json({ error: 'Eroare la generarea facturii' });
    }
  });
  
