  // Raport vânzări detaliate cu export Excel/PDF
  app.get('/api/admin/reports/sales-detailed', checkAdminAuth, async (req, res) => {
    try {
      const { startDate, endDate, format = 'json', category } = req.query;
      const db = await dbPromise;
      
      let whereClause = 'WHERE o.status = "completed" AND o.is_paid = 1';
      let params = [];
      
      if (startDate && endDate) {
        whereClause += ' AND DATE(o.timestamp) BETWEEN ? AND ?';
        params.push(startDate, endDate);
      }
      
      if (category) {
        whereClause += ' AND m.category = ?';
        params.push(category);
      }
      
      const query = `
        SELECT 
          o.id as order_id,
          o.timestamp,
          o.table_number,
          o.client_identifier,
          o.total as order_total,
          m.name as product_name,
          m.category,
          m.price,
          json_extract(oi.value, '$.quantity') as quantity,
          json_extract(oi.value, '$.finalPrice') as final_price,
          json_extract(oi.value, '$.customizations') as customizations
        FROM orders o
        CROSS JOIN json_each(o.items) as oi
        LEFT JOIN menu m ON json_extract(oi.value, '$.productId') = m.id
        ${whereClause}
        ORDER BY o.timestamp DESC
        LIMIT 1000
      `;
      
      db.all(query, params, async (err, rows) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        if (format === 'excel') {
          // Generează Excel
          const workbook = XLSX.utils.book_new();
          const worksheet = XLSX.utils.json_to_sheet(rows);
          XLSX.utils.book_append_sheet(workbook, worksheet, 'Raport Vanzari');
          
          const buffer = XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' });
          
          res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
          res.setHeader('Content-Disposition', `attachment; filename="raport_vanzari_${startDate || 'all'}_${endDate || 'all'}.xlsx"`);
          res.send(buffer);
        } else if (format === 'pdf') {
          // Generează PDF
          const doc = new PDFDocument();
          res.setHeader('Content-Type', 'application/pdf');
          res.setHeader('Content-Disposition', `attachment; filename="raport_vanzari_${startDate || 'all'}_${endDate || 'all'}.pdf"`);
          
          doc.pipe(res);
          
          doc.fontSize(20).text('Raport Vânzări Detaliate', { align: 'center' });
          doc.moveDown();
          
          if (startDate && endDate) {
            doc.fontSize(12).text(`Perioada: ${startDate} - ${endDate}`, { align: 'center' });
          } else {
            doc.fontSize(12).text('Toate vânzările', { align: 'center' });
          }
          
          doc.moveDown();
          
          // Grupează datele pe comenzi
          const ordersMap = new Map();
          rows.forEach(row => {
            if (!ordersMap.has(row.order_id)) {
              ordersMap.set(row.order_id, {
                order_id: row.order_id,
                timestamp: row.timestamp,
                table_number: row.table_number,
                client_identifier: row.client_identifier,
                order_total: row.order_total,
                items: []
              });
            }
            ordersMap.get(row.order_id).items.push(row);
          });
          
          ordersMap.forEach(order => {
            doc.fontSize(14).text(`Comanda #${order.order_id}`, { underline: true });
            doc.fontSize(10).text(`Data: ${new Date(order.timestamp).toLocaleString('ro-RO')}`);
            doc.text(`Masa: ${order.table_number || 'N/A'}`);
            doc.text(`Total: ${order.order_total} RON`);
            doc.moveDown(0.5);
            
            order.items.forEach(item => {
              doc.text(`• ${item.product_name} (${item.category}) - ${item.quantity}x ${item.final_price} RON`);
            });
            
            doc.moveDown();
          });
          
          doc.end();
        } else {
          // Returnează JSON
          res.json({
            success: true,
            data: rows,
            summary: {
              totalOrders: new Set(rows.map(r => r.order_id)).size,
              totalRevenue: rows.reduce((sum, r) => sum + (r.final_price * r.quantity), 0),
              totalItems: rows.reduce((sum, r) => sum + r.quantity, 0),
              period: startDate && endDate ? `${startDate} - ${endDate}` : 'Toate vânzările'
            }
          });
        }
      });
    } catch (error) {
      res.status(500).json({ error: 'Eroare la generarea raportului de vânzări.' });
    }
  });

