  // Funcție pentru calcularea costului real al rețetei
  const calculateRecipeCost = async (productId) => {
    try {
      const db = await dbPromise;
      const recipes = await new Promise((resolve, reject) => {
        db.all(`
          SELECT r.quantity_needed, i.cost_per_unit, i.name as ingredient_name
          FROM recipes r
          JOIN ingredients i ON r.ingredient_id = i.id
          WHERE r.product_id = ?
        `, [productId], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      let totalCost = 0;
      recipes.forEach(recipe => {
        if (recipe.quantity_needed && recipe.cost_per_unit) {
          totalCost += recipe.quantity_needed * recipe.cost_per_unit;
        }
      });
      
      return totalCost;
    } catch (error) {
      console.error('Eroare la calcularea costului rețetei:', error);
      return 0;
    }
  };

  // Raport analiză profitabilitate pe produse cu costuri reale din rețete
  app.get('/api/admin/reports/profitability', checkAdminAuth, async (req, res) => {
    try {
      const { startDate, endDate, format = 'json' } = req.query;
      const db = await dbPromise;
      
      let whereClause = 'WHERE o.status = "completed" AND o.is_paid = 1';
      let params = [];
      
      if (startDate && endDate) {
        whereClause += ' AND DATE(o.timestamp) BETWEEN ? AND ?';
        params.push(startDate, endDate);
      }
      
      const query = `
        SELECT 
          m.id,
          m.name,
          m.category,
          m.price as selling_price,
          COUNT(*) as times_ordered,
          SUM(json_extract(oi.value, '$.quantity')) as total_quantity_sold,
          SUM(json_extract(oi.value, '$.finalPrice') * json_extract(oi.value, '$.quantity')) as total_revenue,
          AVG(json_extract(oi.value, '$.finalPrice')) as avg_selling_price
        FROM orders o
        CROSS JOIN json_each(o.items) as oi
        LEFT JOIN menu m ON json_extract(oi.value, '$.productId') = m.id
        ${whereClause}
        GROUP BY m.id, m.name, m.category, m.price
        HAVING total_quantity_sold > 0
        ORDER BY total_revenue DESC
      `;
      
      db.all(query, params, async (err, rows) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        // Calculează costurile reale și marjele pentru fiecare produs
        const productsWithCosts = await Promise.all(rows.map(async (product) => {
          const recipeCost = await calculateRecipeCost(product.id);
          const totalCost = recipeCost * product.total_quantity_sold;
          const profit = product.total_revenue - totalCost;
          const profitMargin = product.total_revenue > 0 ? (profit / product.total_revenue * 100) : 0;
          
          return {
            ...product,
            recipe_cost_per_unit: recipeCost,
            total_cost: totalCost,
            profit: profit,
            profit_margin_percent: Math.round(profitMargin * 100) / 100,
            profit_margin_ron: profit
          };
        }));
        
        // Sortează după profit
        productsWithCosts.sort((a, b) => b.profit - a.profit);
        
        if (format === 'excel') {
          const workbook = XLSX.utils.book_new();
          const worksheet = XLSX.utils.json_to_sheet(productsWithCosts);
          XLSX.utils.book_append_sheet(workbook, worksheet, 'Profitabilitate');
          
          const buffer = XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' });
          
          res.setHeader('Content-Type', 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');
          res.setHeader('Content-Disposition', `attachment; filename="raport_profitabilitate_${startDate || 'all'}_${endDate || 'all'}.xlsx"`);
          res.send(buffer);
        } else {
          res.json({
            success: true,
            data: productsWithCosts,
            summary: {
              totalProducts: productsWithCosts.length,
              totalRevenue: productsWithCosts.reduce((sum, p) => sum + p.total_revenue, 0),
              totalCosts: productsWithCosts.reduce((sum, p) => sum + p.total_cost, 0),
              totalProfit: productsWithCosts.reduce((sum, p) => sum + p.profit, 0),
              avgProfitMargin: productsWithCosts.length > 0 ? 
                productsWithCosts.reduce((sum, p) => sum + p.profit_margin_percent, 0) / productsWithCosts.length : 0
            }
          });
        }
      });
    } catch (error) {
      res.status(500).json({ error: 'Eroare la generarea raportului de profitabilitate.' });
    }
  });

  // Endpoint pentru calcularea costului și marjei de profit pentru un produs specific
  app.get('/api/admin/products/:id/cost-analysis', checkAdminAuth, async (req, res) => {
    try {
      const productId = req.params.id;
      const db = await dbPromise;
      
      // Obține informațiile produsului
      const product = await new Promise((resolve, reject) => {
        db.get('SELECT id, name, price, category FROM menu WHERE id = ?', [productId], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      if (!product) {
        return res.status(404).json({ error: 'Produsul nu a fost găsit' });
      }
      
      // Calculează costul rețetei
      const recipeCost = await calculateRecipeCost(productId);
      
      // Calculează marja de profit
      const profit = product.price - recipeCost;
      const profitMargin = product.price > 0 ? (profit / product.price * 100) : 0;
      
      // Obține detaliile ingredienteilor din rețetă
      const recipeDetails = await new Promise((resolve, reject) => {
        db.all(`
          SELECT 
            r.quantity_needed,
            r.unit,
            i.name as ingredient_name,
            i.cost_per_unit,
            i.current_stock,
            i.unit as ingredient_unit,
            (r.quantity_needed * i.cost_per_unit) as ingredient_cost
          FROM recipes r
          JOIN ingredients i ON r.ingredient_id = i.id
          WHERE r.product_id = ?
          ORDER BY ingredient_cost DESC
        `, [productId], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      res.json({
        success: true,
        product: {
          id: product.id,
          name: product.name,
          price: product.price,
          category: product.category
        },
        costAnalysis: {
          recipe_cost_per_unit: recipeCost,
          selling_price: product.price,
          profit_per_unit: profit,
          profit_margin_percent: Math.round(profitMargin * 100) / 100,
          cost_percentage: product.price > 0 ? Math.round((recipeCost / product.price * 100) * 100) / 100 : 0
        },
        recipeDetails: recipeDetails,
        summary: {
          total_ingredients: recipeDetails.length,
          most_expensive_ingredient: recipeDetails.length > 0 ? recipeDetails[0] : null,
          profitability_status: profitMargin > 50 ? 'Excelent' : profitMargin > 30 ? 'Bun' : profitMargin > 15 ? 'Acceptabil' : 'Scăzut'
        }
      });
      
    } catch (error) {
      console.error('Eroare la analiza costului produsului:', error);
      res.status(500).json({ error: 'Eroare la calcularea analizei costului' });
    }
  });

