  // GET /api/dashboard/export/pdf
  app.get('/api/dashboard/export/pdf', async (req, res) => {
    try {
      const { start, end, period } = req.query;
      const orders = await getFilteredOrdersForExport(start, end, period);

      if (orders.length === 0) {
        return res.status(404).send('Nu s-au găsit comenzi pentru perioada selectată.');
      }

      // 1. Inițializarea PDF-ului
      const doc = new PDFDocument({ size: 'A4', margin: 50 });
      
      const filename = `raport_comenzi_${period || start}_${end || ''}.pdf`;
      
      // 2. Setarea Headerelor pentru descărcare
      res.setHeader('Content-Type', 'application/pdf');
      res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);

      doc.pipe(res); // Trimite PDF-ul direct ca răspuns HTTP

      // 3. Adăugarea conținutului
      const totalValue = orders.reduce((sum, order) => sum + (order.total || 0), 0);
      
      doc.fontSize(18).text('Raport Comenzi Restaurant', { align: 'center' });
      doc.fontSize(12).text(`Perioada: ${period || start} - ${end || 'Prezent'}`, { align: 'center' });
      doc.moveDown();
      
      doc.fontSize(14).text(`TOTAL VALOARE COMENZI: ${totalValue.toFixed(2)} RON`, { align: 'left' });
      doc.moveDown(0.5);

      // Funcție simplă pentru tabel (pentru o randare curată)
      let yPosition = doc.y;
      const tableTop = yPosition;
      const itemPerRow = 5;
      const rowHeight = 25;
      const columnWidths = [50, 150, 80, 80, 150];
      let currentX = 50;

      // Header Tabel
      const tableHeaders = ["ID", "Data", "Total (RON)", "Status", "Metodă Plată"];
      doc.fillColor('#000');
      doc.fontSize(10);
      
      tableHeaders.forEach((header, i) => {
        doc.text(header, currentX, tableTop, { width: columnWidths[i], align: 'left' });
        currentX += columnWidths[i];
      });
      doc.moveTo(50, tableTop + rowHeight - 5).lineTo(550, tableTop + rowHeight - 5).stroke();
      yPosition += rowHeight;

      // Date Tabel
      orders.forEach(order => {
        if (yPosition > 750) { // Adaugă pagină nouă dacă e nevoie
          doc.addPage();
          yPosition = 50 + rowHeight;
        }

        currentX = 50;
        const rowData = [
          order.id, 
          order.timestamp ? order.timestamp.substring(0, 10) : 'N/A', 
          (order.total || 0).toFixed(2), 
          order.status, 
          'N/A' // payment_method nu există în tabela orders
        ];

        rowData.forEach((data, i) => {
          doc.text(data.toString(), currentX, yPosition, { width: columnWidths[i], align: 'left' });
          currentX += columnWidths[i];
        });

        yPosition += rowHeight;
        doc.moveTo(50, yPosition - 5).lineTo(550, yPosition - 5).stroke('#ccc');
      });
      
      // 4. Finalizarea documentului
      doc.end();

    } catch (error) {
      console.error('❌ Eroare la exportul PDF:', error);
      res.status(500).json({ error: 'Eroare la generarea fișierului PDF' });
    }
  });

  app.post('/api/visits/close', (req, res) => {
    const { tableNumber, clientIdentifier, payment_method = 'cash' } = req.body;
    
    // Pentru comenzile takeout, tableNumber poate fi null
    if (tableNumber === undefined) {
      return res.status(400).json({ error: 'TableNumber este obligatoriu.' });
    }
    
    // Handle empty or null clientIdentifier
    const clientId = clientIdentifier || '';
    
    // Găsim cea mai recentă comandă a clientului pentru a-i afla ID-ul comenzii principale
    let findOrderQuery, queryParams;
    
    if (tableNumber === null) {
      // Pentru comenzile takeout (table_number = null)
      findOrderQuery = clientId === '' 
        ? 'SELECT id FROM orders WHERE table_number IS NULL AND (client_identifier IS NULL OR client_identifier = ?) AND is_paid = 0 ORDER BY timestamp DESC LIMIT 1'
        : 'SELECT id FROM orders WHERE table_number IS NULL AND client_identifier = ? AND is_paid = 0 ORDER BY timestamp DESC LIMIT 1';
      queryParams = [clientId];
    } else {
      // Pentru comenzile normale
      findOrderQuery = clientId === '' 
        ? 'SELECT id FROM orders WHERE table_number = ? AND (client_identifier IS NULL OR client_identifier = ?) AND is_paid = 0 ORDER BY timestamp DESC LIMIT 1'
        : 'SELECT id FROM orders WHERE table_number = ? AND client_identifier = ? AND is_paid = 0 ORDER BY timestamp DESC LIMIT 1';
      queryParams = [tableNumber, clientId];
    }
    
    db.get(findOrderQuery, queryParams, (err, row) => {
      if (err) { 
        console.error(err); 
        return res.status(500).json({ error: 'Eroare la găsirea comenzii.' });
      }

      const representativeOrderId = row ? row.id : null;

      // Marchează toate comenzile neplătite ale clientului ca plătite
      let updateQuery, updateParams;
      
      if (tableNumber === null) {
        // Pentru comenzile takeout (table_number = null)
        updateQuery = 'UPDATE orders SET is_paid = 1, status = ?, payment_method = ?, paid_timestamp = CURRENT_TIMESTAMP WHERE table_number IS NULL AND client_identifier = ? AND is_paid = 0';
        updateParams = ['delivered', payment_method, clientId];
      } else {
        // Pentru comenzile normale
        updateQuery = clientId === '' 
          ? 'UPDATE orders SET is_paid = 1, status = ?, payment_method = ?, paid_timestamp = CURRENT_TIMESTAMP WHERE table_number = ? AND (client_identifier IS NULL OR client_identifier = ?) AND is_paid = 0'
          : 'UPDATE orders SET is_paid = 1, status = ?, payment_method = ?, paid_timestamp = CURRENT_TIMESTAMP WHERE table_number = ? AND client_identifier = ? AND is_paid = 0';
        updateParams = ['delivered', payment_method, tableNumber, clientId];
      }
      
      db.run(updateQuery, updateParams, function(err) {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        // Găsim socket-ul clientului pentru a-i trimite notificarea de plată
        const clientSession = activeClientSessions[tableNumber]?.find(s => s.identifier === clientId);
        if (clientSession && clientSession.socketId) {
          io.to(clientSession.socketId).emit('billPaid', { orderId: representativeOrderId });
        }
        
        // Șterge sesiunea clientului din memorie
        if (clientSessions.has(tableNumber)) {
          const tableSession = clientSessions.get(tableNumber);
          // Găsește și șterge clientToken-ul pentru acest clientIdentifier
          for (const [token, identifier] of tableSession.clients.entries()) {
            if (identifier === clientId) {
              tableSession.clients.delete(token);
              break;
            }
          }
        }
        
        // Șterge din activeClientSessions
        if(activeClientSessions[tableNumber]) {
          activeClientSessions[tableNumber] = activeClientSessions[tableNumber].filter(s => s.identifier !== clientId);
        }
        
        // Trimite notificare WebSocket
        io.emit('visitClosed', { 
          tableNumber: tableNumber, 
          clientIdentifier: clientId,
          timestamp: new Date().toISOString()
        });
        
        // Emit dashboard update
        emitDashboardUpdate();
        
        // Emite automat bon nefiscal pentru grupul de comenzi achitate
        if (this.changes > 0) {
          console.log(`🧾 Emitând automat bon nefiscal pentru ${this.changes} comenzi cu metoda de plată: ${payment_method}`);
          console.log(`🔍 Debug: tableNumber=${tableNumber}, clientId=${clientId}`);
          
          // Găsește toate comenzile achitate pentru acest client
          let findPaidOrdersQuery, findPaidOrdersParams;
          
          if (tableNumber === null) {
            findPaidOrdersQuery = 'SELECT id, total, items FROM orders WHERE table_number IS NULL AND client_identifier = ? AND is_paid = 1 ORDER BY timestamp DESC';
            findPaidOrdersParams = [clientId];
          } else {
            findPaidOrdersQuery = clientId === '' 
              ? 'SELECT id, total, items FROM orders WHERE table_number = ? AND (client_identifier IS NULL OR client_identifier = ?) AND is_paid = 1 ORDER BY timestamp DESC'
              : 'SELECT id, total, items FROM orders WHERE table_number = ? AND client_identifier = ? AND is_paid = 1 ORDER BY timestamp DESC';
            findPaidOrdersParams = [tableNumber, clientId];
          }
          
          db.all(findPaidOrdersQuery, findPaidOrdersParams, async (err, orders) => {
            if (err) {
              console.error('❌ Eroare la găsirea comenzilor pentru bon nefiscal:', err);
              return;
            }
            
            if (orders.length === 0) {
              console.log('⚠️ Nu s-au găsit comenzi pentru bon nefiscal');
              return;
            }
            
            // Dacă există mai multe comenzi, generează un bon nefiscal grupat
            if (orders.length > 1) {
              try {
                console.log(`🔄 Generând bon nefiscal grupat pentru ${orders.length} comenzi...`);
                const groupReceiptResult = await generateGroupFiscalReceipt(orders, payment_method);
                
                if (groupReceiptResult.success) {
                  // Actualizează toate comenzile cu același fiscal_receipt_id
                  const updatePromises = orders.map(order => {
                    return new Promise((resolve, reject) => {
                      db.run('UPDATE orders SET fiscal_receipt_id = ? WHERE id = ?', 
                        [groupReceiptResult.receipt_id, order.id], (err) => {
                        if (err) reject(err);
                        else resolve();
                      });
                    });
                  });
                  
                  await Promise.all(updatePromises);
                  
                  console.log(`✅ Bon nefiscal grupat generat: ${groupReceiptResult.receipt_number} pentru ${orders.length} comenzi`);
                  console.log(`💰 Suma totală: ${groupReceiptResult.total_amount} RON`);
                  
                  // Emite notificare WebSocket pentru bonul fiscal grupat
                  io.emit('groupFiscalReceiptGenerated', {
                    receiptNumber: groupReceiptResult.receipt_number,
                    orders: orders.map(o => o.id),
                    totalAmount: groupReceiptResult.total_amount,
                    paymentMethod: payment_method
                  });
                } else {
                  console.error('❌ Eroare la generarea bonului nefiscal grupat:', groupReceiptResult.error);
                }
              } catch (error) {
                console.error('❌ Eroare la generarea bonului nefiscal grupat:', error);
              }
            } else {
              // Pentru o singură comandă, generează bon nefiscal individual
              try {
                const fiscalReq = {
                  params: { orderId: orders[0].id },
                  body: {
                    payment_method: payment_method,
                    is_fiscal: 1, // Bon nefiscal
                    waiter_id: null
                  }
                };
                
                const fiscalRes = {
                  json: (data) => data,
                  status: 200
                };
                
                const fiscalData = await emitFiscalReceipt(fiscalReq, fiscalRes, orders[0].id, payment_method);
                
                if (fiscalData && fiscalData.success) {
                  console.log(`✅ Bon nefiscal individual emis pentru comanda ${orders[0].id}: ${fiscalData.receipt_number}`);
                } else {
                  console.error(`❌ Eroare la emiterea bonului nefiscal pentru comanda ${orders[0].id}`);
                }
              } catch (error) {
                console.error(`❌ Eroare la emiterea bonului nefiscal pentru comanda ${orders[0].id}:`, error);
              }
            }
          });
        }
        
        res.json({ 
          success: true, 
          message: `Vizita clientului ${clientId || 'N/A'} de la masa ${tableNumber} a fost închisă cu succes.`,
          ordersUpdated: this.changes
        });
      });
    });
  });
  
  app.get('/api/orders-display', (req, res) => {
    const lang = (req.query.lang || 'ro').toLowerCase();
    db.all('SELECT * FROM orders WHERE status = "pending" ORDER BY timestamp ASC', (err, rows) => {
      if (err) { return res.status(500).json({ error: err.message }); }
      
      const promises = rows.map(order => {
        return new Promise((resolve, reject) => {
            const items = safeParseItems(order.items);
          const itemPromises = items.map(item => {
            return new Promise((resolveItem, rejectItem) => {
              const sel = lang === 'en' ? 'SELECT name_en, name, price FROM menu WHERE id = ?' : 'SELECT name, price FROM menu WHERE id = ?';
              db.get(sel, [item.productId], (itemErr, p) => {
                if (itemErr) return rejectItem(itemErr);
                if (lang === 'en') {
                  const enName = (p && p.name_en && String(p.name_en).trim()) ? p.name_en : (USE_EN_FALLBACK ? translateRoToEn(p ? p.name : '') : (p && p.name_en ? p.name_en : ''));
                  resolveItem({ ...item, name: enName || 'Product', price: p ? p.price : 0 });
                } else {
                resolveItem({ ...item, name: (p && p.name) ? p.name : 'Produs șters', price: p ? p.price : 0 });
                }
              });
            });
          });
          Promise.all(itemPromises)
            .then(enriched => {
              const o = formatOrderTimestamps({ ...order, items: enriched });
              resolve(formatOrderTimestampsLang(o, lang));
            })
            .catch(reject);
        });
      });
      
      Promise.all(promises).then(orders => res.json({ orders })).catch(err => res.status(500).json({ error: err.message }));
    });
  });

  // Station-specific pending items
  app.get('/api/orders-display/kitchen', (req, res) => {
    const lang = (req.query.lang || 'ro').toLowerCase();
    // 🚀 OPTIMIZARE: Folosește indexul pe status și selectează doar câmpurile necesare
    db.all('SELECT id, table_number, type, timestamp, items, food_notes, general_notes, status FROM orders WHERE status IN ("pending", "preparing") ORDER BY timestamp ASC', (err, rows) => {
      if (err) { return res.status(500).json({ error: err.message }); }
      const orders = (rows || []).map(order => {
        let items = [];
        items = safeParseItems(order.items) || [];
        const pendingKitchen = items.filter(it => it && it.station === 'kitchen' && (it.status === 'pending' || it.status === 'preparing'));
        // Pentru comenzile supervisor modificate, afișează doar item-urile noi cu status pending
        const hasNewPendingItems = pendingKitchen.some(it => it.status === 'pending');
        if (pendingKitchen.length === 0) return null;
        
        const itemsToShow = hasNewPendingItems ? 
          pendingKitchen.filter(it => it.status === 'pending') : 
          pendingKitchen;
        const mapped = itemsToShow.map(it => ({ 
          itemId: it.itemId, 
          productId: it.productId, 
          name: it.name || 'Produs', // Păstrează numele din comandă
          quantity: it.quantity, 
          customizations: (it.customizations || []).map(c => ({ ...c, id: c.id })) 
        }));
        const o = formatOrderTimestamps({ 
          id: order.id, 
          table_number: order.table_number, 
          type: order.type, 
          timestamp: order.timestamp, 
          items: mapped,
          food_notes: order.food_notes,
          general_notes: order.general_notes,
          status: order.status
        });
        return formatOrderTimestampsLang(o, lang);
      }).filter(Boolean);
      if (orders.length) {
        const productIds = new Set();
        const customizationIds = new Set();
        orders.forEach(o => o.items.forEach(it => {
          productIds.add(it.productId);
          (it.customizations || []).forEach(c => { if (c && Number.isInteger(c.id)) customizationIds.add(c.id); });
        }));

        const prodPlaceholders = Array.from(productIds).map(() => '?').join(',');
        const prodSql = `SELECT id, name_en, name FROM menu WHERE id IN (${prodPlaceholders})`;
        db.all(prodSql, Array.from(productIds), (e2, rows2) => {
          const nameMap = new Map((rows2 || []).map(r => [r.id, { name_en: r.name_en, name_ro: r.name }]));

          const applyProductNames = () => {
            orders.forEach(o => o.items.forEach(it => {
              // Dacă produsul are deja numele setat (pentru meniul zilei), nu-l suprascrie
              if (it.name && it.name !== 'Produs' && it.name.trim() !== '') {
                return; // Păstrează numele existent
              }
              
              if (nameMap.has(it.productId)) {
                const rec = nameMap.get(it.productId);
                if (lang === 'en') {
                  const enName = (rec.name_en && String(rec.name_en).trim()) ? rec.name_en : (USE_EN_FALLBACK ? translateRoToEn(rec.name_ro || '') : rec.name_en);
                  it.name = enName || it.name;
                } else {
                  it.name = rec.name_ro || it.name;
                }
              }
            }));
          };

        const finishWithResponse = () => {
            orders.forEach(o => o.items.forEach(it => { delete it.productId; }));
            return res.json({ orders });
          };

          const custIdsArr = Array.from(customizationIds);
          if (custIdsArr.length === 0) {
            applyProductNames();
            return finishWithResponse();
          }

          const custPlaceholders = custIdsArr.map(() => '?').join(',');
          const custSql = `SELECT id, option_name, option_name_en FROM customization_options WHERE id IN (${custPlaceholders})`;
          db.all(custSql, custIdsArr, (e3, rows3) => {
            const optMap = new Map((rows3 || []).map(r => [r.id, { ro: r.option_name || '', en: r.option_name_en || '' }]));
            applyProductNames();
            orders.forEach(o => o.items.forEach(it => {
              (it.customizations || []).forEach(c => {
                const rec = optMap.get(c.id);
                if (rec) {
                  c.name = (lang === 'en')
                    ? (rec.en && String(rec.en).trim() ? rec.en : translateRoToEn(rec.ro || c.name || ''))
                    : (rec.ro || c.name);
                }
              });
            }));
            return finishWithResponse();
          });
        });
      } else {
        return res.json({ orders });
      }
    });
  });

