  // Endpoint pentru "TOATE COMENZILE" - intervalul 08:00-03:00
  app.get('/api/orders-display/bar/all-daily', (req, res) => {
    const lang = (req.query.lang || 'ro').toLowerCase();
    
    // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
    const now = new Date();
    const currentHour = now.getHours();
    
    let startTime, endTime;
    if (currentHour >= 8) {
      // Dacă este după 08:00, intervalul este de azi 08:00 la mâine 03:00
      startTime = new Date(now);
      startTime.setHours(8, 0, 0, 0);
      endTime = new Date(now);
      endTime.setDate(endTime.getDate() + 1);
      endTime.setHours(3, 0, 0, 0);
    } else {
      // Dacă este înainte de 08:00, intervalul este de ieri 08:00 la azi 03:00
      startTime = new Date(now);
      startTime.setDate(startTime.getDate() - 1);
      startTime.setHours(8, 0, 0, 0);
      endTime = new Date(now);
      endTime.setHours(3, 0, 0, 0);
    }
    
    console.log('🕐 Daily interval:', startTime.toISOString(), 'to', endTime.toISOString());
    
    db.all(`
      SELECT * FROM orders 
      WHERE timestamp >= ? AND timestamp <= ? 
      ORDER BY timestamp ASC
    `, [startTime.toISOString(), endTime.toISOString()], (err, rows) => {
      if (err) { 
        console.error('Eroare SQL all daily orders:', err);
        return res.status(500).json({ error: err.message }); 
      }
      
      const orders = (rows || []).map(order => {
        let items = [];
        try { 
          items = safeParseItems(order.items) || []; 
        } catch(e) { 
          console.error('JSON parse error for order', order.id, e);
          items = []; 
        }
        
        // Filtrează produsele de bar
        const barItems = items.filter(it => it && it.station === 'bar');
        
        if (barItems.length === 0) return null;
        
        const mapped = barItems.map(it => ({ 
          itemId: it.itemId, 
          productId: it.productId, 
          name: it.name || 'Produs', 
          quantity: it.quantity, 
          customizations: (it.customizations || []).map(c => ({ ...c, id: c.id })),
          status: it.status || 'pending',
          station: it.station,
          finalPrice: it.finalPrice || 0,
          isFree: it.isFree || false
        }));
        
        return {
          id: order.id,
          table_number: order.table_number,
          client_identifier: order.client_identifier,
          type: order.type,
          timestamp: order.timestamp,
          completed_timestamp: order.completed_timestamp,
          delivered_timestamp: order.delivered_timestamp,
          status: order.status,
          is_paid: order.is_paid,
          items: mapped,
          drink_notes: order.drink_notes,
          general_notes: order.general_notes
        };
      }).filter(Boolean);
      
      // Procesează traducerile
      if (lang === 'en' && orders.length) {
        const ids = new Set();
        orders.forEach(o => o.items.forEach(it => ids.add(it.productId)));
        
        if (ids.size > 0) {
          const placeholders = Array.from(ids).map(() => '?').join(',');
          const sql = `SELECT id, name_en, name FROM menu WHERE id IN (${placeholders})`;
          
          db.all(sql, Array.from(ids), (e2, rows2) => {
            const nameMap = new Map((rows2||[]).map(r => [r.id, { name_en: r.name_en, name_ro: r.name }]));
            
            orders.forEach(o => o.items.forEach(it => {
              if (nameMap.has(it.productId)) {
                const rec = nameMap.get(it.productId);
                const enName = rec.name_en && String(rec.name_en).trim() ? rec.name_en : translateRoToEn(rec.name_ro || '');
                it.name = enName || it.name;
              }
              delete it.productId;
            }));
            
            return res.json({ orders });
          });
        } else {
          orders.forEach(o => o.items.forEach(it => { delete it.productId; }));
          return res.json({ orders });
        }
      } else {
        orders.forEach(o => o.items.forEach(it => { delete it.productId; }));
        return res.json({ orders });
      }
    });
  });

  // Endpoint pentru remarcarea items-urilor ca "pending" (pentru a putea reveni asupra lor)
  app.put('/api/orders/:id/reset-items-to-pending', (req, res) => {
    const orderId = req.params.id;
    const { itemIds } = req.body || {};
    if (!Array.isArray(itemIds) || itemIds.length === 0) {
      return res.status(400).json({ error: 'Lipsesc itemIds.' });
    }
    
    db.get('SELECT * FROM orders WHERE id = ?', [orderId], (err, order) => {
      if (err) return res.status(500).json({ error: err.message });
      if (!order) return res.status(404).json({ error: 'Comanda nu a fost găsită.' });
      
      let items = [];
      items = safeParseItems(order.items) || [];
      
      let changed = false;
      items = items.map(it => {
        if (itemIds.includes(it.itemId) && it.status === 'completed') {
          changed = true;
          return { ...it, status: 'pending' };
        }
        return it;
      });
      
      if (!changed) {
        return res.json({ message: 'Nicio modificare.' });
      }
      
      const updatedItemsJson = JSON.stringify(items);
      db.run('UPDATE orders SET items = ? WHERE id = ?', [updatedItemsJson, orderId], function(updErr) {
        if (updErr) return res.status(500).json({ error: updErr.message });
        
        // Emit update pentru a actualiza toate ferestrele
        io.emit('orderUpdated', { orderId });
        
        res.json({ 
          success: true,
          message: `Items-urile din comanda ${orderId} au fost remarcate ca pending.` 
        });
      });
    });
  });

