  // POST /api/menu/product - Creare produs nou în meniu
  app.post('/api/menu/product', checkAdminAuth, async (req, res) => {
    try {
      const { name } = req.body;
      if (!name || name.trim() === '') {
        return res.status(400).json({ success: false, error: 'Numele produsului este obligatoriu.' });
      }

      const db = await dbPromise;

      // Verifică dacă produsul există deja
      const existingProduct = await new Promise((resolve, reject) => {
        db.get('SELECT id FROM menu WHERE name = ?', [name.trim()], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });

      if (existingProduct) {
        return res.status(400).json({ 
          success: false, 
          error: `Produsul "${name}" există deja în meniu.` 
        });
      }

      // Inserare în tabela 'menu' cu valori implicite
      const result = await new Promise((resolve, reject) => {
        db.run(`INSERT INTO menu (name, name_en, category, price, description, is_sellable, is_vegetarian, is_spicy, is_takeout_only) VALUES (?, ?, 'Necategorizat', 0.00, 'Produs nou creat', 1, 0, 0, 0)`, 
          [name.trim(), name.trim()], 
          function(err) {
            if (err) return reject(err);
            resolve(this.lastID);
          }
        );
      });

      // Reîncarcă cache-ul meniului
      await loadMenuCache();

      res.status(201).json({ 
        success: true, 
        product_id: result,
        message: `Produsul "${name}" a fost creat cu succes și este disponibil în Gestionare Meniu.`
      });

    } catch (error) {
      console.error('Eroare la crearea produsului în meniu:', error);
      res.status(500).json({ success: false, error: 'Eroare la crearea produsului pe server.' });
    }
  });

// GET /api/dashboard/metrics - Dashboard metrics (simplified)
app.get('/api/dashboard/metrics', async (req, res) => {
  const startTime = Date.now();
  try {
    console.log('🔍 Dashboard metrics requested');
    const db = await dbPromise;
    const today = new Date().toISOString().split('T')[0];
    
    // Query pentru comenzile de astăzi cu venituri calculate din JSON
    // ✅ EXCLUDEM comenzile anulate (status != 'cancelled')
    const todayStats = await new Promise((resolve, reject) => {
      db.all(`
        SELECT items, status
        FROM orders 
        WHERE DATE(timestamp) = ?
          AND status != 'cancelled'
      `, [today], (err, rows) => {
        if (err) {
          console.error('❌ Database error:', err);
          reject(err);
        } else {
          let totalOrders = rows.length;
          let totalRevenue = 0;
          let totalItems = 0;
          
          // Calculează veniturile din items JSON (doar pentru comenzi NEANULATE)
          rows.forEach(order => {
            try {
              const items = safeParseItems(order.items);
              items.forEach(item => {
                if (item.finalPrice && item.quantity) {
                  totalRevenue += item.finalPrice * item.quantity;
                  totalItems += item.quantity;
                }
              });
            } catch (e) {
              console.error('Error parsing items JSON:', e);
            }
          });
          
          console.log(`📊 Today stats: ${totalOrders} comenzi (FĂRĂ anulate), ${totalRevenue.toFixed(2)} RON venituri`);
          
          resolve({
            total_orders: totalOrders,
            total_revenue: totalRevenue,
            avg_order_value: totalOrders > 0 ? totalRevenue / totalOrders : 0,
            total_items: totalItems
          });
        }
      });
    });

    // Query pentru comenzile active
    const activeStats = await new Promise((resolve, reject) => {
      db.get(`
        SELECT COUNT(*) as active_orders 
        FROM orders 
        WHERE status IN ('pending', 'preparing', 'ready')
      `, [], (err, row) => {
        if (err) {
          console.error('❌ Active orders error:', err);
          reject(err);
        } else {
          resolve(row || { active_orders: 0 });
        }
      });
    });

    // Query pentru top produse live
    // ✅ EXCLUDEM produsele din comenzile anulate
    const topProducts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT items
        FROM orders 
        WHERE DATE(timestamp) = ?
          AND status != 'cancelled'
      `, [today], (err, rows) => {
        if (err) {
          console.error('❌ Top products error:', err);
          reject(err);
        } else {
          const productCounts = {};
          
          rows.forEach(order => {
            try {
              const items = safeParseItems(order.items);
              items.forEach(item => {
                if (item.name && item.quantity) {
                  if (productCounts[item.name]) {
                    productCounts[item.name] += item.quantity;
                  } else {
                    productCounts[item.name] = item.quantity;
                  }
                }
              });
            } catch (e) {
              console.error('Error parsing items JSON for top products:', e);
            }
          });
          
          // Sortează și ia top 5
          const sortedProducts = Object.entries(productCounts)
            .map(([name, count]) => ({ name, count }))
            .sort((a, b) => b.count - a.count)
            .slice(0, 5);
          
          console.log(`📊 Top products: ${sortedProducts.length} produse (FĂRĂ din comenzi anulate)`);
          
          resolve(sortedProducts);
        }
      });
    });

    // Query pentru status mese (mesele 1-200 configurate în aplicație)
    const tableStatus = await new Promise((resolve, reject) => {
      db.all(`
        SELECT table_number, status, timestamp
        FROM orders 
        WHERE status IN ('pending', 'preparing', 'ready', 'delivered')
        AND timestamp > datetime('now', '-4 hours')
        ORDER BY table_number
      `, [], (err, rows) => {
        if (err) {
          console.error('❌ Table status error:', err);
          reject(err);
        } else {
          // Creează status pentru toate mesele 1-200
          const tables = {};
          for (let i = 1; i <= 200; i++) {
            tables[i] = { number: i, status: 'free', lastOrder: null };
          }
          
          // Actualizează statusul meselelor cu comenzi active
          rows.forEach(order => {
            const tableNum = parseInt(order.table_number);
            if (tableNum >= 1 && tableNum <= 200) {
              // Păstrează statusul cel mai recent pentru fiecare masă
              if (!tables[tableNum].lastOrder || new Date(order.timestamp) > new Date(tables[tableNum].lastOrder)) {
                tables[tableNum] = {
                  number: tableNum,
                  status: order.status,
                  lastOrder: order.timestamp
                };
              }
            }
          });
          
          console.log(`📊 Table status: ${Object.values(tables).filter(t => t.status !== 'free').length} mese ocupate din 200`);
          resolve(Object.values(tables));
        }
      });
    });

    const responseTime = Date.now() - startTime;
    
    const dashboardData = {
      timestamp: new Date().toISOString(),
      today: {
        total_orders: todayStats.total_orders || 0,
        total_revenue: todayStats.total_revenue || 0,
        avg_order_value: todayStats.avg_order_value || 0,
        total_items: todayStats.total_items || 0
      },
      active: {
        active_orders: activeStats.active_orders || 0
      },
      top_products: topProducts || [],
      table_status: tableStatus || [],
      system: {
        uptime: process.uptime(),
        memory: process.memoryUsage(),
        response_time: responseTime,
        active_connections: io.engine.clientsCount
      }
    };

    console.log('✅ Dashboard data prepared:', dashboardData);
    res.json(dashboardData);

  } catch (error) {
    console.error('❌ Dashboard metrics error:', error);
    res.status(500).json({ 
      error: 'Failed to load dashboard data',
      details: error.message,
      timestamp: new Date().toISOString()
    });
  }
});

// GET /api/analytics/cancellation-stats - Statistici pentru analiză anulări
app.get('/api/analytics/cancellation-stats', async (req, res) => {
  try {
    console.log('📊 Cancellation analytics requested');
    const db = await dbPromise;
    
    const period = req.query.period || 'week';
    const startDate = req.query.startDate;
    const endDate = req.query.endDate;
    
    // Calculează intervalul de timp
    let startTimestamp, endTimestamp;
    const now = new Date();
    const today = now.toISOString().split('T')[0]; // Format: YYYY-MM-DD
    
    if (period === 'custom' && startDate && endDate) {
      startTimestamp = startDate + 'T00:00:00.000Z';
      endTimestamp = endDate + 'T23:59:59.999Z';
    } else if (period === 'day') {
      // Astăzi: de la 00:00:00 până la 23:59:59
      startTimestamp = today + 'T00:00:00.000Z';
      endTimestamp = today + 'T23:59:59.999Z';
    } else if (period === 'week') {
      // Ultima săptămână
      const weekAgo = new Date(now);
      weekAgo.setDate(weekAgo.getDate() - 7);
      startTimestamp = weekAgo.toISOString().split('T')[0] + 'T00:00:00.000Z';
      endTimestamp = today + 'T23:59:59.999Z';
    } else if (period === 'month') {
      // Ultima lună
      const monthAgo = new Date(now);
      monthAgo.setMonth(monthAgo.getMonth() - 1);
      startTimestamp = monthAgo.toISOString().split('T')[0] + 'T00:00:00.000Z';
      endTimestamp = today + 'T23:59:59.999Z';
    } else if (period === 'year') {
      // Ultimul an
      const yearAgo = new Date(now);
      yearAgo.setFullYear(yearAgo.getFullYear() - 1);
      startTimestamp = yearAgo.toISOString().split('T')[0] + 'T00:00:00.000Z';
      endTimestamp = today + 'T23:59:59.999Z';
    } else {
      // Default: ultima săptămână
      const weekAgo = new Date(now);
      weekAgo.setDate(weekAgo.getDate() - 7);
      startTimestamp = weekAgo.toISOString().split('T')[0] + 'T00:00:00.000Z';
      endTimestamp = today + 'T23:59:59.999Z';
    }
    
    console.log(`📅 Period: ${period}, From: ${startTimestamp}, To: ${endTimestamp}`);
    console.log(`🔍 Query params:`, req.query);
    
    // 1. General Stats
    const generalStats = await new Promise((resolve, reject) => {
      // Query simplă pentru total și anulate
      db.all(`
        SELECT 
          id,
          items,
          status,
          timestamp,
          cancelled_timestamp
        FROM orders
        WHERE timestamp >= ? AND timestamp <= ?
      `, [startTimestamp, endTimestamp], (err, rows) => {
        if (err) {
          reject(err);
        } else {
          let totalOrders = rows.length;
          let cancelledOrders = 0;
          let cancelledValue = 0;
          let totalCancelTime = 0;
          
          // Procesează fiecare comandă
          rows.forEach(order => {
            if (order.status === 'cancelled') {
              cancelledOrders++;
              
              // Calculează valoarea comenzii anulate
              try {
                const items = typeof order.items === 'string' ? JSON.parse(order.items) : order.items;
                items.forEach(item => {
                  const price = item.finalPrice || item.price || 0;
                  const quantity = item.quantity || 0;
                  cancelledValue += price * quantity;
                });
              } catch (e) {
                console.error('Error parsing items for value:', e);
              }
              
              // Calculează timpul de anulare (dacă există cancelled_timestamp)
              if (order.cancelled_timestamp && order.timestamp) {
                const placedTime = new Date(order.timestamp).getTime();
                const cancelledTime = new Date(order.cancelled_timestamp).getTime();
                const diffMinutes = (cancelledTime - placedTime) / 1000 / 60;
                totalCancelTime += diffMinutes;
              }
            }
          });
          
          const avgCancelTime = cancelledOrders > 0 ? Math.round(totalCancelTime / cancelledOrders) : 0;
          
          console.log(`📊 Stats calculated: ${cancelledOrders} anulate din ${totalOrders}, valoare: ${cancelledValue.toFixed(2)} RON`);
          console.log(`   Total rows from DB: ${rows.length}`);
          console.log(`   Cancelled rows: ${rows.filter(r => r.status === 'cancelled').length}`);
          
          resolve({
            total_orders: totalOrders,
            cancelled_orders: cancelledOrders,
            cancellation_rate: totalOrders > 0 ? (cancelledOrders / totalOrders * 100) : 0,
            cancelled_value: cancelledValue,
            avg_cancel_time_minutes: avgCancelTime
          });
        }
      });
    });
    
    // 2. Hourly Distribution (anulări pe ore)
    const hourlyDistribution = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          CAST(strftime('%H', timestamp) AS INTEGER) as hour,
          COUNT(*) as count
        FROM orders
        WHERE status = 'cancelled'
          AND timestamp >= ? AND timestamp <= ?
        GROUP BY hour
        ORDER BY hour
      `, [startTimestamp, endTimestamp], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // 3. Cancellation Reasons (motive anulare)
    const cancellationReasons = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          cancelled_reason as reason,
          COUNT(*) as count
        FROM orders
        WHERE status = 'cancelled'
          AND timestamp >= ? AND timestamp <= ?
        GROUP BY cancelled_reason
        ORDER BY count DESC
        LIMIT 10
      `, [startTimestamp, endTimestamp], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // 4. Top Cancelled Products (produse cu cele mai multe anulări)
    const topCancelledProducts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT items
        FROM orders
        WHERE status = 'cancelled'
          AND timestamp >= ? AND timestamp <= ?
      `, [startTimestamp, endTimestamp], (err, rows) => {
        if (err) reject(err);
        else {
          const productCounts = {};
          rows.forEach(order => {
            try {
              const items = typeof order.items === 'string' ? JSON.parse(order.items) : order.items;
              items.forEach(item => {
                if (productCounts[item.name]) {
                  productCounts[item.name]++;
                } else {
                  productCounts[item.name] = 1;
                }
              });
            } catch (e) {
              console.error('Error parsing items:', e);
            }
          });
          
          const sorted = Object.entries(productCounts)
            .map(([name, count]) => ({ name, cancellation_count: count }))
            .sort((a, b) => b.cancellation_count - a.cancellation_count)
            .slice(0, 10);
          
          resolve(sorted);
        }
      });
    });
    
    // 5. Trends (trend zilnic/săptămânal)
    const trends = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          DATE(timestamp) as date,
          COUNT(*) as count
        FROM orders
        WHERE status = 'cancelled'
          AND timestamp >= ? AND timestamp <= ?
        GROUP BY date
        ORDER BY date
      `, [startTimestamp, endTimestamp], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    const analyticsData = {
      general_stats: generalStats,
      hourly_distribution: hourlyDistribution,
      cancellation_reasons: cancellationReasons,
      top_cancelled_products: topCancelledProducts,
      trends: trends,
      period: period,
      timestamp: new Date().toISOString()
    };
    
    console.log(`✅ Cancellation analytics: ${generalStats.cancelled_orders} anulări din ${generalStats.total_orders} comenzi`);
    console.log(`📤 Sending analytics data:`, JSON.stringify(analyticsData, null, 2));
    res.json(analyticsData);
    
  } catch (error) {
    console.error('❌ Cancellation analytics error:', error);
    res.status(500).json({ 
      error: 'Failed to load cancellation analytics',
      details: error.message
    });
  }
});

// GET /api/dashboard/real-time-metrics - Dashboard metrics (legacy)
app.get('/api/dashboard/real-time-metrics', checkAdminAuth, async (req, res) => {
  try {
    console.log('🔍 Dashboard metrics requested');
    const db = await dbPromise;
    const now = new Date();
    const today = now.toISOString().split('T')[0];
    
    // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
    const currentHour = now.getHours();
    let startTime, endTime;
    if (currentHour >= 8) {
      startTime = new Date(now);
      startTime.setHours(8, 0, 0, 0);
      endTime = new Date(now);
      endTime.setDate(endTime.getDate() + 1);
      endTime.setHours(3, 0, 0, 0);
    } else {
      startTime = new Date(now);
      startTime.setDate(startTime.getDate() - 1);
      startTime.setHours(8, 0, 0, 0);
      endTime = new Date(now);
      endTime.setHours(3, 0, 0, 0);
    }
    
    // Query pentru comenzi din interval
    const todayOrders = await new Promise((resolve, reject) => {
      db.get('SELECT COUNT(*) as count FROM orders WHERE created_at >= ? AND created_at <= ?', 
        [startTime.toISOString(), endTime.toISOString()], (err, row) => {
        if (err) reject(err);
        else resolve(row.count);
      });
    });
    
    // Query pentru venituri din interval
    const todayRevenue = await new Promise((resolve, reject) => {
      db.get('SELECT SUM(total) as revenue FROM orders WHERE created_at >= ? AND created_at <= ? AND is_paid = 1', 
        [startTime.toISOString(), endTime.toISOString()], (err, row) => {
        if (err) reject(err);
        else resolve(row.revenue || 0);
      });
    });
    
    // Query pentru comenzi active
    const activeOrders = await new Promise((resolve, reject) => {
      db.get('SELECT COUNT(*) as count FROM orders WHERE status IN ("pending", "preparing")', [], (err, row) => {
        if (err) reject(err);
        else resolve(row.count);
      });
    });
    
    // Query pentru top produse
    const topProducts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT m.name, SUM(CAST(JSON_EXTRACT(item.value, '$.quantity') AS INTEGER)) as quantity
        FROM orders o
        CROSS JOIN JSON_EACH(JSON_EXTRACT(o.items, '$')) as item
        JOIN menu m ON CAST(JSON_EXTRACT(item.value, '$.productId') AS INTEGER) = m.id
        WHERE o.is_paid = 1 AND o.created_at >= ? AND o.created_at <= ?
        GROUP BY m.id, m.name
        ORDER BY quantity DESC
        LIMIT 5
      `, [startTime.toISOString(), endTime.toISOString()], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // Performance metrics
    const memUsage = process.memoryUsage();
    const performance = {
      responseTime: 0,
      activeConnections: io.engine.clientsCount,
      memoryUsage: Math.round(memUsage.heapUsed / 1024 / 1024)
    };
    
    console.log('✅ Dashboard data prepared successfully');
    
    res.json({
      success: true,
      timestamp: now,
      data: {
        todayOrders: todayOrders,
        todayRevenue: todayRevenue,
        activeOrders: activeOrders,
        avgOrderTime: 0,
        tableStatus: [],
        topProducts: topProducts,
        performance: performance,
        revenueHistory: []
      }
    });
  } catch (error) {
    console.error('❌ Error fetching real-time metrics:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// GET /api/admin/top-products - Top produse vândute
app.get('/api/admin/top-products', checkAdminAuth, async (req, res) => {
    try {
      const { startDate, endDate, category } = req.query;
      
      // Construiește query-ul pentru filtrarea perioadei
      let dateFilter = '';
      let params = [];
      
      if (startDate && endDate) {
        dateFilter = 'AND o.timestamp >= ? AND o.timestamp <= ?';
        params.push(startDate + 'T00:00:00.000Z', endDate + 'T23:59:59.999Z');
      } else if (startDate) {
        dateFilter = 'AND o.timestamp >= ?';
        params.push(startDate + 'T00:00:00.000Z');
      } else if (endDate) {
        dateFilter = 'AND o.timestamp <= ?';
        params.push(endDate + 'T23:59:59.999Z');
      }
      
      // Construiește query-ul pentru filtrarea categoriilor
      let categoryFilter = '';
      if (category === 'alimente') {
        categoryFilter = `AND m.category NOT IN ('Cafea/Ciocolată/Ceai', 'Răcoritoare', 'Băuturi și Coctailuri')`;
      } else if (category === 'bauturi') {
        categoryFilter = `AND m.category IN ('Cafea/Ciocolată/Ceai', 'Răcoritoare', 'Băuturi și Coctailuri')`;
      }
      
      const query = `
        SELECT 
          m.id,
          m.name,
          m.category,
          m.price,
          SUM(CAST(JSON_EXTRACT(item.value, '$.quantity') AS INTEGER)) as total_quantity,
          SUM(CAST(JSON_EXTRACT(item.value, '$.quantity') AS INTEGER) * m.price) as total_value
        FROM orders o
        CROSS JOIN JSON_EACH(JSON_EXTRACT(o.items, '$')) as item
        JOIN menu m ON CAST(JSON_EXTRACT(item.value, '$.productId') AS INTEGER) = m.id
        WHERE o.is_paid = 1
          ${dateFilter}
          ${categoryFilter}
        GROUP BY m.id, m.name, m.category, m.price
        HAVING total_quantity > 0
        ORDER BY total_quantity DESC, total_value DESC
        LIMIT 50
      `;
      
      const products = await new Promise((resolve, reject) => {
        db.all(query, params, (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Calculează statisticile generale
      const statsQuery = `
        SELECT 
          SUM(CAST(JSON_EXTRACT(item.value, '$.quantity') AS INTEGER)) as total_quantity,
          SUM(CAST(JSON_EXTRACT(item.value, '$.quantity') AS INTEGER) * m.price) as total_value
        FROM orders o
        CROSS JOIN JSON_EACH(JSON_EXTRACT(o.items, '$')) as item
        JOIN menu m ON CAST(JSON_EXTRACT(item.value, '$.productId') AS INTEGER) = m.id
        WHERE o.is_paid = 1
          ${dateFilter}
          ${categoryFilter}
      `;
      
      const stats = await new Promise((resolve, reject) => {
        db.get(statsQuery, params, (err, row) => {
          if (err) reject(err);
          else resolve(row || { total_quantity: 0, total_value: 0 });
        });
      });
      
      res.json({
        success: true,
        products: products,
        stats: stats
      });
      
    } catch (error) {
      console.error('Error fetching top products:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la încărcarea top produselor' 
      });
    }
  });

  app.get('/api/admin/products/:id', checkAdminAuth, (req, res) => {
    const productId = req.params.id;
    db.get('SELECT * FROM menu WHERE id = ?', [productId], (err, product) => {
      if (err) return res.status(500).json({ error: err.message });
      if (!product) return res.status(404).json({ error: 'Produs nu a fost găsit' });
      
      product.hasImage = require('fs').existsSync(require('path').join(__dirname, 'public', 'images', 'menu', `${product.id}.jpg`));
      res.json(product);
    });
  });

  app.post('/api/admin/products', checkAdminAuth, upload.single('image'), async (req, res) => {
    const {
      name, price, category, description, weight, is_vegetarian, is_spicy, is_takeout_only, allergens,
      name_en, description_en, category_en, allergens_en, info, ingredients, prep_time, spice_level, calories, protein, carbs, fat,
      fiber, sodium, sugar, salt, recipe_ingredients, stock_management, preparation_section
    } = req.body;
    
    console.log('📦 Creating product:', { name, category, price, description, stock_management, preparation_section });
    console.log('📦 Ingredients (old format):', ingredients);
    console.log('📦 Recipe ingredients (new format):', recipe_ingredients);
    
    try {
      const database = await dbPromise;
      
      // Gestionează imaginea dacă există
      let imageUrl = null;
      if (req.file) {
        imageUrl = `/images/menu/${req.file.filename}`;
      }
      
      // 1. Creează produsul în tabela menu
      const sql = `INSERT INTO menu (
        name, price, category, description, weight, is_vegetarian, is_spicy, is_takeout_only, allergens,
        name_en, description_en, category_en, allergens_en, info, ingredients, prep_time, spice_level, calories, protein, carbs, fat,
        fiber, sodium, sugar, salt, image_url, stock_management, preparation_section
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`;
      
      const params = [
        name, price, category, description, weight, is_vegetarian ? 1 : 0, is_spicy ? 1 : 0, is_takeout_only ? 1 : 0, allergens,
        name_en, description_en, category_en, allergens_en, info, ingredients, prep_time, spice_level, calories, protein, carbs, fat,
        fiber, sodium, sugar, salt, imageUrl, stock_management, preparation_section
      ];
      
      const productId = await new Promise((resolve, reject) => {
        database.run(sql, params, function(err) {
          if (err) {
            console.error('❌ Error creating product:', err);
            reject(err);
          } else {
            resolve(this.lastID);
          }
        });
      });
      
      console.log('✅ Product created successfully with ID:', productId);
      
      // 2. Gestionare imagine (redenumire cu ID-ul produsului)
      if (req.file && imageUrl) {
        const oldPath = path.join(__dirname, 'public', 'images', 'menu', req.file.filename);
        const ext = path.extname(req.file.filename);
        const newPath = path.join(__dirname, 'public', 'images', 'menu', `${productId}${ext}`);
        
        try {
          await fs.promises.rename(oldPath, newPath);
          imageUrl = `/images/menu/${productId}${ext}`;
          
          await new Promise((resolve, reject) => {
            database.run('UPDATE menu SET image_url = ? WHERE id = ?', [imageUrl, productId], (err) => {
              if (err) reject(err);
              else resolve();
            });
          });
          
          console.log('✅ Image renamed and updated:', imageUrl);
        } catch (renameErr) {
          console.error('⚠️ Eroare la redenumirea fișierului:', renameErr);
        }
      }
      
      // 3. Procesare ingrediente din rețetă (dacă există)
      let createdIngredients = [];
      let calculatedNutrition = null;
      
      if (recipe_ingredients) {
        const { fetchNutritionalData, detectCategory } = require('./nutritionApi');
        let recipeList = [];
        
        // Parse JSON dacă e string
        if (typeof recipe_ingredients === 'string') {
          try {
            recipeList = JSON.parse(recipe_ingredients);
          } catch (e) {
            console.error('⚠️ Nu pot parsa recipe_ingredients:', e);
            recipeList = [];
          }
        } else {
          recipeList = recipe_ingredients;
        }
        
        console.log(`📋 Procesare ${recipeList.length} ingrediente pentru rețetă...`);
        
        // Accumulatori pentru calcul nutrițional
        let totalCalories = 0;
        let totalProtein = 0;
        let totalCarbs = 0;
        let totalFat = 0;
        let totalFiber = 0;
        let totalSalt = 0;
        let allAllergens = new Set();
        
        for (const recipeItem of recipeList) {
          const { ingredient_name, ingredient_id, quantity, unit, waste_percentage, item_type } = recipeItem;
          
          let finalIngredientId = ingredient_id;
          let ingredientData = null;
          
          // Dacă nu avem ingredient_id, înseamnă că e ingredient nou
          if (!finalIngredientId && ingredient_name) {
            console.log(`🆕 Ingredient nou: "${ingredient_name}"`);
            
            // Caută date nutriționale automat
            const nutritionData = await fetchNutritionalData(ingredient_name, 'ro');
            
            if (nutritionData) {
              console.log(`✅ Date găsite de pe ${nutritionData.source}`);
              ingredientData = nutritionData;
            } else {
              console.log(`⚠️ Nu s-au găsit date pentru "${ingredient_name}". Folosesc detectare automată.`);
              ingredientData = {
                category: detectCategory(ingredient_name),
                energy_kcal: 0,
                protein: 0,
                fat: 0,
                carbs: 0,
                fiber: 0,
                salt: 0,
                allergens: '',
                additives: ''
              };
            }
            
            // Creează ingredientul în baza de date
            finalIngredientId = await new Promise((resolve, reject) => {
              database.run(
                `INSERT INTO ingredients (
                  name, category, unit, current_stock, min_stock, cost_per_unit,
                  description, energy_kcal, fat, saturated_fat, carbs, sugars, protein, salt, fiber,
                  allergens, additives, potential_allergens
                ) VALUES (?, ?, ?, 0, 0, 0, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
                [
                  ingredient_name,
                  ingredientData.category || 'Altele',
                  unit || 'g',
                  ingredientData.description || `Auto-creat pentru ${name}`,
                  ingredientData.energy_kcal || 0,
                  ingredientData.fat || 0,
                  ingredientData.saturated_fat || 0,
                  ingredientData.carbs || 0,
                  ingredientData.sugars || 0,
                  ingredientData.protein || 0,
                  ingredientData.salt || 0,
                  ingredientData.fiber || 0,
                  ingredientData.allergens || '',
                  ingredientData.additives || '',
                  ingredientData.potential_allergens || ''
                ],
                function(err) {
                  if (err) {
                    console.error(`❌ Eroare la crearea ingredientului "${ingredient_name}":`, err);
                    reject(err);
                  } else {
                    console.log(`✅ Ingredient creat: "${ingredient_name}" cu ID ${this.lastID}`);
                    resolve(this.lastID);
                  }
                }
              );
            });
            
            createdIngredients.push({ id: finalIngredientId, name: ingredient_name, source: ingredientData.source || 'detectare automată' });
          } else if (finalIngredientId) {
            // Ingredient existent, obține datele din BD
            ingredientData = await new Promise((resolve, reject) => {
              database.get(
                'SELECT energy_kcal, protein, fat, carbs, fiber, salt, allergens FROM ingredients WHERE id = ?',
                [finalIngredientId],
                (err, row) => {
                  if (err) reject(err);
                  else resolve(row);
                }
              );
            });
          }
          
          // Adaugă în rețetă (recipes table)
          if (finalIngredientId && item_type === 'ingredient') {
            await new Promise((resolve, reject) => {
              database.run(
                `INSERT INTO recipes (product_id, ingredient_id, quantity_needed, unit, waste_percentage, item_type, created_at)
                 VALUES (?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)`,
                [productId, finalIngredientId, quantity, unit, waste_percentage || 0, item_type || 'ingredient'],
                (err) => {
                  if (err) {
                    console.error('❌ Eroare la adăugarea în rețetă:', err);
                    reject(err);
                  } else {
                    resolve();
                  }
                }
              );
            });
            
            // Calculează contribuția nutrițională
            if (ingredientData && quantity) {
              const quantityInGrams = parseFloat(quantity) || 0;
              const wasteFactor = 1 + (parseFloat(waste_percentage) || 0) / 100;
              const effectiveQuantity = quantityInGrams * wasteFactor / 100; // Convertește la factori de calcul
              
              totalCalories += (ingredientData.energy_kcal || 0) * effectiveQuantity;
              totalProtein += (ingredientData.protein || 0) * effectiveQuantity;
              totalCarbs += (ingredientData.carbs || 0) * effectiveQuantity;
              totalFat += (ingredientData.fat || 0) * effectiveQuantity;
              totalFiber += (ingredientData.fiber || 0) * effectiveQuantity;
              totalSalt += (ingredientData.salt || 0) * effectiveQuantity;
              
              // Colectează alergeni
              if (ingredientData.allergens) {
                ingredientData.allergens.split(',').forEach(a => allAllergens.add(a.trim()));
              }
            }
          }
        }
        
        // Actualizează valorile nutriționale calculate
        calculatedNutrition = {
          calories: Math.round(totalCalories),
          protein: Math.round(totalProtein * 10) / 10,
          carbs: Math.round(totalCarbs * 10) / 10,
          fat: Math.round(totalFat * 10) / 10,
          fiber: Math.round(totalFiber * 10) / 10,
          salt: Math.round(totalSalt * 100) / 100,
          allergens: Array.from(allAllergens).join(', ')
        };
        
        // Actualizează produsul cu valorile calculate
        await new Promise((resolve, reject) => {
          database.run(
            'UPDATE menu SET calories = ?, protein = ?, carbs = ?, fat = ?, fiber = ?, salt = ?, allergens = ? WHERE id = ?',
            [calculatedNutrition.calories, calculatedNutrition.protein, calculatedNutrition.carbs, 
             calculatedNutrition.fat, calculatedNutrition.fiber, calculatedNutrition.salt, 
             calculatedNutrition.allergens, productId],
            (err) => {
              if (err) reject(err);
              else resolve();
            }
          );
        });
        
        console.log('✅ Valori nutriționale calculate și salvate:', calculatedNutrition);
      }
      
      // 4. Invalidează cache-ul
      invalidateMenuCache();
      
      res.json({ 
        success: true, 
        message: 'Produs adăugat cu succes', 
        product_id: productId,
        id: productId, 
        imageUrl: imageUrl,
        created_ingredients: createdIngredients,
        calculated_nutrition: calculatedNutrition
      });
      
    } catch (error) {
      console.error('❌ Eroare la crearea produsului:', error);
      res.status(500).json({ error: 'Eroare la crearea produsului', details: error.message });
    }
  });

