  app.post('/api/admin/transfer-tables', checkAdminAuth, (req, res) => {
    const { fromWaiterId, toWaiterId, tables } = req.body;
    
    // Obține mesele ospătarului sursă
    db.get('SELECT tables FROM waiters WHERE id = ?', [fromWaiterId], (err, fromWaiter) => {
      if (err) return res.status(500).json({ error: err.message });
      
      const fromTables = JSON.parse(fromWaiter.tables || '[]');
      const remainingTables = fromTables.filter(table => !tables.includes(table));
      
      // Obține mesele ospătarului destinație
      db.get('SELECT tables FROM waiters WHERE id = ?', [toWaiterId], (err, toWaiter) => {
        if (err) return res.status(500).json({ error: err.message });
        
        const toTables = JSON.parse(toWaiter.tables || '[]');
        const newToTables = [...toTables, ...tables];
        
        // Actualizează mesele pentru ambii ospătari
        db.run('UPDATE waiters SET tables = ? WHERE id = ?', [JSON.stringify(remainingTables), fromWaiterId], (err) => {
          if (err) return res.status(500).json({ error: err.message });
          
          db.run('UPDATE waiters SET tables = ? WHERE id = ?', [JSON.stringify(newToTables), toWaiterId], (err) => {
            if (err) return res.status(500).json({ error: err.message });
            
            res.json({ message: 'Transfer realizat cu succes' });
          });
        });
      });
    });
  });

