  // GET /api/fiscal/paid-orders - Obține comenzile achitate structurate pe zile pentru dropdown
  app.get('/api/fiscal/paid-orders', checkAdminAuth, async (req, res) => {
    try {
      const db = await dbPromise;
      
      // Obține comenzile achitate din ultimele 30 de zile, grupate pe zile
      const query = `
        SELECT 
          id,
          table_number,
          client_identifier,
          total,
          timestamp,
          DATE(timestamp) as order_date,
          status,
          items
        FROM orders 
        WHERE is_paid = 1 
          AND timestamp >= datetime('now', '-30 days')
        ORDER BY timestamp DESC
      `;
      
      db.all(query, [], (err, rows) => {
        if (err) {
          console.error('❌ Eroare la obținerea comenzilor achitate:', err);
          return res.status(500).json({ error: 'Eroare la obținerea comenzilor achitate' });
        }
        
        // Grupează comenzile pe zile
        const ordersByDate = {};
        rows.forEach(order => {
          const dateKey = order.order_date;
          if (!ordersByDate[dateKey]) {
            ordersByDate[dateKey] = [];
          }
          
          // Parsează items pentru a obține numele produselor
          let items = [];
          try {
            items = safeParseItems(order.items) || [];
          } catch (e) {
            console.warn(`⚠️ Eroare la parsarea items pentru comanda ${order.id}:`, e.message);
            items = [];
          }
          
          // Obține numele produselor
          const productNames = items.map(item => item.name || 'Produs necunoscut').join(', ');
          
          ordersByDate[dateKey].push({
            id: order.id,
            table_number: order.table_number,
            client_identifier: order.client_identifier,
            total: order.total,
            timestamp: order.timestamp,
            status: order.status,
            items_preview: productNames.substring(0, 50) + (productNames.length > 50 ? '...' : ''),
            items_count: items.length
          });
        });
        
        // Sortează zilele descrescător
        const sortedDates = Object.keys(ordersByDate).sort((a, b) => new Date(b) - new Date(a));
        
        // Formatează răspunsul
        const result = sortedDates.map(date => ({
          date: date,
          display_date: new Date(date).toLocaleDateString('ro-RO', {
            weekday: 'long',
            year: 'numeric',
            month: 'long',
            day: 'numeric'
          }),
          orders: ordersByDate[date]
        }));
        
        console.log(`📋 Returnat ${rows.length} comenzi achitate din ${sortedDates.length} zile`);
        res.json({ success: true, orders_by_date: result });
      });
      
    } catch (error) {
      console.error('❌ Eroare la endpoint-ul paid-orders:', error);
      res.status(500).json({ error: 'Eroare internă la obținerea comenzilor achitate' });
    }
  });

  // Funcție pentru emiterea automată a bonului nefiscal
  async function emitFiscalReceipt(req, res, orderId, payment_method = 'cash') {
    try {
      const db = await dbPromise;
      const { is_fiscal = 1, waiter_id = null } = req.body || {};

      // 1. Obține detalii comandă
      const order = await new Promise((resolve, reject) => {
          db.get('SELECT total, items, table_number, type, timestamp FROM orders WHERE id = ? AND status IN (?, ?, ?)', [orderId, 'pending', 'paid', 'delivered'], (err, row) => {
              if (err) {
                  console.error('❌ Eroare la query comandă:', err);
                  reject(err);
              } else {
                  resolve(row);
              }
          });
      });
      if (!order) return { success: false, error: 'Comanda nu a fost găsită sau este deja finalizată.' };
      
      // 2. Generează numărul de bon/chitanță
      const receiptNumber = await generateFiscalNumber('RECEIPT'); 
      
      // 3. Calculează TVA și totalul
      let totalAmount = order.total || 0;
      
      // Dacă totalul este null sau 0, calculează din items
      if (!totalAmount && order.items) {
          try {
              const itemsData = safeParseItems(order.items);
              if (Array.isArray(itemsData)) {
                  totalAmount = itemsData.reduce((sum, item) => {
                      const itemPrice = item.finalPrice || item.price || 0;
                      const customizationsTotal = item.customizations ? 
                          item.customizations.reduce((customSum, custom) => customSum + (custom.price_change || 0), 0) : 0;
                      return sum + (itemPrice + customizationsTotal) * (item.quantity || 1);
                  }, 0);
              }
          } catch (e) {
              console.log('⚠️ Nu s-au putut parsa items pentru calculul totalului:', e.message);
          }
      }
      
      // Calculează TVA diferențiat pe categorii (ca în receipt-group)
      let totalVAT11 = 0;
      let totalVAT21 = 0;
      
      // Parse items pentru calculul TVA defalcat
      try {
          const itemsData = safeParseItems(order.items);
          if (Array.isArray(itemsData)) {
              const foodCategories = [
                'Aperitive', 'Aperitive Calde', 'Aperitive Reci', 'Burgeri', 'Ciorbe', 
                'Deserturi', 'Fel Principal', 'Garnituri', 'Mic Dejun', 'Paste', 
                'Paste Fresca', 'Penne Al Forno', 'Peste Fructe de Mare', 'Pizza', 
                'Platouri', 'Salate', 'Salate Însoțitoare'
              ];
              const alcoholCategories = ['Băuturi și Coctailuri'];
              
              itemsData.forEach(item => {
                  const vatFoodRate = 0.11;
                  const vatDrinksRate = 0.21;
                  
                  let vatRate = vatFoodRate;
                  if (alcoholCategories.includes(item.category)) {
                      vatRate = vatDrinksRate;
                  } else if (item.category === 'Cafea/Ciocolată/Ceai' || item.category === 'Răcoritoare') {
                      vatRate = vatDrinksRate;
                  }
                  
                  const itemTotal = (item.finalPrice || item.price || 0) * (item.quantity || 1);
                  const itemPrice = item.finalPrice || item.price || 0;
                  const unitPrice = itemPrice / (1 + vatRate);
                  const itemVAT = itemTotal - (unitPrice * item.quantity);
                  
                  if (vatRate === vatFoodRate) {
                      totalVAT11 += itemVAT;
                  } else {
                      totalVAT21 += itemVAT;
                  }
              });
          }
      } catch (e) {
          console.log('⚠️ Eroare calcul TVA defalcat, folosesc default:', e.message);
          // Fallback la calculul simplu
          const vatRate = 0.21;
          totalVAT21 = totalAmount * (vatRate / (1 + vatRate));
      }
      
      const vatAmount = Math.round((totalVAT11 + totalVAT21) * 100) / 100;

      // 4. Salvează în fiscal_receipts cu defalcare TVA
      const receiptResult = await db.run(
          'INSERT INTO fiscal_receipts (order_id, receipt_number, total_amount, vat_amount, payment_method, waiter_id, is_fiscal, vat_21, vat_11, vat_5, vat_0) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)',
          [orderId, receiptNumber, totalAmount, vatAmount, payment_method || 'cash', waiter_id || null, is_fiscal || 1, Math.round(totalVAT21 * 100) / 100, Math.round(totalVAT11 * 100) / 100, 0, 0]
      );
      const receiptId = receiptResult.lastID;
      console.log(`🔧 Bon nefiscal creat cu ID: ${receiptId} pentru comanda ${orderId} (TVA21=${Math.round(totalVAT21 * 100) / 100}, TVA11=${Math.round(totalVAT11 * 100) / 100})`);
      
      // 5. Actualizează Comanda (status 'paid', fiscal_receipt_id și payment_method)
      console.log(`🔧 Actualizez comanda ${orderId} cu fiscal_receipt_id = ${receiptId}, payment_method = ${payment_method}`);
      const updateResult = await db.run('UPDATE orders SET status = ?, fiscal_receipt_id = ?, payment_method = ?, paid_timestamp = CURRENT_TIMESTAMP WHERE id = ?', ['paid', receiptId, payment_method, orderId]);
      console.log(`✅ Comanda ${orderId} actualizată cu ${updateResult.changes} modificări`);

      // 6. Înregistrează în Registrul de Casă (doar cash)
      if (payment_method === 'cash') {
          await db.run(
              'INSERT INTO cash_register (type, document_type, document_id, amount, description, waiter_id) VALUES (?, ?, ?, ?, ?, ?)',
              ['entry', 'receipt', receiptId, totalAmount, 'Încasare comandă', waiter_id]
          );
      }
      
      // 7. Generează PDF-ul pentru bonul fiscal
      const itemsData = safeParseItems(order.items) || [];
      let pdfPath;
      try {
        console.log('🔄 Încep generarea PDF-ului pentru bonul fiscal...');
        pdfPath = await generateFiscalPDF({ 
          receipt_number: receiptNumber, 
          total_amount: totalAmount, 
          vat_amount: vatAmount, 
          issue_date: new Date(),
          order_id: orderId,
          table_number: order.table_number,
          type: order.type
        }, itemsData, 'receipt');
        
        console.log(`📄 PDF generat cu succes: ${pdfPath}`);
      } catch (pdfError) {
        console.error('❌ Eroare la generarea PDF-ului:', pdfError);
        // Continuă fără PDF - bonul fiscal este înregistrat în baza de date
        pdfPath = null;
      }

      return { 
        success: true, 
        receipt_number: receiptNumber,
        receipt_id: receiptId,
        total_amount: totalAmount,
        vat_amount: vatAmount,
        payment_method: payment_method,
        order: order,
        pdfUrl: pdfPath ? `/documents/receipt_${receiptNumber}.pdf` : null
      };
      
    } catch (error) {
      console.error('❌ Eroare la emiterea bonului nefiscal:', error);
      return { success: false, error: error.message };
    }
  }

  /**
   * Obține și agregează datele (items și total) dintr-un grup de comenzi.
   */
  async function getGroupOrderData(orderIds) {
    if (!orderIds || orderIds.length === 0) {
      return { totalAmount: 0, aggregatedItems: [] };
    }

    const db = await dbPromise;
    const placeholders = orderIds.map(() => '?').join(',');

    const orders = await new Promise((resolve, reject) => {
      db.all(`SELECT id, items, total FROM orders WHERE id IN (${placeholders}) AND is_paid = 1`, orderIds, (err, rows) => {
        if (err) { 
          console.error('❌ Eroare la query-ul comenzilor din grup:', err); 
          reject(err); 
        } else { 
          resolve(rows || []); 
        }
      });
    });

    // Obține categoriile pentru toate produsele din items-uri
    const allProductIds = new Set();
    orders.forEach(order => {
      if (order.items) {
        const itemsData = safeParseItems(order.items);
        if (Array.isArray(itemsData)) {
          itemsData.forEach(item => {
            if (item.productId) {
              allProductIds.add(item.productId);
            }
          });
        }
      }
    });

    // Obține categoriile din baza de date
    const productCategories = new Map();
    if (allProductIds.size > 0) {
      const productPlaceholders = Array.from(allProductIds).map(() => '?').join(',');
      const categories = await new Promise((resolve, reject) => {
        db.all(`SELECT id, category FROM menu WHERE id IN (${productPlaceholders})`, Array.from(allProductIds), (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      categories.forEach(cat => {
        productCategories.set(cat.id, cat.category);
      });
    }

    let totalAmount = 0;
    const itemMap = new Map();

    orders.forEach(order => {
      if (order.total && order.total > 0) {
        totalAmount += order.total;
      } else if (order.items) {
        // Calculează totalul din items dacă order.total este null sau 0
        const itemsData = safeParseItems(order.items);
        if (Array.isArray(itemsData)) {
          const orderTotal = itemsData.reduce((sum, item) => {
            const itemPrice = item.finalPrice || item.price || 0;
            const customizationsTotal = item.customizations ? 
                item.customizations.reduce((customSum, custom) => customSum + (custom.price_change || 0), 0) : 0;
            return sum + (itemPrice + customizationsTotal) * (item.quantity || 1);
          }, 0);
          totalAmount += orderTotal;
        }
      }

      if (order.items) {
        const itemsData = safeParseItems(order.items);
        if (Array.isArray(itemsData)) {
            itemsData.forEach(item => {
              const key = item.productId + (item.customizations ? JSON.stringify(item.customizations) : '');
              
              // Adaugă categoria la item
              item.category = productCategories.get(item.productId) || 'Necunoscută';
              
              if (itemMap.has(key)) {
                const existingItem = itemMap.get(key);
                existingItem.quantity += (item.quantity || 1);
              } else {
                const newItem = { ...item }; 
                const itemPrice = newItem.finalPrice || newItem.price || 0;
                const customizationsTotal = newItem.customizations ? newItem.customizations.reduce((customSum, custom) => customSum + (custom.price_change || 0), 0) : 0;
                
                newItem.finalPrice = itemPrice + customizationsTotal;
                itemMap.set(key, newItem);
              }
            });
        }
      }
    });
    
    return { 
      totalAmount: Math.round(totalAmount * 100) / 100, 
      aggregatedItems: Array.from(itemMap.values()).map(item => ({
        ...item,
        total: (item.quantity * item.finalPrice) // Calculează totalul pe linie
      }))
    };
  }

  // Funcție pentru generarea unui bon nefiscal grupat pentru mai multe comenzi
  async function generateGroupFiscalReceipt(groupOrders, payment_method = 'cash') {
    try {
      const db = await dbPromise;
      
      // 1. Generează numărul de bon nefiscal
      const receiptNumber = await generateFiscalNumber('RECEIPT');
      
      // 2. Calculează totalul pentru toate comenzile din grup
      let totalAmount = 0;
      const allItems = [];
      
      for (const order of groupOrders) {
        let orderTotal = order.total || 0;
        
        // Dacă totalul este null sau 0, calculează din items
        if (!orderTotal && order.items) {
          try {
            const itemsData = safeParseItems(order.items);
            if (Array.isArray(itemsData)) {
              orderTotal = itemsData.reduce((sum, item) => {
                const itemPrice = item.finalPrice || item.price || 0;
                const customizationsTotal = item.customizations ? 
                    item.customizations.reduce((customSum, custom) => customSum + (custom.price_change || 0), 0) : 0;
                return sum + (itemPrice + customizationsTotal) * (item.quantity || 1);
              }, 0);
              
              console.log(`📊 Calculat total pentru comanda ${order.id}: ${orderTotal} RON din ${itemsData.length} produse`);
            }
          } catch (e) {
            console.log('⚠️ Nu s-au putut parsa items pentru comanda', order.id, ':', e.message);
          }
        }
        
        // Adaugă items-urile la lista totală pentru bonul fiscal
        if (order.items) {
          try {
            const itemsData = safeParseItems(order.items);
            if (Array.isArray(itemsData)) {
              itemsData.forEach(item => {
                allItems.push({
                  ...item,
                  orderId: order.id,
                  orderNumber: order.id,
                  category: item.category || 'general', // Adaugă categoria pentru calculul TVA
                  // Asigură-te că există proprietățile necesare
                  name: item.name || 'Produs necunoscut',
                  quantity: item.quantity || 1,
                  price: item.price || item.finalPrice || 0,
                  total_price: item.total_price || item.finalPrice || (item.price || 0) * (item.quantity || 1),
                  finalPrice: item.finalPrice || item.price || 0
                });
              });
              console.log(`📦 Adăugat ${itemsData.length} produse pentru comanda ${order.id} la bonul fiscal`);
            }
          } catch (e) {
            console.log('⚠️ Nu s-au putut parsa items pentru bonul fiscal pentru comanda', order.id, ':', e.message);
          }
        }
        
        totalAmount += orderTotal;
      }
      
      // 3. Calculează TVA diferențiat pe categorii
      let totalVAT11 = 0; // TVA 11% pentru alimente
      let totalVAT21 = 0; // TVA 21% pentru băuturi alcoolice
      
      // Categorii cu TVA 11% (alimente)
      const foodCategories = [
        'Aperitive', 'Aperitive Calde', 'Aperitive Reci', 'Burgeri', 'Ciorbe', 
        'Deserturi', 'Fel Principal', 'Garnituri', 'Mic Dejun', 'Paste', 
        'Paste Fresca', 'Penne Al Forno', 'Peste Fructe de Mare', 'Pizza', 
        'Platouri', 'Salate', 'Salate Însoțitoare'
      ];
      
      // Categorii cu TVA 21% (băuturi alcoolice și alte produse)
      const alcoholCategories = ['Băuturi și Coctailuri'];
      
      // Calculează TVA pentru fiecare item din allItems
      allItems.forEach(item => {
        // Determină categoria TVA pe baza categoriei produsului
        const vatFoodRate = 0.11; // 11% pentru alimente
        const vatDrinksRate = 0.21; // 21% pentru băuturi
        
        let vatRate = vatFoodRate; // Default pentru alimente
        if (alcoholCategories.includes(item.category)) {
          vatRate = vatDrinksRate; // Băuturi alcoolice
        } else if (item.category === 'Cafea/Ciocolată/Ceai' || item.category === 'Răcoritoare') {
          vatRate = vatDrinksRate; // Băuturi non-alcoolice
        }
        
        // Calculează TVA pe categorii
        const itemTotal = item.total_price || item.finalPrice || (item.price || 0) * (item.quantity || 1);
        const itemPrice = item.finalPrice || item.price || 0;
        const unitPrice = itemPrice / (1 + vatRate);
        const itemVAT = itemTotal - (unitPrice * item.quantity);
        
        if (vatRate === vatFoodRate) {
          totalVAT11 += itemVAT;
        } else {
          totalVAT21 += itemVAT;
        }
      });
      
      const vatAmount = Math.round((totalVAT11 + totalVAT21) * 100) / 100;
      
      // Validare pentru a evita erorile SQL
      if (isNaN(vatAmount) || isNaN(totalAmount)) {
        console.error('❌ Eroare la calculul TVA în generateGroupFiscalReceipt:', { totalAmount, vatAmount, totalVAT11, totalVAT21 });
        return { success: false, error: 'Eroare la calculul TVA pentru bonul fiscal grupat' };
      }
      
      // 4. Salvează în fiscal_receipts cu primul order_id ca referință și defalcarea TVA
      const receiptResult = await db.run(
        `INSERT INTO fiscal_receipts (
          order_id, receipt_number, total_amount, vat_amount, 
          payment_method, waiter_id, is_fiscal,
          vat_21, vat_11, vat_5, vat_0
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
        [
          groupOrders[0].id, 
          receiptNumber, 
          totalAmount, 
          vatAmount, 
          payment_method, 
          null, 
          1,
          Math.round(totalVAT21 * 100) / 100,  // Salvează TVA 21%
          Math.round(totalVAT11 * 100) / 100,  // Salvează TVA 11%
          0,  // TVA 5%
          0   // TVA 0%
        ]
      );
      const receiptId = receiptResult.lastID;
      
      console.log(`🔧 Bon nefiscal grupat creat cu ID: ${receiptId} pentru ${groupOrders.length} comenzi (TVA21=${Math.round(totalVAT21 * 100) / 100}, TVA11=${Math.round(totalVAT11 * 100) / 100})`);
      
      // 5. Înregistrează în Registrul de Casă (doar cash)
      if (payment_method === 'cash') {
        await db.run(
          'INSERT INTO cash_register (type, document_type, document_id, amount, description, waiter_id) VALUES (?, ?, ?, ?, ?, ?)',
          ['entry', 'receipt', receiptId, totalAmount, `Încasare grup comenzi (${groupOrders.length} comenzi)`, null]
        );
      }
      
      return { 
        success: true, 
        receipt_number: receiptNumber,
        receipt_id: receiptId,
        total_amount: totalAmount,
        vat_amount: vatAmount,
        vat_11_amount: totalVAT11,
        vat_21_amount: totalVAT21,
        subtotal: totalAmount - vatAmount,
        payment_method: payment_method,
        groupOrders: groupOrders,
        allItems: allItems
      };
      
    } catch (error) {
      console.error('❌ Eroare la generarea bonului nefiscal grupat:', error);
      return { success: false, error: error.message };
    }
  }

