  // Funcție helper pentru agregarea TVA din bonurile fiscale (NU recalculează, doar citește)
  async function getVATBreakdownFromReceipts(db, receiptIds) {
    if (!receiptIds || receiptIds.length === 0) {
      return { vat21: 0, vat11: 0, vat5: 0, vat0: 0 };
    }
    
    const placeholders = receiptIds.map(() => '?').join(',');
    const result = await new Promise((resolve, reject) => {
      db.get(`
        SELECT 
          SUM(vat_21) as vat21,
          SUM(vat_11) as vat11,
          SUM(vat_5) as vat5,
          SUM(vat_0) as vat0
        FROM fiscal_receipts
        WHERE id IN (${placeholders})
      `, receiptIds, (err, row) => {
        if (err) reject(err);
        else resolve(row || {});
      });
    });
    
    return {
      vat21: parseFloat((result.vat21 || 0).toFixed(2)),
      vat11: parseFloat((result.vat11 || 0).toFixed(2)),
      vat5: parseFloat((result.vat5 || 0).toFixed(2)),
      vat0: parseFloat((result.vat0 || 0).toFixed(2))
    };
  }
  
  // Funcție helper pentru agregarea TVA din comenzi și produsele lor
  async function getVATBreakdownFromOrders(db, orderIds) {
    if (!orderIds || orderIds.length === 0) {
      return { vat21: 0, vat11: 0, vat5: 0, vat0: 0 };
    }
    
    const placeholders = orderIds.map(() => '?').join(',');
    const result = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          oi.total_price,
          p.vat_rate,
          CASE 
            WHEN p.vat_rate = 21 THEN oi.total_price * p.vat_rate / (100 + p.vat_rate)
            ELSE 0
          END as vat_21,
          CASE 
            WHEN p.vat_rate = 11 THEN oi.total_price * p.vat_rate / (100 + p.vat_rate)
            ELSE 0
          END as vat_11,
          CASE 
            WHEN p.vat_rate = 5 THEN oi.total_price * p.vat_rate / (100 + p.vat_rate)
            ELSE 0
          END as vat_5,
          CASE 
            WHEN p.vat_rate = 0 THEN 0
            ELSE 0
          END as vat_0
        FROM order_items oi
        LEFT JOIN products p ON oi.product_name = p.name
        WHERE oi.order_id IN (${placeholders})
      `, orderIds, (err, rows) => {
        if (err) {
          reject(err);
        } else {
          const breakdown = rows.reduce((acc, row) => {
            acc.vat21 += row.vat_21 || 0;
            acc.vat11 += row.vat_11 || 0;
            acc.vat5 += row.vat_5 || 0;
            acc.vat0 += row.vat_0 || 0;
            return acc;
          }, { vat21: 0, vat11: 0, vat5: 0, vat0: 0 });
          resolve(breakdown);
        }
      });
    });
    
    return {
      vat21: parseFloat((result.vat21 || 0).toFixed(2)),
      vat11: parseFloat((result.vat11 || 0).toFixed(2)),
      vat5: parseFloat((result.vat5 || 0).toFixed(2)),
      vat0: parseFloat((result.vat0 || 0).toFixed(2))
    };
  }

  // POST /api/fiscal/report-x - Generează Raport X pentru o dată specifică
  app.post('/api/fiscal/report-x', checkAdminAuth, async (req, res) => {
    try {
      const { date } = req.body;
      const db = await dbPromise;
      const targetDate = date || new Date().toISOString().split('T')[0];
      
      // Obține toate bonurile fiscale din ziua specificată
      const receipts = await new Promise((resolve, reject) => {
        db.all(`
          SELECT 
            fr.*,
            o.type as order_type,
            o.table_number,
            o.client_identifier
          FROM fiscal_receipts fr
          LEFT JOIN orders o ON fr.order_id = o.id
          WHERE DATE(fr.issue_date) = ?
          ORDER BY fr.issue_date ASC
        `, [targetDate], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Calculează totaluri
      const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
      const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
      const totalVAT = receipts.reduce((sum, r) => sum + (r.vat_amount || 0), 0);
      const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
      
      // Citește defalcarea TVA direct din bonurile fiscale (NU recalculează!)
      const receiptIds = receipts.map(r => r.id).filter(id => id);
      const vatBreakdown = await getVATBreakdownFromReceipts(db, receiptIds);
      
      // Obține ultimul număr X și incrementează
      const lastX = await new Promise((resolve, reject) => {
        db.get(`
          SELECT MAX(x_number) as last_x FROM x_reports
        `, (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      const nextXNumber = (lastX && lastX.last_x) ? lastX.last_x + 1 : 1;
      
      // Salvează raportul X în baza de date
      const reportId = await new Promise((resolve, reject) => {
        db.run(`
          INSERT INTO x_reports (
            x_number,
            report_date,
            total_receipts,
            total_revenue,
            total_cash,
            total_card,
            total_vat,
            created_at
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        `, [
          nextXNumber,
          targetDate,
          receipts.length,
          totalAmount,
          totalCash,
          totalCard,
          totalVAT,
          new Date().toISOString()
        ], function(err) {
          if (err) reject(err);
          else resolve(this.lastID);
        });
      });
      
      const reportData = {
        success: true,
        reportType: 'X',
        reportId: reportId,
        xNumber: nextXNumber,
        reportDate: targetDate,
        timestamp: new Date().toISOString(),
        summary: {
          totalReceipts: receipts.length,
          totalAmount: parseFloat(totalAmount.toFixed(2)),
          totalCash: parseFloat(totalCash.toFixed(2)),
          totalCard: parseFloat(totalCard.toFixed(2)),
          totalVAT: parseFloat(totalVAT.toFixed(2)),
          netAmount: parseFloat((totalAmount - totalVAT).toFixed(2)),
          vatBreakdown: vatBreakdown
        },
        receipts: receipts.map(r => ({
          receiptNumber: r.receipt_number,
          amount: r.total_amount,
          vat: r.vat_amount || 0,
          paymentMethod: r.payment_method,
          time: r.issue_date,
          orderType: r.order_type
        })),
        note: 'Raport X - Intermediar (salvat permanent)'
      };
      
      console.log(`✅ Raport X #${nextXNumber} generat pentru ${targetDate}`);
      res.json(reportData);
      
    } catch (error) {
      console.error('❌ Eroare generare Raport X:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la generarea raportului X',
        message: error.message 
      });
    }
  });

  // POST /api/fiscal/report-z - Generează și salvează Raport Z pentru închidere zilnică
  app.post('/api/fiscal/report-z', checkAdminAuth, async (req, res) => {
    try {
      const { date } = req.body;
      const db = await dbPromise;
      const targetDate = date || new Date().toISOString().split('T')[0];
      
      // Verifică dacă există deja raport Z pentru această dată (în ambele tabele)
      const existingZ = await new Promise((resolve, reject) => {
        db.get(`
          SELECT * FROM z_reports WHERE DATE(report_date) = ?
        `, [targetDate], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      // Verifică și în tabela daily_z_reports (pentru compatibilitate cu noul sistem)
      const existingDailyZ = await new Promise((resolve, reject) => {
        db.get(`
          SELECT * FROM daily_z_reports WHERE DATE(report_date) = ?
        `, [targetDate], (err, row) => {
          if (err && !err.message.includes('no such table')) reject(err);
          else resolve(row);
        });
      });
      
      if (existingZ || existingDailyZ) {
        return res.status(400).json({
          success: false,
          error: 'Raportul Z pentru această dată a fost deja generat',
          existingReport: existingZ || existingDailyZ,
          message: 'Un raport Z pentru această dată există deja în sistem. Nu se pot genera duplicate.'
        });
      }
      
      // Obține toate bonurile fiscale din ziua specificată
      const receipts = await new Promise((resolve, reject) => {
        db.all(`
          SELECT 
            fr.*,
            o.type as order_type,
            o.table_number,
            o.client_identifier
          FROM fiscal_receipts fr
          LEFT JOIN orders o ON fr.order_id = o.id
          WHERE DATE(fr.issue_date) = ?
          ORDER BY fr.issue_date ASC
        `, [targetDate], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Calculează totaluri
      const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
      const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
      const totalVAT = receipts.reduce((sum, r) => sum + (r.vat_amount || 0), 0);
      const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
      
      // Citește defalcarea TVA direct din bonurile fiscale (NU recalculează!)
      const receiptIds = receipts.map(r => r.id).filter(id => id);
      const vatBreakdown = await getVATBreakdownFromReceipts(db, receiptIds);
      
      // Obține ultimul număr Z și incrementează
      const lastZ = await new Promise((resolve, reject) => {
        db.get(`
          SELECT MAX(z_number) as last_z FROM z_reports
        `, (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      const nextZNumber = (lastZ && lastZ.last_z) ? lastZ.last_z + 1 : 1;
      
      // Salvează raportul Z în baza de date
      const reportId = await new Promise((resolve, reject) => {
        db.run(`
          INSERT INTO z_reports (
            z_number,
            report_date,
            total_receipts,
            total_revenue,
            total_cash,
            total_card,
            total_vat,
            created_at
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        `, [
          nextZNumber,
          targetDate,
          receipts.length,
          totalAmount,
          totalCash,
          totalCard,
          totalVAT,
          new Date().toISOString()
        ], function(err) {
          if (err) reject(err);
          else resolve(this.lastID);
        });
      });
      
      const reportData = {
        success: true,
        reportType: 'Z',
        reportId: reportId,
        zNumber: nextZNumber,
        reportDate: targetDate,
        timestamp: new Date().toISOString(),
        summary: {
          totalReceipts: receipts.length,
          totalAmount: parseFloat(totalAmount.toFixed(2)),
          totalCash: parseFloat(totalCash.toFixed(2)),
          totalCard: parseFloat(totalCard.toFixed(2)),
          totalVAT: parseFloat(totalVAT.toFixed(2)),
          netAmount: parseFloat((totalAmount - totalVAT).toFixed(2)),
          vatBreakdown: vatBreakdown
        },
        receipts: receipts.map(r => ({
          receiptNumber: r.receipt_number,
          amount: r.total_amount,
          vat: r.vat_amount || 0,
          paymentMethod: r.payment_method,
          time: r.issue_date,
          orderType: r.order_type
        })),
        note: 'Raport Z - Închidere zilnică (salvat permanent)'
      };
      
      console.log(`✅ Raport Z #${nextZNumber} generat pentru ${targetDate}`);
      res.json(reportData);
      
    } catch (error) {
      console.error('❌ Eroare generare Raport Z:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la generarea raportului Z',
        message: error.message 
      });
    }
  });

  // POST /api/fiscal/monthly-report - Generează Raport Lunar
  app.post('/api/fiscal/monthly-report', checkAdminAuth, async (req, res) => {
    try {
      const { month } = req.body; // Format: YYYY-MM
      const db = await dbPromise;
      
      if (!month || !/^\d{4}-\d{2}$/.test(month)) {
        return res.status(400).json({
          success: false,
          error: 'Format invalid pentru lună. Utilizați formatul YYYY-MM (ex: 2025-10)'
        });
      }
      
      const [year, monthNum] = month.split('-');
      const startDate = `${year}-${monthNum}-01`;
      const endDate = new Date(parseInt(year), parseInt(monthNum), 0).toISOString().split('T')[0];
      
      // Obține toate bonurile fiscale din luna specificată
      const receipts = await new Promise((resolve, reject) => {
        db.all(`
          SELECT 
            fr.*,
            o.type as order_type,
            o.table_number,
            o.client_identifier
          FROM fiscal_receipts fr
          LEFT JOIN orders o ON fr.order_id = o.id
          WHERE DATE(fr.issue_date) >= ? AND DATE(fr.issue_date) <= ?
          ORDER BY fr.issue_date ASC
        `, [startDate, endDate], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Obține rapoartele Z din luna respectivă
      const zReports = await new Promise((resolve, reject) => {
        db.all(`
          SELECT * FROM z_reports
          WHERE DATE(report_date) >= ? AND DATE(report_date) <= ?
          ORDER BY report_date ASC
        `, [startDate, endDate], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Calculează totaluri
      const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
      const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
      const totalVAT = receipts.reduce((sum, r) => sum + (r.vat_amount || 0), 0);
      const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
      
      // Citește defalcarea TVA direct din bonurile fiscale pentru toată luna (NU recalculează!)
      const receiptIds = receipts.map(r => r.id).filter(id => id);
      const vatBreakdown = await getVATBreakdownFromReceipts(db, receiptIds);
      
      // Grupare pe zile
      const dailyBreakdown = {};
      receipts.forEach(r => {
        const day = r.issue_date.split('T')[0];
        if (!dailyBreakdown[day]) {
          dailyBreakdown[day] = {
            date: day,
            receipts: 0,
            amount: 0,
            vat: 0,
            cash: 0,
            card: 0
          };
        }
        dailyBreakdown[day].receipts++;
        dailyBreakdown[day].amount += r.total_amount;
        dailyBreakdown[day].vat += r.vat_amount || 0;
        if (r.payment_method === 'cash') dailyBreakdown[day].cash += r.total_amount;
        if (r.payment_method === 'card') dailyBreakdown[day].card += r.total_amount;
      });
      
      // Verifică dacă există deja raport lunar pentru această lună
      const existingMonthly = await new Promise((resolve, reject) => {
        db.get(`
          SELECT * FROM monthly_reports WHERE report_month = ?
        `, [month], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      if (existingMonthly) {
        return res.status(400).json({
          success: false,
          error: 'Raportul lunar pentru această lună a fost deja generat',
          existingReport: existingMonthly
        });
      }
      
      // Salvează raportul lunar în baza de date
      const reportId = await new Promise((resolve, reject) => {
        db.run(`
          INSERT INTO monthly_reports (
            report_month,
            total_receipts,
            total_revenue,
            total_cash,
            total_card,
            total_vat,
            created_at
          ) VALUES (?, ?, ?, ?, ?, ?, ?)
        `, [
          month,
          receipts.length,
          totalAmount,
          totalCash,
          totalCard,
          totalVAT,
          new Date().toISOString()
        ], function(err) {
          if (err) reject(err);
          else resolve(this.lastID);
        });
      });
      
      const reportData = {
        success: true,
        reportType: 'MONTHLY',
        reportId: reportId,
        month: month,
        period: {
          start: startDate,
          end: endDate
        },
        timestamp: new Date().toISOString(),
        summary: {
          totalReceipts: receipts.length,
          totalAmount: parseFloat(totalAmount.toFixed(2)),
          totalCash: parseFloat(totalCash.toFixed(2)),
          totalCard: parseFloat(totalCard.toFixed(2)),
          totalVAT: parseFloat(totalVAT.toFixed(2)),
          netAmount: parseFloat((totalAmount - totalVAT).toFixed(2)),
          totalZReports: zReports.length,
          daysActive: Object.keys(dailyBreakdown).length,
          vatBreakdown: vatBreakdown
        },
        dailyBreakdown: Object.values(dailyBreakdown).map(d => ({
          date: d.date,
          receipts: d.receipts,
          amount: parseFloat(d.amount.toFixed(2)),
          vat: parseFloat(d.vat.toFixed(2)),
          cash: parseFloat(d.cash.toFixed(2)),
          card: parseFloat(d.card.toFixed(2))
        })),
        zReports: zReports.map(z => ({
          zNumber: z.z_number,
          date: z.report_date,
          receipts: z.total_receipts,
          revenue: z.total_revenue
        })),
        note: 'Raport Lunar - Sinteză lunară (salvat permanent)'
      };
      
      console.log(`✅ Raport lunar generat pentru ${month}`);
      res.json(reportData);
      
    } catch (error) {
      console.error('❌ Eroare generare Raport Lunar:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la generarea raportului lunar',
        message: error.message 
      });
    }
  });

  // GET /api/fiscal/receipt-details/:receiptNumber - Detalii bon nefiscal
  app.get('/api/fiscal/receipt-details/:receiptNumber', checkAdminAuth, async (req, res) => {
    try {
      const { receiptNumber } = req.params;
      const db = await dbPromise;
      
      // Obține detaliile bonului nefiscal
      const receipt = await new Promise((resolve, reject) => {
        db.get(`
          SELECT 
            fr.*,
            o.table_number,
            o.client_identifier,
            o.items as order_items,
            o.paid_timestamp
          FROM fiscal_receipts fr
          LEFT JOIN orders o ON fr.order_id = o.id
          WHERE fr.receipt_number = ?
        `, [receiptNumber], (err, row) => {
          if (err) {
            console.error('❌ Eroare la query bon nefiscal:', err);
            reject(err);
          } else {
            resolve(row);
          }
        });
      });
      
      if (!receipt) {
        return res.status(404).json({ error: 'Bonul fiscal nu a fost găsit' });
      }
      
      // Pentru bonuri fiscale grupate, obține toate produsele din grupul de comenzi
      let allItems = [];
      
      if (receipt.paid_timestamp) {
        // Bon nefiscal grupat - obține toate comenzile din aceeași sesiune de plată
        const groupOrders = await new Promise((resolve, reject) => {
          db.all(`
            SELECT id, items, total, table_number, client_identifier, timestamp
            FROM orders 
            WHERE table_number = ? AND client_identifier = ? AND paid_timestamp = ? AND is_paid = 1
            ORDER BY timestamp ASC
          `, [receipt.table_number, receipt.client_identifier, receipt.paid_timestamp], (err, rows) => {
            if (err) {
              console.error('❌ Eroare la query grup comenzi:', err);
              reject(err);
            } else {
              resolve(rows || []);
            }
          });
        });
        
        // Adaugă toate produsele din toate comenzile din grup
        groupOrders.forEach(order => {
          if (order.items) {
            try {
              const orderItems = safeParseItems(order.items) || [];
              allItems = allItems.concat(orderItems);
            } catch (e) {
              console.warn(`⚠️ Eroare la parsarea items pentru comanda ${order.id}:`, e.message);
            }
          }
        });
        
        console.log(`📋 Bon nefiscal grupat ${receiptNumber}: ${groupOrders.length} comenzi, ${allItems.length} produse total`);
      } else {
        // Bon nefiscal individual - folosește items-urile din comanda specifică
        if (receipt.order_items) {
          try {
            allItems = safeParseItems(receipt.order_items) || [];
          } catch (e) {
            console.warn(`⚠️ Eroare la parsarea items pentru bonul ${receiptNumber}:`, e.message);
            allItems = [];
          }
        }
        
        console.log(`📋 Bon nefiscal individual ${receiptNumber}: ${allItems.length} produse`);
      }
      
      // Adaugă items-urile la răspuns
      receipt.items = allItems;
      
      console.log(`📋 Detalii bon nefiscal ${receiptNumber} returnate cu ${allItems.length} produse`);
      res.json(receipt);
      
    } catch (error) {
      console.error('❌ Eroare la obținerea detaliilor bonului nefiscal:', error);
      res.status(500).json({ error: 'Eroare la obținerea detaliilor bonului nefiscal' });
    }
  });

