  // GET /api/fiscal/register - Registrul de Casă (vizualizare tranzacții și solduri)
  app.get('/api/fiscal/register', checkAdminAuth, async (req, res) => {
      try {
          const db = await dbPromise;
          
          // Obține soldul inițial (ultimul final_balance sau 0)
          const lastBalance = await new Promise((resolve, reject) => {
              db.get('SELECT amount FROM cash_register WHERE type = ? ORDER BY transaction_date DESC LIMIT 1', ['final_balance'], (err, row) => {
                  if (err) {
                      console.error('❌ Eroare la query sold inițial:', err);
                      reject(err);
                  } else {
                      resolve(row);
                  }
              });
          });
          const initialBalance = lastBalance ? lastBalance.amount : 0;
          
          // Calculează totalul intrărilor și ieșirilor de astăzi
          const today = new Date().toISOString().slice(0, 10);
          const todayStats = await new Promise((resolve, reject) => {
              db.all(`
                  SELECT 
                      type,
                      SUM(CASE WHEN amount > 0 THEN amount ELSE 0 END) as total_in,
                      SUM(CASE WHEN amount < 0 THEN ABS(amount) ELSE 0 END) as total_out
                  FROM cash_register 
                  WHERE DATE(transaction_date) = ?
                  GROUP BY type
              `, [today], (err, rows) => {
                  if (err) {
                      console.error('❌ Eroare la query statistici zilnice:', err);
                      reject(err);
                  } else {
                      resolve(rows || []);
                  }
              });
          });
          
          const totalIn = todayStats.reduce((sum, stat) => sum + (stat.total_in || 0), 0);
          const totalOut = todayStats.reduce((sum, stat) => sum + (stat.total_out || 0), 0);
          const currentBalance = initialBalance + totalIn - totalOut;
          
          // Obține ultimele tranzacții
          const transactions = await new Promise((resolve, reject) => {
              db.all(`
                  SELECT 
                      transaction_date,
                      type,
                      document_type,
                      amount,
                      description
                  FROM cash_register 
                  ORDER BY transaction_date DESC 
                  LIMIT 50
              `, (err, rows) => {
                  if (err) {
                      console.error('❌ Eroare la query tranzacții:', err);
                      reject(err);
                  } else {
                      resolve(rows || []);
                  }
              });
          });
          
          res.json({
              current_balance: currentBalance,
              today_total_in: totalIn,
              today_total_out: totalOut,
              transactions: transactions
          });
          
      } catch (error) {
          console.error('❌ Eroare la obținerea registrului de casă:', error);
          res.status(500).json({ error: 'Eroare la obținerea registrului de casă' });
      }
  });

