  // Obține stocurile pentru toate ingredientele
  app.get('/api/stock/products', (req, res) => {
    const query = `
      SELECT 
        i.*,
        CASE 
          WHEN i.current_stock <= i.min_stock THEN 'low'
          WHEN i.current_stock = 0 THEN 'out'
          ELSE 'ok'
        END as stock_status,
        i.min_stock,
        i.current_stock
      FROM ingredients i
      ORDER BY i.name
    `;
    
    db.all(query, (err, rows) => {
      if (err) return res.status(500).json({ error: err.message });
      res.json({ products: rows });
    });
  });

