  // Scădere automată stoc la comandă
  app.post('/api/stock/auto-deduct', (req, res) => {
    const { order_id, items } = req.body;
    
    if (!order_id || !items || !Array.isArray(items)) {
      return res.status(400).json({ error: 'order_id și items sunt obligatorii' });
    }
    
    let completed = 0;
    let hasError = false;
    const results = [];
    
    items.forEach(item => {
      const productId = item.id;
      const quantity = item.quantity || 1;
      
      // Obține stocul curent
      db.get('SELECT current_stock FROM product_stock WHERE product_id = ?', [productId], (err, row) => {
        if (err) {
          console.error(`Eroare la obținerea stocului pentru produsul ${productId}:`, err.message);
          hasError = true;
          return;
        }
        
        if (!row) {
          console.error(`Produsul ${productId} nu are stoc configurat`);
          hasError = true;
          return;
        }
        
        const oldStock = row.current_stock;
        const newStock = Math.max(0, oldStock - quantity);
        
        // Actualizează stocul
        db.run(
          'UPDATE product_stock SET current_stock = ?, last_updated = CURRENT_TIMESTAMP WHERE product_id = ?',
          [newStock, productId],
          function(err) {
            if (err) {
              console.error(`Eroare la actualizarea stocului pentru produsul ${productId}:`, err.message);
              hasError = true;
            } else {
              // Adaugă în istoric
              db.run(
                'INSERT INTO stock_history (product_id, action, quantity_change, old_stock, new_stock, reason) VALUES (?, ?, ?, ?, ?, ?)',
                [productId, 'order', -quantity, oldStock, newStock, `Order ${order_id}`],
                (err) => {
                  if (err) console.error('Eroare la adăugarea în istoric:', err.message);
                }
              );
              
              results.push({
                product_id: productId,
                old_stock: oldStock,
                new_stock: newStock,
                quantity_deducted: quantity
              });
            }
            
            completed++;
            if (completed === items.length) {
              if (hasError) {
                res.status(500).json({ error: 'Erori la actualizarea stocurilor', results });
              } else {
                // Verifică stocul scăzut după actualizare
                checkLowStockAndNotify();
                res.json({ message: 'Stocuri actualizate cu succes', results });
              }
            }
          }
        );
      });
    });
  });

