  // POST /api/admin/generate-product/preview - Preview generare fișă de produs
  app.post('/api/admin/generate-product/preview', checkAdminAuth, async (req, res) => {
    try {
      const { productName } = req.body;
      
      if (!productName || productName.trim() === '') {
        return res.status(400).json({ error: 'Denumirea produsului este obligatorie' });
      }

      // Importă funcțiile din scriptul de generare
      const { identifyProductCategory, calculateWaste, getPackaging, getIngredients, calculatePrice } = require('./generate-product-sheet');
      
      // Identifică categoria
      const category = identifyProductCategory(productName);
      
      // Identifică ingredientele
      const ingredients = getIngredients(productName);
      
      // Calculează waste-ul
      const wastePercentage = calculateWaste(productName);
      
      // Identifică ambalajele
      const packagingRestaurant = getPackaging(productName, false);
      const packagingDelivery = getPackaging(productName, true);
      
      // Calculează prețul
      const price = calculatePrice(ingredients, wastePercentage);
      
      res.json({
        success: true,
        productName,
        category,
        ingredients,
        wastePercentage,
        packagingRestaurant,
        packagingDelivery,
        price
      });
      
    } catch (error) {
      console.error('Eroare la preview generare produs:', error);
      res.status(500).json({ error: 'Eroare la preview generare produs: ' + error.message });
    }
  });

  // POST /api/admin/generate-product - Generează fișă de produs completă
  app.post('/api/admin/generate-product', checkAdminAuth, async (req, res) => {
    try {
      const { productName } = req.body;
      
      if (!productName || productName.trim() === '') {
        return res.status(400).json({ error: 'Denumirea produsului este obligatorie' });
      }

      // Importă funcția principală din scriptul de generare
      const { generateProductSheet } = require('./generate-product-sheet');
      
      // Generează fișa de produs
      const result = await generateProductSheet(productName);
      
      res.json({
        success: true,
        message: `Produs "${productName}" generat cu succes!`,
        productId: result.productId,
        productName: result.productName,
        category: result.category,
        price: result.price,
        ingredients: result.ingredients,
        wastePercentage: result.wastePercentage
      });
      
    } catch (error) {
      console.error('Eroare la generare produs:', error);
      res.status(500).json({ error: 'Eroare la generare produs: ' + error.message });
    }
  });

