  // ==================== ARHIVARE AUTOMATĂ COMENZI ====================
  
  // Funcție pentru arhivarea automată a comenzilor vechi (1 an)
  async function archiveOldOrders() {
    try {
      const db = await dbPromise;
      const archiveDate = new Date();
      archiveDate.setFullYear(archiveDate.getFullYear() - 1); // 1 an în urmă
      
      console.log(`🗂️ Începe arhivarea comenzilor mai vechi de ${archiveDate.toISOString().split('T')[0]}...`);
      
      // Verifică mai întâi câte comenzi sunt de arhivat
      const countResult = await new Promise((resolve, reject) => {
        db.get('SELECT COUNT(*) as count FROM orders WHERE timestamp < ?', [archiveDate.toISOString()], (err, row) => {
          if (err) reject(err);
          else resolve(row);
        });
      });
      
      console.log(`📊 Găsite ${countResult.count} comenzi de arhivat`);
      
      if (countResult.count === 0) {
        console.log('✅ Nu există comenzi de arhivat');
        return;
      }
      
      // Mută comenzile vechi în tabelul de arhivă
      const archiveResult = await new Promise((resolve, reject) => {
        db.run(`
          INSERT INTO orders_archive (id, type, isTogether, items, status, timestamp, completed_timestamp, delivered_timestamp, table_number, client_identifier, is_paid, archived_at)
          SELECT id, type, isTogether, items, status, timestamp, completed_timestamp, delivered_timestamp, table_number, client_identifier, is_paid, CURRENT_TIMESTAMP
          FROM orders 
          WHERE timestamp < ?
        `, [archiveDate.toISOString()], function(err) {
          if (err) reject(err);
          else resolve({ changes: this.changes });
        });
      });
      
      console.log(`✅ Arhivate ${archiveResult.changes} comenzi`);
      
      if (archiveResult.changes > 0) {
        // Șterge comenzile arhivate din tabelul principal
        const deleteResult = await new Promise((resolve, reject) => {
          db.run(`
            DELETE FROM orders 
            WHERE timestamp < ?
          `, [archiveDate.toISOString()], function(err) {
            if (err) reject(err);
            else resolve({ changes: this.changes });
          });
        });
        
        console.log(`🗑️ Șterse ${deleteResult.changes} comenzi din tabelul principal`);
        console.log(`📊 Arhivare completă: ${archiveResult.changes} comenzi arhivate`);
      }
    } catch (error) {
      console.error('❌ Eroare la arhivarea automată:', error);
    }
  }

  // Funcție pentru exportul comenzilor arhivate în CSV
  async function exportArchivedOrders(startDate, endDate) {
    try {
      const db = await dbPromise;
      const query = `
        SELECT 
          id,
          type,
          table_number,
          client_identifier,
          status,
          timestamp,
          completed_timestamp,
          delivered_timestamp,
          is_paid,
          archived_at
        FROM orders_archive 
        WHERE archived_at BETWEEN ? AND ?
        ORDER BY archived_at DESC
      `;
      
      const rows = await new Promise((resolve, reject) => {
        db.all(query, [startDate, endDate], (err, rows) => {
          if (err) reject(err);
          else resolve(rows);
        });
      });
      
      // Generează CSV
      let csv = 'ID,Tip,Masa,Client,Status,Data Comanda,Data Finalizare,Data Livrare,Platit,Data Arhivare\n';
      
      rows.forEach(row => {
        csv += `"${row.id}","${row.type || ''}","${row.table_number || ''}","${row.client_identifier || ''}","${row.status || ''}","${row.timestamp || ''}","${row.completed_timestamp || ''}","${row.delivered_timestamp || ''}","${row.is_paid ? 'Da' : 'Nu'}","${row.archived_at || ''}"\n`;
      });
      
      return {
        csv: csv,
        count: rows.length,
        filename: `comenzi_arhivate_${startDate.split('T')[0]}_${endDate.split('T')[0]}.csv`
      };
    } catch (error) {
      throw error;
    }
  }

  // Funcție pentru ștergerea completă a comenzilor arhivate
  async function deleteArchivedOrders(startDate, endDate) {
    try {
      const db = await dbPromise;
      
      const result = await new Promise((resolve, reject) => {
        db.run(`
          DELETE FROM orders_archive 
          WHERE archived_at BETWEEN ? AND ?
        `, [startDate, endDate], function(err) {
          if (err) {
            reject(err);
            return;
          }
          
          resolve({
            deletedCount: this.changes,
            message: `Șterse ${this.changes} comenzi arhivate`
          });
        });
      });
      
      return result;
    } catch (error) {
      throw error;
    }
  }

