  // ==================== ENDPOINT-URI PENTRU GESTIONAREA COMENZILOR ====================
  
  // GET /api/admin/orders/all - Obține toate comenzile cu filtrare
  app.get('/api/admin/orders/all', checkAdminAuth, async (req, res) => {
    try {
      const db = await dbPromise;
      const { 
        date, 
        status, 
        table_number, 
        order_id, 
        page = 1, 
        limit = 1000 
      } = req.query;
      
      let query = `
        SELECT 
          o.id,
          o.timestamp,
          o.table_number,
          o.client_identifier,
          o.status,
          o.total,
          o.is_paid,
          o.payment_method,
          o.items,
          o.paid_timestamp,
          CASE 
            WHEN fr.id IS NOT NULL THEN 1 
            WHEN o.is_paid = 1 AND o.paid_timestamp IS NOT NULL THEN 
              (SELECT COUNT(*) FROM fiscal_receipts fr2 
               JOIN orders o2 ON fr2.order_id = o2.id 
               WHERE o2.table_number = o.table_number 
               AND o2.client_identifier = o.client_identifier 
               AND o2.paid_timestamp = o.paid_timestamp 
               AND o2.is_paid = 1) > 0
            ELSE 0 
          END as has_fiscal_receipt
        FROM orders o
        LEFT JOIN fiscal_receipts fr ON o.id = fr.order_id
        WHERE 1=1
      `;
      const params = [];
      
      // Filtrare după dată
      if (date) {
        query += ` AND DATE(o.timestamp) = ?`;
        params.push(date);
      }
      
      // Filtrare după status
      if (status) {
        query += ` AND o.status = ?`;
        params.push(status);
      }
      
      // Filtrare după masă
      if (table_number) {
        query += ` AND o.table_number = ?`;
        params.push(table_number);
      }
      
      // Filtrare după ID comandă
      if (order_id) {
        query += ` AND o.id LIKE ?`;
        params.push(`%${order_id}%`);
      }
      
      query += ` ORDER BY o.timestamp DESC LIMIT ? OFFSET ?`;
      params.push(parseInt(limit), (parseInt(page) - 1) * parseInt(limit));
      
      const orders = await new Promise((resolve, reject) => {
        db.all(query, params, (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Obține numărul total de comenzi pentru paginare
      let countQuery = `SELECT COUNT(*) as total FROM orders o WHERE 1=1`;
      const countParams = [];
      
      if (date) {
        countQuery += ` AND DATE(o.timestamp) = ?`;
        countParams.push(date);
      }
      if (status) {
        countQuery += ` AND o.status = ?`;
        countParams.push(status);
      }
      if (table_number) {
        countQuery += ` AND o.table_number = ?`;
        countParams.push(table_number);
      }
      if (order_id) {
        countQuery += ` AND o.id LIKE ?`;
        countParams.push(`%${order_id}%`);
      }
      
      const totalCount = await new Promise((resolve, reject) => {
        db.get(countQuery, countParams, (err, row) => {
          if (err) reject(err);
          else resolve(row.total);
        });
      });
      
      // Calculează totalul din items pentru comenzile care au total null
      const processedOrders = orders.map(order => {
        if (order.total === null || order.total === 0) {
          try {
            const items = safeParseItems(order.items) || [];
            const calculatedTotal = items.reduce((sum, item) => sum + (item.finalPrice || 0), 0);
            return { ...order, total: calculatedTotal };
          } catch (e) {
            console.warn(`⚠️ Eroare la calcularea totalului pentru comanda ${order.id}:`, e.message);
            return order;
          }
        }
        return order;
      });
      
      res.json({
        orders: processedOrders,
        total: totalCount,
        page: parseInt(page),
        limit: parseInt(limit),
        totalPages: Math.ceil(totalCount / parseInt(limit))
      });
      
    } catch (error) {
      console.error('❌ Eroare la obținerea comenzilor:', error);
      res.status(500).json({ error: 'Eroare la obținerea comenzilor' });
    }
  });
  
  // GET /api/admin/orders/export - Export CSV al comenzilor
  app.get('/api/admin/orders/export', checkAdminAuth, async (req, res) => {
    try {
      const db = await dbPromise;
      const { startDate, endDate } = req.query;
      
      let query = `
        SELECT 
          id,
          timestamp,
          table_number,
          client_identifier,
          status,
          total,
          is_paid,
          payment_method,
          items
        FROM orders 
        WHERE 1=1
      `;
      const params = [];
      
      if (startDate) {
        query += ` AND DATE(timestamp) >= ?`;
        params.push(startDate);
      }
      
      if (endDate) {
        query += ` AND DATE(timestamp) <= ?`;
        params.push(endDate);
      }
      
      query += ` ORDER BY timestamp DESC`;
      
      const orders = await new Promise((resolve, reject) => {
        db.all(query, params, (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Generează CSV
      let csv = 'ID,Dată,Masa,Client,Status,Total,Achitată,Metodă Plată,Produse\n';
      
      orders.forEach(order => {
        const date = new Date(order.timestamp).toLocaleString();
        const table = order.table_number || 'Takeout';
        const client = order.client_identifier || '';
        const status = order.status || '';
        const total = order.total || 0;
        const isPaid = order.is_paid ? 'Da' : 'Nu';
        const paymentMethod = order.payment_method || '';
        
        let items = '';
        if (order.items) {
          try {
            const itemsArray = safeParseItems(order.items);
            items = itemsArray.map(item => `${item.name} (${item.quantity}x)`).join('; ');
          } catch (e) {
            items = 'Eroare la parsarea produselor';
          }
        }
        
        csv += `"${order.id}","${date}","${table}","${client}","${status}","${total}","${isPaid}","${paymentMethod}","${items}"\n`;
      });
      
      res.setHeader('Content-Type', 'text/csv');
      res.setHeader('Content-Disposition', `attachment; filename="comenzi_${new Date().toISOString().split('T')[0]}.csv"`);
      res.send(csv);
      
    } catch (error) {
      console.error('❌ Eroare la exportul comenzilor:', error);
      res.status(500).json({ error: 'Eroare la exportul comenzilor' });
    }
  });

  // ==================== API PENTRU ISTORIC ZILNIC ====================
  
  // ==================== ENDPOINT ACTUALIZAT PENTRU ISTORIC ZILNIC BUCĂTĂRIE ====================

  // Înlocuiește endpoint-ul existent `/api/daily-history/:station` cu această versiune îmbunătățită
  app.get('/api/daily-history/:station', async (req, res) => {
    const station = req.params.station; // 'bar' sau 'kitchen'
    const { lang = 'ro' } = req.query;
    
    if (!['bar', 'kitchen'].includes(station)) {
      return res.status(400).json({ error: 'Station must be bar or kitchen' });
    }
    
    try {
      const db = await dbPromise;
      
      // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
      const now = new Date();
      const currentHour = now.getHours();
      
      let referenceDate;
      if (currentHour >= 8) {
        // Dacă suntem după 08:00, folosim ziua curentă
        referenceDate = new Date(now);
        referenceDate.setHours(0, 0, 0, 0);
      } else {
        // Dacă suntem înainte de 08:00, folosim ziua precedentă
        referenceDate = new Date(now);
        referenceDate.setDate(referenceDate.getDate() - 1);
        referenceDate.setHours(0, 0, 0, 0);
      }
      
      const startTime = new Date(referenceDate);
      startTime.setHours(8, 0, 0, 0); // 08:00:00
      
      const endTime = new Date(referenceDate);
      endTime.setDate(endTime.getDate() + 1);
      endTime.setHours(3, 0, 0, 0); // 03:00:00 ziua următoare
      
      
      // Obține TOATE comenzile din intervalul orar (nu doar cele finalizate)
      const allOrdersQuery = `
        SELECT 
          o.id as order_id,
          o.table_number,
          o.client_identifier,
          o.type,
          o.timestamp as order_time,
          o.completed_timestamp,
          o.delivered_timestamp,
          o.status,
          o.is_paid,
          o.items,
          o.food_notes,
          o.drink_notes,
          o.general_notes,
          o.cancelled_timestamp,
          o.cancelled_reason
        FROM orders o
        WHERE o.timestamp >= ? 
          AND o.timestamp <= ?
        ORDER BY o.timestamp DESC
      `;
      
      const allOrders = await new Promise((resolve, reject) => {
        db.all(allOrdersQuery, [startTime.toISOString(), endTime.toISOString()], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Procesează TOATE comenzile din intervalul orar
      const orders = [];
      let totalItems = 0;
      
      // Procesează toate comenzile (active și finalizate)
      allOrders.forEach(row => {
        let items = [];
        try {
          items = safeParseItems(row.items) || [];
        } catch (e) {
          console.error('Eroare la parsarea items pentru comanda', row.order_id, e);
          return;
        }
        
        // Filtrează produsele pentru stația specificată
        let stationItems;
        if (station === 'kitchen') {
          // Pentru bucătărie, include doar produsele pentru bucătărie
          stationItems = items.filter(item => 
            item.station === 'kitchen'
          );
        } else {
          // Pentru bar, include doar produsele pentru bar
          stationItems = items.filter(item => item.station === station);
        }
        
        if (stationItems.length > 0) {
          const orderData = {
            order_id: row.order_id,
            table_number: row.table_number,
            client_identifier: row.client_identifier,
            type: row.type,
            order_time: row.order_time,
            completed_timestamp: row.completed_timestamp,
            delivered_timestamp: row.delivered_timestamp,
            cancelled_timestamp: row.cancelled_timestamp,
            cancelled_reason: row.cancelled_reason,
            status: row.status,
            is_paid: row.is_paid,
            items: stationItems.map(item => ({
              name: item.name,
              quantity: item.quantity,
              customizations: item.customizations || [],
              final_price: item.finalPrice || 0,
              completed_at: item.completed_at || null,
              status: row.status === 'cancelled' ? 'cancelled' : (item.status || 'pending')
            }))
          };

          // Adaugă mentiunile specifice pentru fiecare stație
          if (station === 'kitchen') {
            orderData.food_notes = row.food_notes;
            orderData.general_notes = row.general_notes;
          } else if (station === 'bar') {
            orderData.drink_notes = row.drink_notes;
            orderData.general_notes = row.general_notes;
          }

          orders.push(orderData);
          totalItems += stationItems.length;
        }
      });
      
      // Sortează comenzile cu cea mai recentă prima
      orders.sort((a, b) => {
        const aTime = new Date(a.order_time || 0);
        const bTime = new Date(b.order_time || 0);
        return bTime - aTime; // Cea mai recentă prima
      });
      
      res.json({
        success: true,
        station: station,
        period: {
          start: startTime.toISOString(),
          end: endTime.toISOString(),
          current: now.toISOString(),
          display: currentHour >= 8 ? 
            (lang === 'ro' ? 'Azi 08:00 - Mâine 03:00' : 'Today 08:00 - Tomorrow 03:00') :
            (lang === 'ro' ? 'Ieri 08:00 - Azi 03:00' : 'Yesterday 08:00 - Today 03:00')
        },
        orders: orders,
        total_orders: orders.length,
        total_items: totalItems
      });
      
    } catch (error) {
      console.error('Eroare la procesarea istoricului zilnic:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la procesarea istoricului',
        details: error.message 
      });
    }
  });

  // Endpoint specific pentru bucătărie (pentru compatibilitate cu kds.html)
  // ==================== ENDPOINT ACTUALIZAT PENTRU ISTORIC ZILNIC BUCĂTĂRIE ====================
  app.get('/api/daily-history/kitchen', async (req, res) => {
    const { lang = 'ro' } = req.query;
    
    try {
      const db = await dbPromise;
      
      // Calculează intervalul zilnic: 08:00 - 03:00 (următoarea zi)
      const now = new Date();
      const currentHour = now.getHours();
      
      let referenceDate;
      if (currentHour >= 8) {
        // Dacă suntem după 08:00, folosim ziua curentă
        referenceDate = new Date(now);
        referenceDate.setHours(0, 0, 0, 0);
      } else {
        // Dacă suntem înainte de 08:00, folosim ziua precedentă
        referenceDate = new Date(now);
        referenceDate.setDate(referenceDate.getDate() - 1);
        referenceDate.setHours(0, 0, 0, 0);
      }
      
      const startTime = new Date(referenceDate);
      startTime.setHours(8, 0, 0, 0); // 08:00:00
      
      const endTime = new Date(referenceDate);
      endTime.setDate(endTime.getDate() + 1);
      endTime.setHours(3, 0, 0, 0); // 03:00:00 ziua următoare
      
      // Obține TOATE comenzile din intervalul relevant (pending, preparing, completed, delivered)
      const allOrdersQuery = `
          SELECT * FROM orders 
          WHERE timestamp >= ? AND timestamp <= ?
          ORDER BY timestamp ASC
      `;
      
      const allOrders = await new Promise((resolve, reject) => {
        db.all(allOrdersQuery, [startTime.toISOString(), endTime.toISOString()], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      });
      
      // Procesează și combină comenzile, filtrând pentru bucătărie
      const processedOrders = [];
      let totalKitchenItems = 0;
      
      allOrders.forEach(row => {
        let items = [];
        try {
          items = safeParseItems(row.items) || [];
        } catch (e) {
          console.error('Eroare la parsarea items pentru comanda', row.id, e);
          return; // Sare peste comanda dacă are format JSON invalid
        }
        
        // Filtrează produsele care aparțin bucătăriei
        const kitchenItems = items.filter(item => item.station === 'kitchen');
        
        if (kitchenItems.length > 0) {
          let orderStatus = row.status;
          
          // Dacă comanda e 'pending' sau 'preparing', o considerăm 'preparing' pentru afișare
          if (['pending', 'preparing'].includes(orderStatus)) {
            orderStatus = 'preparing';
          }

          processedOrders.push({
            order_id: row.id,
            table_number: row.table_number,
            client_identifier: row.client_identifier,
            type: row.type,
            order_time: row.timestamp,
            completed_timestamp: row.completed_timestamp,
            delivered_timestamp: row.delivered_timestamp,
            cancelled_timestamp: row.cancelled_timestamp,
            cancelled_reason: row.cancelled_reason,
            status: orderStatus,
            is_paid: row.is_paid,
            food_notes: row.food_notes,
            general_notes: row.general_notes,
            items: kitchenItems.map(item => ({
              name: item.name,
              quantity: item.quantity,
              customizations: item.customizations || [],
              final_price: item.finalPrice || 0,
              completed_at: item.status === 'completed' ? row.completed_timestamp : null,
              status: row.status === 'cancelled' ? 'cancelled' : (item.status || 'pending')
            }))
          });
          totalKitchenItems += kitchenItems.reduce((sum, item) => sum + item.quantity, 0);
        }
      });
      
      res.json({
        success: true,
        station: 'kitchen',
        period: {
          start: startTime.toISOString(),
          end: endTime.toISOString()
        },
        orders: processedOrders,
        total_orders: processedOrders.length,
        total_items: totalKitchenItems // Numărul total de produse de bucătărie
      });
      
    } catch (error) {
      console.error('Eroare la procesarea istoricului zilnic pentru bucătărie:', error);
      res.status(500).json({ 
        success: false, 
        error: 'Eroare la procesarea istoricului',
        details: error.message 
      });
    }
  });

  // Endpoint de debug pentru testare
  app.get('/api/debug/kitchen-orders', checkAdminAuth, (req, res) => {
    const { hours = 24 } = req.query;
    
    dbPromise.then(db => {
      const cutoffTime = new Date();
      cutoffTime.setHours(cutoffTime.getHours() - parseInt(hours));
      
      const query = `
        SELECT 
          o.id,
          o.status,
          o.timestamp,
          o.table_number,
          o.items,
          CASE 
            WHEN o.timestamp >= ? THEN 'recent'
            ELSE 'old'
          END as age_category
        FROM orders o
        ORDER BY o.timestamp DESC
        LIMIT 20
      `;
      
      db.all(query, [cutoffTime.toISOString()], (err, rows) => {
        if (err) {
          return res.status(500).json({ error: err.message });
        }
        
        const processedOrders = rows.map(row => {
          let items = [];
          try {
            items = safeParseItems(row.items) || [];
          } catch (e) {
            items = [];
          }
          
          const kitchenItems = items.filter(item => 
            item.station === 'kitchen'
          );
          
          return {
            ...row,
            kitchen_items_count: kitchenItems.length,
            total_items_count: items.length,
            has_kitchen_items: kitchenItems.length > 0
          };
        });
        
        res.json({
          debug_info: {
            cutoff_time: cutoffTime.toISOString(),
            current_time: new Date().toISOString(),
            hours_back: hours
          },
          orders: processedOrders,
          summary: {
            total_orders: processedOrders.length,
            orders_with_kitchen_items: processedOrders.filter(o => o.has_kitchen_items).length,
            recent_orders: processedOrders.filter(o => o.age_category === 'recent').length
          }
        });
      });
    }).catch(err => {
      res.status(500).json({ error: 'Database connection error: ' + err.message });
    });
  });

  // Pornește arhivarea automată
  scheduleAutoArchive();

