// Funcție pentru încărcarea ofertei zilei din baza de date
function loadDailyOffer() {
  return new Promise((resolve, reject) => {
    dbPromise.then(db => {
      // Găsește oferta activă
      db.get('SELECT * FROM daily_offers WHERE is_active = 1', (err, offer) => {
        if (err) {
          console.error('Eroare la obținerea ofertei:', err);
          return reject(err);
        }
        
        if (!offer) {
          return resolve(null);
        }
        
        // Preia condițiile ofertei
        db.all('SELECT * FROM daily_offer_conditions WHERE offer_id = ?', [offer.id], (err, conditions) => {
          if (err) {
            console.error('Eroare la obținerea condițiilor:', err);
            return reject(err);
          }
          
          // Preia beneficiile ofertei (dacă sunt produse specifice)
          if (offer.benefit_type === 'specific') {
            db.all(`
              SELECT m.* FROM daily_offer_benefit_products bop
              JOIN menu m ON bop.product_id = m.id
              WHERE bop.offer_id = ?
            `, [offer.id], (err, benefitProducts) => {
              if (err) {
                console.error('Eroare la obținerea beneficiilor:', err);
                return reject(err);
              }
              
              resolve({
                ...offer,
                conditions: conditions,
                benefit_products: benefitProducts
              });
            });
          } else {
            resolve({
              ...offer,
              conditions: conditions,
              benefit_products: []
            });
          }
        });
      });
    }).catch(reject);
  });
}

// API pentru obținerea ofertei zilnice (structură complexă îmbunătățită)
app.get('/api/daily-offer', (req, res) => {
  dbPromise.then(db => {
    db.get('SELECT * FROM daily_offers WHERE is_active = 1', (err, offer) => {
      if (err) return res.status(500).json({ error: 'Eroare la obținerea ofertei' });
      if (!offer) return res.status(404).json({ message: 'Nu există ofertă activă' });

      // Funcție asincronă pentru a procesa oferta
      async function processOffer() {
        try {
          // Preia toate produsele din meniu o singură dată
          const allProducts = await new Promise((resolve, reject) => {
            db.all('SELECT id, name, category, price FROM menu', (err, rows) => {
              if (err) reject(err);
              else resolve(rows);
            });
          });

          // Preia condițiile ofertei
          const conditions = await new Promise((resolve, reject) => {
            db.all('SELECT * FROM daily_offer_conditions WHERE offer_id = ?', [offer.id], (err, rows) => {
              if (err) reject(err);
              else resolve(rows);
            });
          });

          // Adaugă produsele eligibile la fiecare condiție
          const enrichedConditions = conditions.map(cond => ({
            ...cond,
            products: allProducts.filter(p => p.category === cond.category)
          }));

          let benefitProducts = [];
          if (offer.benefit_type === 'category') {
            benefitProducts = allProducts.filter(p => p.category === offer.benefit_category);
          } else if (offer.benefit_type === 'specific') {
            benefitProducts = await new Promise((resolve, reject) => {
              db.all(`
                SELECT m.id, m.name, m.price, m.category FROM daily_offer_benefit_products b
                JOIN menu m ON b.product_id = m.id
                WHERE b.offer_id = ?
              `, [offer.id], (err, rows) => {
                if (err) reject(err);
                else resolve(rows);
              });
            });
          }

          res.json({
            success: true,
            offer: {
              ...offer,
              conditions: enrichedConditions,
              benefit_products: benefitProducts
            }
          });

        } catch (error) {
          res.status(500).json({ error: 'Eroare la procesarea detaliilor ofertei' });
        }
      }

      processOffer();
    });
  }).catch(err => res.status(500).json({ error: 'Eroare la conectarea la baza de date' }));
});

// API pentru salvarea ofertei zilnice (structură complexă)
// API pentru salvarea ofertei zilnice
app.post('/api/daily-offer', checkAdminAuth, (req, res) => {
    const {
        title, description, title_en, description_en, is_active,
        conditions, benefit_type, benefit_category, benefit_quantity, benefit_products
    } = req.body;

    if (!title || !description || !conditions || !benefit_type) {
        return res.status(400).json({ error: 'Datele ofertei sunt incomplete.' });
    }

    dbPromise.then(db => {
        db.serialize(() => {
            db.run('BEGIN TRANSACTION');

            // 1. Șterge complet oferta veche. Datorită "ON DELETE CASCADE", 
            //    se vor șterge automat și condițiile și beneficiile asociate.
            db.run('DELETE FROM daily_offers', (err) => {
                if (err) {
                    db.run('ROLLBACK');
                    return res.status(500).json({ error: 'Eroare la curățarea ofertelor vechi: ' + err.message });
                }

                // Dacă oferta nouă este inactivă, nu mai facem nimic
                if (!is_active) {
                    db.run('COMMIT');
                    return res.json({ success: true, message: 'Oferta a fost salvată ca inactivă.' });
                }

                // 2. Inserează noua ofertă în tabelul principal
                const offerSql = `
                    INSERT INTO daily_offers (title, description, title_en, description_en, is_active, benefit_type, benefit_category, benefit_quantity)
                    VALUES (?, ?, ?, ?, 1, ?, ?, ?)
                `;
                db.run(offerSql, [
                    title, description, title_en, description_en,
                    benefit_type, benefit_category, benefit_quantity
                ], function(err) {
                    if (err) {
                        db.run('ROLLBACK');
                        return res.status(500).json({ error: 'Eroare la salvarea ofertei principale: ' + err.message });
                    }
                    
                    const offerId = this.lastID;

                    // 3. Inserează noile condiții
                    const conditionStmt = db.prepare('INSERT INTO daily_offer_conditions (offer_id, category, quantity) VALUES (?, ?, ?)');
                    conditions.forEach(cond => {
                        conditionStmt.run(offerId, cond.category, cond.quantity);
                    });
                    conditionStmt.finalize();

                    // 4. Inserează noile beneficii (dacă sunt produse specifice)
                    if (benefit_type === 'specific' && benefit_products && benefit_products.length > 0) {
                        const benefitStmt = db.prepare('INSERT INTO daily_offer_benefit_products (offer_id, product_id) VALUES (?, ?)');
                        benefit_products.forEach(productId => {
                            benefitStmt.run(offerId, productId);
                        });
                        benefitStmt.finalize();
                    }

                    // Finalizează tranzacția
                    db.run('COMMIT', (err) => {
                        if (err) {
                            return res.status(500).json({ error: 'Eroare la finalizarea tranzacției: ' + err.message });
                        }
                        res.json({ success: true, message: 'Oferta a fost salvată cu succes!', offer_id: offerId });
                    });
                });
            });
        });
    }).catch(err => {
        res.status(500).json({ error: 'Eroare la conectarea la baza de date: ' + err.message });
    });
});

// API pentru verificarea și aplicarea ofertei zilnice la coș (structură complexă)
app.post('/api/daily-offer/check', (req, res) => {
  const { cartItems } = req.body;
  
  dbPromise.then(db => {
    // Găsește oferta activă
    db.get('SELECT * FROM daily_offers WHERE is_active = 1', (err, offer) => {
      if (err) {
        console.error('Eroare la obținerea ofertei:', err);
        return res.status(500).json({ error: 'Eroare la obținerea ofertei' });
      }
      
      if (!offer) {
        return res.json({
          success: true,
          hasOffer: false,
          message: 'Nu există ofertă activă'
        });
      }
      
      // Preia condițiile ofertei
      db.all('SELECT * FROM daily_offer_conditions WHERE offer_id = ?', [offer.id], (err, conditions) => {
        if (err) {
          console.error('Eroare la obținerea condițiilor:', err);
          return res.status(500).json({ error: 'Eroare la obținerea condițiilor' });
        }
        
        // Verifică dacă coșul îndeplinește condițiile ofertei
        let conditionsMet = true;
        
        for (const condition of conditions) {
          const categoryItems = cartItems.filter(item => item.category === condition.category);
          const totalQuantity = categoryItems.reduce((sum, item) => sum + item.quantity, 0);
          
          if (totalQuantity < condition.quantity) {
            conditionsMet = false;
            break;
          }
        }
        
        if (conditionsMet) {
          // Preia beneficiile ofertei
          if (offer.benefit_type === 'specific') {
            db.all(`
              SELECT m.* FROM daily_offer_benefit_products bop
              JOIN menu m ON bop.product_id = m.id
              WHERE bop.offer_id = ?
            `, [offer.id], (err, benefitProducts) => {
              if (err) {
                console.error('Eroare la obținerea beneficiilor:', err);
                return res.status(500).json({ error: 'Eroare la obținerea beneficiilor' });
              }
              
              res.json({
                success: true,
                hasOffer: true,
                offer: {
                  ...offer,
                  conditions: conditions,
                  benefit_products: benefitProducts
                },
                message: 'Oferta zilnică se aplică!'
              });
            });
          } else {
            res.json({
              success: true,
              hasOffer: true,
              offer: {
                ...offer,
                conditions: conditions,
                benefit_products: []
              },
              message: 'Oferta zilnică se aplică!'
            });
          }
        } else {
          res.json({
            success: true,
            hasOffer: false,
            message: 'Coșul nu îndeplinește condițiile ofertei'
          });
        }
      });
    });
  }).catch(err => {
    console.error('Eroare la conectarea la baza de date:', err);
    res.status(500).json({ error: 'Eroare la conectarea la baza de date' });
  });
});

// Funcție pentru verificarea condițiilor ofertei
function checkOfferConditions(cartItems, conditions) {
  const categoryCounts = {};
  
  // Numără produsele pe categorii
  cartItems.forEach(item => {
    if (!categoryCounts[item.category]) {
      categoryCounts[item.category] = 0;
    }
    categoryCounts[item.category] += item.quantity;
  });
  
  // Verifică fiecare condiție
  return conditions.every(condition => {
    const count = categoryCounts[condition.category] || 0;
    return count >= condition.quantity;
  });
}

// Funcție pentru găsirea produselor eligibile
function findEligibleItems(cartItems, offer) {
  if (offer.benefit_type === 'category') {
    // Filtrează produsele din categoria beneficiară
    return cartItems.filter(item => item.category === offer.benefit_category);
  } else if (offer.benefit_type === 'specific') {
    // Filtrează produsele specifice
    return cartItems.filter(item => offer.benefit_products.includes(item.id));
  }
  
  return [];
}

