// Endpoint pentru comenzile anulate cu debugging robust
app.get('/api/orders-cancelled', async (req, res) => {
    try {
        const db = await dbPromise;
        const { startDate, endDate } = req.query;

        // Calculează intervalul pentru ziua curentă (08:00-03:00)
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        
        // Dacă este între 00:00-03:00, consideră că este încă ziua precedentă
        let startOfDay, endOfDay;
        if (now.getHours() >= 0 && now.getHours() < 3) {
            // Este încă ziua precedentă (08:00-03:00)
            startOfDay = new Date(today.getTime() - 24 * 60 * 60 * 1000); // Ieri
            startOfDay.setHours(8, 0, 0, 0); // 08:00 ieri
            endOfDay = new Date(today); // Azi
            endOfDay.setHours(3, 0, 0, 0); // 03:00 azi
        } else {
            // Este ziua curentă (08:00-03:00)
            startOfDay = new Date(today);
            startOfDay.setHours(8, 0, 0, 0); // 08:00 azi
            endOfDay = new Date(today.getTime() + 24 * 60 * 60 * 1000); // Mâine
            endOfDay.setHours(3, 0, 0, 0); // 03:00 mâine
        }

        // ⚠️ Query SQL cu filtrare pe intervalul 08:00-03:00 din ziua curentă
        let sql = `
            SELECT 
                id, type, table_number, total, timestamp, 
                cancelled_timestamp, cancelled_reason, items
            FROM orders 
            WHERE status = 'cancelled' 
            AND cancelled_timestamp >= ? 
            AND cancelled_timestamp <= ?
        `;
        
        let params = [startOfDay.toISOString(), endOfDay.toISOString()];
        
        // Adaugă filtrare suplimentară pe date dacă sunt specificate (pentru compatibilitate)
        if (startDate && endDate) {
            sql += ` AND DATE(cancelled_timestamp) BETWEEN ? AND ?`;
            params.push(startDate, endDate);
        }
        
        sql += ` ORDER BY cancelled_timestamp DESC`;

        console.log('🔍 Filtrare comenzi anulate pentru intervalul:', startOfDay.toISOString(), 'până la', endOfDay.toISOString());

        db.all(sql, params, (err, rows) => {
            if (err) {
                // EROARE CRITICĂ: Arată eroarea SQL exactă!
                console.error('❌ EROARE SQL la /api/orders-cancelled:', err.message); 
                return res.status(500).json({ 
                    error: "Eroare SQL în interogarea comenzilor anulate", 
                    details: err.message // Trimite detaliile SQL înapoi la client (temporar pentru debug)
                });
            }
            
            console.log('📊 Found cancelled orders rows:', rows ? rows.length : 0);
            
            // Procesează comenzile pentru a include items-urile parsate
            const orders = (rows || []).map(order => {
                let items = [];
                try { 
                    items = safeParseItems(order.items) || []; 
                } catch(e) { 
                    console.error('JSON parse error for cancelled order', order.id, e);
                    items = []; 
                }
                
                const mapped = items.map(it => ({ 
                    itemId: it.itemId, 
                    productId: it.productId, 
                    name: it.name || 'Produs', 
                    quantity: it.quantity, 
                    customizations: (it.customizations || []).map(c => ({ ...c, id: c.id })),
                    status: 'cancelled',
                    station: it.station
                }));
                
                return {
                    id: order.id, 
                    table_number: order.table_number, 
                    type: order.type, 
                    timestamp: order.timestamp,
                    status: 'cancelled',
                    cancelled_timestamp: order.cancelled_timestamp,
                    cancelled_reason: order.cancelled_reason,
                    items: mapped,
                    total: order.total
                };
            }).filter(Boolean); // Elimină comenzile null (fără items pentru bucătărie)
            
            console.log('📊 Processed cancelled orders:', orders.length);
            res.json({ orders });
        });

    } catch (error) {
        // EROARE DE COD: Arată eroarea de programare (ex: o variabilă undefined)
        console.error('❌ EROARE DE COD la /api/orders-cancelled:', error);
        res.status(500).json({ 
            error: "Eroare internă de programare la rută",
            details: error.message 
        });
    }
});

