// ==================== ENDPOINT-URI PENTRU INVENTAR ȘI NIR ====================

// POST /api/inventory/nir - Creare Notă de Intrare-Recepție (NIR)
app.post('/api/inventory/nir', checkAdminAuth, async (req, res) => {
    const { supplier, supplier_name, supplierName, document_date, date, items, created_by } = req.body;
    const finalSupplierName = supplier || supplier_name || supplierName; // Acceptă toate variantele
    const finalDocumentDate = document_date || date; // Acceptă ambele variante
    
    try {
        const db = await dbPromise;

        // 1. Calculează totalurile și generează NIR Number
        const totalValue = items.reduce((sum, item) => sum + item.total_price, 0);
        // TVA ar trebui calculat pe fiecare item, dar simplificăm pentru total
        const totalVAT = items.reduce((sum, item) => sum + (item.total_price * 0.21 / 1.21), 0); // TVA 21% standard RO 
        const nirNumber = await generateFiscalNumber('NIR'); 
        
        // 2. Inserare în nir_documents cu TIMESTAMP LOCAL (România UTC+3/+2)
        const nirId = await new Promise((resolve, reject) => {
            db.run(
                `INSERT INTO nir_documents (nir_number, supplier_name, document_date, reception_date, total_value, total_vat, created_by, created_at) 
                 VALUES (?, ?, ?, ?, ?, ?, ?, datetime('now', 'localtime'))`,
                [nirNumber, finalSupplierName, finalDocumentDate, new Date().toISOString().slice(0, 10), totalValue, totalVAT, created_by],
                function(err) {
                    if (err) {
                        console.error('❌ Eroare la inserarea NIR în nir_documents:', err);
                        reject(err);
                    } else {
                        console.log(`✅ NIR ${nirNumber} inserat cu ID: ${this.lastID}`);
                        resolve(this.lastID);
                    }
                }
            );
        });

        // 3. Procesează Articolele (nir_items și CAMP)
        for (const item of items) {
            console.log(`📦 Procesare articol NIR: ${JSON.stringify(item)}`);
            
            // Mapare date frontend → backend
            const quantity = parseFloat(item.qtyReceived || item.quantity || 0);
            const unit_price = parseFloat(item.priceExVat || item.unit_price || 0);
            const total_price = parseFloat(item.valueExVat || item.total_price || (quantity * unit_price));
            const unit = item.unit || 'buc';
            const productName = item.name || '';
            const code = item.code || '';
            
            // Căutare produs în baza de date (pentru a obține product_id și product_type)
            let product_id = null;
            let product_type = 'ingredient'; // Default: ingredient
            
            // Caută mai întâi după COD exact în ingrediente
            let ingredient = null;
            if (code) {
                ingredient = await new Promise((resolve, reject) => {
                    db.get('SELECT id, name, code FROM ingredients WHERE code = ? LIMIT 1', [code], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
            }
            
            // Dacă nu găsește după cod, caută după NUME în ingrediente
            if (!ingredient) {
                ingredient = await new Promise((resolve, reject) => {
                    db.get('SELECT id, name, code FROM ingredients WHERE name LIKE ? LIMIT 1', [`%${productName}%`], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
            }
            
            if (ingredient) {
                product_id = ingredient.id;
                product_type = 'ingredient';
                console.log(`🔍 Găsit ingredient: ${ingredient.name} (Cod: ${ingredient.code}, ID: ${product_id})`);
            } else {
                // Dacă nu e ingredient, caută în meniu
                const menuItem = await new Promise((resolve, reject) => {
                    db.get('SELECT id, name FROM menu WHERE name LIKE ? LIMIT 1', [`%${productName}%`], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
                
                if (menuItem) {
                    product_id = menuItem.id;
                    product_type = 'menu_product';
                    console.log(`🔍 Găsit produs meniu: ${menuItem.name} (ID: ${product_id})`);
                } else {
                    // PRODUS NOU - Creează automat în ingredients cu cod auto-generat
                    console.log(`🆕 Produs NOU "${productName}" - Se creează automat în baza de date...`);
                    
                    // Generează cod nou (găsește ultimul cod P + max ID)
                    const maxId = await new Promise((resolve, reject) => {
                        db.get('SELECT MAX(id) as maxId FROM ingredients', (err, row) => {
                            if (err) reject(err);
                            else resolve(row?.maxId || 0);
                        });
                    });
                    
                    const newId = maxId + 1;
                    const newCode = code || `P${String(newId).padStart(3, '0')}`; // Folosește codul introdus sau generează P001, P002, etc.
                    
                    // Creează ingredientul nou
                    product_id = await new Promise((resolve, reject) => {
                        db.run(
                            `INSERT INTO ingredients (code, name, unit, category, current_stock, minimum_stock, cost_per_unit, supplier) 
                             VALUES (?, ?, ?, ?, 0, 0, ?, ?)`,
                            [newCode, productName, unit, 'Altele', unit_price, finalSupplierName],
                            function(err) {
                                if (err) {
                                    console.error(`❌ Eroare la crearea ingredientului "${productName}":`, err);
                                    reject(err);
                                } else {
                                    console.log(`✅ Ingredient NOU creat: ${productName} (Cod: ${newCode}, ID: ${this.lastID})`);
                                    resolve(this.lastID);
                                }
                            }
                        );
                    });
                    
                    product_type = 'ingredient';
                }
            }
            
            // Inserare în nir_items (cu promisiune pentru gestionare erori)
            await new Promise((resolve, reject) => {
                db.run(
                    'INSERT INTO nir_items (nir_id, product_type, product_id, quantity, purchase_price_unit, purchase_price_total, unit_of_measure) VALUES (?, ?, ?, ?, ?, ?, ?)',
                    [nirId, product_type, product_id, quantity, unit_price, total_price, unit],
                    function(err) {
                        if (err) {
                            console.error('❌ Eroare la inserarea articolului NIR:', err);
                            reject(err);
                        } else {
                            console.log(`✅ Articol NIR ${product_type} ID ${product_id} inserat`);
                            resolve();
                        }
                    }
                );
            });

            // 4. Calculează și actualizează CAMP (Costul Mediu Ponderat)
            await calculateCAMP(product_type, product_id, quantity, unit_price);

            // 5. Creează audit trail în stock_movements (doar pentru ingrediente)
            if (product_type === 'ingredient') {
                await db.run(`
                    INSERT INTO stock_movements (
                        ingredient_id, 
                        quantity_change, 
                        movement_type, 
                        reference_id, 
                        notes,
                        created_at
                    ) VALUES (?, ?, 'nir', ?, ?, datetime('now', 'localtime'))
                `, [
                    product_id, 
                    quantity, 
                    nirNumber,
                    `NIR ${nirNumber} - ${finalSupplierName}: +${quantity} ${unit} @ ${unit_price} RON/${unit}`
                ]);
                
                console.log(`✅ Audit trail creat pentru ingredient ID ${product_id}: +${quantity} ${unit}`);
            }
        }
        
        res.json({ success: true, nir_number: nirNumber, message: 'NIR-ul a fost înregistrat și stocurile/CAMP au fost actualizate.' });

    } catch (error) {
        console.error('❌ Eroare la crearea NIR-ului:', error);
        res.status(500).json({ error: 'Eroare la crearea NIR-ului', details: error.message, stack: error.stack });
    }
});

// GET /api/inventory/products/search - Căutare produse pentru autocomplete în NIR
app.get('/api/inventory/products/search', checkAdminAuth, async (req, res) => {
    try {
        const db = await dbPromise;
        const searchTerm = req.query.q || '';
        
        if (searchTerm.length < 2) {
            return res.json([]);
        }
        
        // Caută în ingredients
        const ingredients = await new Promise((resolve, reject) => {
            db.all(
                `SELECT id, code, name, unit, 'ingredient' as type FROM ingredients 
                 WHERE name LIKE ? OR code LIKE ? 
                 ORDER BY name LIMIT 10`,
                [`%${searchTerm}%`, `%${searchTerm}%`],
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows || []);
                }
            );
        });
        
        // Caută în menu (produse finite care pot fi și ele primite ca marfă)
        const menuProducts = await new Promise((resolve, reject) => {
            db.all(
                `SELECT id, 'M' || SUBSTR('000' || id, -3) as code, name, 'buc' as unit, 'menu_product' as type 
                 FROM menu 
                 WHERE name LIKE ? 
                 ORDER BY name LIMIT 5`,
                [`%${searchTerm}%`],
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows || []);
                }
            );
        });
        
        // Combină rezultatele (prioritate ingredients)
        const results = [...ingredients, ...menuProducts];
        
        res.json(results);
    } catch (error) {
        console.error('❌ Eroare la căutarea produselor:', error);
        res.status(500).json({ error: 'Eroare la căutarea produselor' });
    }
});

