// GET /api/inventory/nir/:id - Detalii NIR cu articole
app.get('/api/inventory/nir/:id', checkAdminAuth, async (req, res) => {
    try {
        const db = await dbPromise;
        const nirId = req.params.id;
        
        // Obține datele NIR-ului (cu Promise wrapper pentru db.get)
        const nir = await new Promise((resolve, reject) => {
            db.get('SELECT * FROM nir_documents WHERE id = ?', [nirId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!nir) {
            return res.status(404).json({ error: 'NIR-ul nu a fost găsit' });
        }
        
        // Obține articolele NIR-ului (cu Promise wrapper pentru db.all)
        const items = await new Promise((resolve, reject) => {
            db.all(`
                SELECT 
                    ni.*,
                    CASE 
                        WHEN ni.product_type = 'menu_product' THEN m.name
                        ELSE i.name
                    END as product_name
                FROM nir_items ni
                LEFT JOIN menu m ON ni.product_type = 'menu_product' AND ni.product_id = m.id
                LEFT JOIN ingredients i ON ni.product_type = 'ingredient' AND ni.product_id = i.id
                WHERE ni.nir_id = ?
            `, [nirId], (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });
        
        console.log(`📋 NIR ${nir.nir_number}: returnat ${items.length} articole`);
        
        res.json({ nir, items });
    } catch (error) {
        console.error('❌ Eroare la obținerea detaliilor NIR:', error);
        res.status(500).json({ error: 'Eroare la obținerea detaliilor NIR' });
    }
});

