app.post('/api/areas', async (req, res) => {
  try {
    const db = await dbPromise;
    const { name, name_en, type, description, display_order } = req.body;
    
    db.run(`
      INSERT INTO areas (name, name_en, type, description, is_active, display_order)
      VALUES (?, ?, ?, ?, 1, ?)
    `, [name, name_en, type || 'indoor', description, display_order || 0], function(err) {
      if (err) {
        console.error('❌ Eroare la creare area:', err);
        return res.status(500).json({ success: false, error: err.message });
      }
      res.json({ success: true, data: { id: this.lastID }, message: 'Zonă creată cu succes' });
    });
  } catch (error) {
    console.error('❌ Eroare la creare area:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// PUT - Actualizează zonă
app.put('/api/areas/:id', async (req, res) => {
  try {
    const db = await dbPromise;
    const { name, name_en, type, description, is_active, display_order } = req.body;
    
    db.run(`
      UPDATE areas 
      SET name = ?, name_en = ?, type = ?, description = ?, is_active = ?, display_order = ?, updated_at = CURRENT_TIMESTAMP
      WHERE id = ?
    `, [name, name_en, type, description, is_active, display_order, req.params.id], function(err) {
      if (err) {
        console.error('❌ Eroare la actualizare area:', err);
        return res.status(500).json({ success: false, error: err.message });
      }
      res.json({ success: true, message: 'Zonă actualizată cu succes' });
    });
  } catch (error) {
    console.error('❌ Eroare la actualizare area:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// DELETE - Șterge zonă
app.delete('/api/areas/:id', async (req, res) => {
  try {
    const db = await dbPromise;
    
    // Verifică dacă zona are mese asociate
    db.get('SELECT COUNT(*) as count FROM tables WHERE area_id = ?', [req.params.id], (err, row) => {
      if (err) {
        return res.status(500).json({ success: false, error: err.message });
      }
      
      if (row.count > 0) {
        return res.status(400).json({ 
          success: false, 
          error: `Nu poți șterge zona. Există ${row.count} mese asociate cu această zonă.` 
        });
      }
      
      // Șterge zona
      db.run('DELETE FROM areas WHERE id = ?', [req.params.id], function(err) {
        if (err) {
          console.error('❌ Eroare la ștergere area:', err);
          return res.status(500).json({ success: false, error: err.message });
        }
        res.json({ success: true, message: 'Zonă ștearsă cu succes' });
      });
    });
  } catch (error) {
    console.error('❌ Eroare la ștergere area:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// === TABLES (Mese) ===

// GET - Toate mesele
app.get('/api/tables', async (req, res) => {
  try {
    const db = await dbPromise;
    const areaId = req.query.area_id;
    const activeOnly = req.query.active_only === 'true';
    
    let query = `
      SELECT t.*, a.name as area_name, a.type as area_type
      FROM tables t
      LEFT JOIN areas a ON t.area_id = a.id
      WHERE 1=1
    `;
    const params = [];
    
    if (areaId) {
      query += ' AND t.area_id = ?';
      params.push(areaId);
    }
    
    if (activeOnly) {
      query += ' AND t.is_active = 1';
    }
    
    query += ' ORDER BY t.table_number';
    
    db.all(query, params, (err, rows) => {
      if (err) {
        console.error('❌ Eroare la obținere tables:', err);
        return res.status(500).json({ success: false, error: err.message });
      }
      res.json({ success: true, data: rows || [] });
    });
  } catch (error) {
    console.error('❌ Eroare la obținere tables:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

