// ==================== PDF GENERATOR PENTRU TRANSFERURI ====================

const transferPDFGenerator = require('./helpers/transfer-pdf-generator');

// GET - Generează PDF Aviz Transfer (pentru gestiunea sursă)
app.get('/api/transfers/:id/aviz-pdf', async (req, res) => {
  try {
    const transferId = req.params.id;
    
    // Obține detalii transfer complet
    const transfer = await transferHelpers.getTransferById(transferId);
    
    if (!transfer) {
      return res.status(404).json({ success: false, error: 'Transfer negăsit' });
    }
    
    // Verifică că transferul este aprobat
    if (transfer.status !== 'approved' && transfer.status !== 'completed') {
      return res.status(400).json({ 
        success: false, 
        error: 'Avizul poate fi generat doar pentru transferuri aprobate sau finalizate' 
      });
    }
    
    // Obține informații despre gestiunile implicate
    const fromLocation = await new Promise((resolve, reject) => {
      db.get('SELECT * FROM management_locations WHERE id = ?', [transfer.from_location_id], (err, row) => {
        if (err) reject(err);
        else resolve(row);
      });
    });
    
    const toLocation = await new Promise((resolve, reject) => {
      db.get('SELECT * FROM management_locations WHERE id = ?', [transfer.to_location_id], (err, row) => {
        if (err) reject(err);
        else resolve(row);
      });
    });
    
    if (!fromLocation || !toLocation) {
      return res.status(404).json({ 
        success: false, 
        error: 'Gestiunile implicate nu au fost găsite' 
      });
    }
    
    // Generează PDF
    const pdfBuffer = await transferPDFGenerator.generateAvizTransferPDF(
      transfer, 
      transfer.items, 
      fromLocation, 
      toLocation
    );
    
    // Trimite PDF
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', `attachment; filename="Aviz_Transfer_${transfer.transfer_number}.pdf"`);
    res.send(pdfBuffer);
    
  } catch (error) {
    console.error('❌ Eroare la generare PDF Aviz:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

