// PUT - Actualizare status raport varianță
app.put('/api/variance/reports/:id/status', checkAdminAuth, async (req, res) => {
  try {
    const reportId = parseInt(req.params.id);
    const { status, approved_by } = req.body;
    
    console.log(`📊 [ETAPA 7] Request pentru actualizare status raport ${reportId}: ${status}`);
    
    // Validare
    if (!status) {
      return res.status(400).json({ success: false, error: 'Lipsește câmpul status' });
    }
    
    const validStatuses = ['draft', 'completed', 'approved', 'archived'];
    if (!validStatuses.includes(status)) {
      return res.status(400).json({ success: false, error: `Status invalid. Valori permise: ${validStatuses.join(', ')}` });
    }
    
    const result = await varianceHelpers.updateVarianceReportStatus(reportId, status, approved_by);
    
    if (result.changes === 0) {
      return res.status(404).json({ success: false, error: 'Raport nu a fost găsit' });
    }
    
    console.log(`✅ [ETAPA 7] Status raport ${reportId} actualizat la: ${status}`);
    
    res.json({
      success: true,
      data: result,
      message: 'Status raport actualizat cu succes'
    });
  } catch (error) {
    console.error('❌ [ETAPA 7] Eroare la actualizare status raport:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

