// Obține toate ingredientele
app.get('/api/ingredients', async (req, res) => {
    console.log('📋 Request pentru ingrediente...');
    const showHidden = req.query.show_hidden === 'true';
    
    try {
        // 🚀 OPTIMIZARE: Folosește cache-ul în loc de query direct la DB
        const cache = await loadMenuCache();
        let ingredients = cache.ingredients;
        
        // Filtrează ingredientele ascunse (dacă nu sunt cerute explicit)
        if (!showHidden) {
            ingredients = ingredients.filter(ing => !ing.is_hidden || ing.is_hidden === 0);
            console.log(`🔍 Filtrate ingredientele ascunse (rămase: ${ingredients.length})`);
        } else {
            // Dacă show_hidden=true, returnează DOAR cele ascunse
            ingredients = ingredients.filter(ing => ing.is_hidden === 1);
            console.log(`👻 Returnate DOAR ingredientele ascunse: ${ingredients.length}`);
        }
        
        // Adaugă statusul stocului pentru fiecare ingredient
        const ingredientsWithStatus = ingredients.map(ingredient => ({
            ...ingredient,
            stock_status: ingredient.current_stock <= ingredient.min_stock ? 'low' :
                         ingredient.current_stock <= ingredient.min_stock * 1.5 ? 'warning' : 'ok'
        }));
        
        console.log(`✅ Returnate ${ingredientsWithStatus.length} ingrediente din cache`);
        res.json({
            success: true,
            data: ingredientsWithStatus, // Format standard pentru teste
            ingredients: ingredientsWithStatus // Backward compatibility
        });
    } catch (error) {
        console.error('❌ Eroare la obținerea ingredientelor:', error);
        res.status(500).json({ error: 'Eroare la conectarea cu baza de date', details: error.message });
    }
});

