// Adaugă un ingredient nou - CU VERIFICARE ANTI-DUPLICATE și VALIDARE MANUALĂ
app.post('/api/ingredients', checkAdminAuth, async (req, res) => {
    const { name, category, unit, current_stock, min_stock, cost_per_unit, supplier, force, validation_reason } = req.body;

    if (!name || !category || !unit) {
        res.status(400).json({ error: 'Numele, categoria și unitatea sunt obligatorii' });
        return;
    }

    try {
        const db = await dbPromise;
        
        // Obține toate ingredientele pentru verificare similaritate
        const allIngredients = await new Promise((resolve, reject) => {
            db.all('SELECT id, name, category, unit, current_stock FROM ingredients', [], (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });

        // Verifică duplicate și similaritate
        const duplicateCheck = checkIngredientExists(name, allIngredients);

        // Dacă există exact sau foarte similar și nu e forțat
        if (duplicateCheck.exists && !force) {
            if (duplicateCheck.exact) {
                return res.status(409).json({
                    error: 'Ingredientul există deja în sistem',
                    duplicate: true,
                    exact: true,
                    existing: duplicateCheck.match,
                    message: `"${duplicateCheck.match.name}" există deja (ID: ${duplicateCheck.match.id})`
                });
            } else {
                // Analizează diferențele pentru a ajuta utilizatorul
                const analysis = analyzeDifferences(name, duplicateCheck.similar[0].name);
                
                // Ingrediente similare găsite - cere validare manuală
                return res.status(409).json({
                    error: 'Ingrediente similare găsite',
                    duplicate: true,
                    exact: false,
                    similar: duplicateCheck.similar,
                    analysis: analysis,
                    message: `Atenție! Găsite ${duplicateCheck.similar.length} ingrediente similare. Sigur vrei să adaugi "${name}"?`,
                    suggestion: `Ai vrut să zici "${duplicateCheck.similar[0].name}"?`,
                    requiresValidation: true,
                    validationPrompt: analysis.hasDifferences 
                        ? 'Pare a fi ingredient diferit. Te rog confirmă sau explică diferența:'
                        : 'Ingredientele par identice. Dacă sunt diferite, te rog explică diferența:'
                });
            }
        }

        // Adaugă ingredient (cu sau fără validare)
        const query = `
            INSERT INTO ingredients 
            (name, category, unit, current_stock, min_stock, cost_per_unit, supplier, created_at, last_updated)
            VALUES (?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
        `;

        const result = await new Promise((resolve, reject) => {
            db.run(query, [name, category, unit, current_stock || 0, min_stock || 0, cost_per_unit || 0, supplier || ''], function(err) {
                if (err) reject(err);
                else resolve(this.lastID);
            });
        });

        // Log validare manuală dacă există
        if (force && validation_reason) {
            console.log(`✅ Ingredient adăugat cu validare manuală: "${name}" (ID: ${result})`);
            console.log(`   Motiv: ${validation_reason}`);
            
            // Salvează motivul în log sau notes (optional)
            db.run(
                'UPDATE ingredients SET notes = ? WHERE id = ?',
                [`Validat manual: ${validation_reason}`, result],
                (err) => {
                    if (err) console.error('Eroare salvare motiv validare:', err);
                }
            );
        } else {
            console.log(`✅ Ingredient nou adăugat: "${name}" (ID: ${result})`);
        }

        res.json({
            success: true,
            message: 'Ingredientul a fost adăugat cu succes',
            ingredient_id: result,
            warning: force ? (validation_reason ? `Validat manual: ${validation_reason}` : 'Ingredient adăugat cu forțare') : null
        });
    } catch (error) {
        console.error('❌ Eroare la adăugarea ingredientului:', error);
        res.status(500).json({ error: 'Eroare la adăugarea ingredientului', details: error.message });
    }
});

