// Șterge un ingredient
app.delete('/api/ingredients/:id', checkAdminAuth, async (req, res) => {
    const ingredientId = req.params.id;
    const forceDelete = req.query.force === 'true'; // Permite ștergere forțată

    try {
        const db = await dbPromise;
        
        // Obține informații despre ingredient
        const ingredientInfo = await new Promise((resolve, reject) => {
            db.get('SELECT name FROM ingredients WHERE id = ?', [ingredientId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });

        if (!ingredientInfo) {
            return res.status(404).json({ 
                error: 'Ingredientul nu a fost găsit' 
            });
        }
        
        // Verifică dacă ingredientul este folosit în rețete
        const checkQuery = `
            SELECT COUNT(*) as count, 
                   GROUP_CONCAT(DISTINCT m.name) as product_names
            FROM recipes r
            JOIN menu m ON r.product_id = m.id
            WHERE r.ingredient_id = ?
        `;
        
        const checkResult = await new Promise((resolve, reject) => {
            db.get(checkQuery, [ingredientId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });

        if (checkResult.count > 0) {
            if (!forceDelete) {
                // Returnează info despre produsele care folosesc ingredientul
                const products = checkResult.product_names ? checkResult.product_names.split(',').slice(0, 5) : [];
                return res.status(400).json({ 
                    error: 'Ingredientul este folosit în rețete',
                    usedIn: checkResult.count,
                    products: products,
                    moreProducts: checkResult.count > 5 ? checkResult.count - 5 : 0,
                    canForceDelete: true
                });
            }

            // Ștergere forțată - șterge mai întâi din rețete
            await new Promise((resolve, reject) => {
                db.run('DELETE FROM recipes WHERE ingredient_id = ?', [ingredientId], function(err) {
                    if (err) reject(err);
                    else resolve(this.changes);
                });
            });

            console.log(`⚠️ Șterse ${checkResult.count} utilizări ale ingredientului din rețete`);
        }

        // Șterge ingredientul
        const deleteQuery = `DELETE FROM ingredients WHERE id = ?`;
        
        await new Promise((resolve, reject) => {
            db.run(deleteQuery, [ingredientId], function(err) {
                if (err) reject(err);
                else resolve(this.changes);
            });
        });

        console.log(`✅ Ingredient șters cu ID: ${ingredientId} (${ingredientInfo.name})`);
        res.json({
            success: true,
            message: `Ingredientul "${ingredientInfo.name}" a fost șters cu succes`,
            deletedRecipes: forceDelete ? checkResult.count : 0
        });
    } catch (error) {
        console.error('❌ Eroare la ștergerea ingredientului:', error);
        res.status(500).json({ error: 'Eroare la ștergerea ingredientului', details: error.message });
    }
});

// Ascunde un ingredient (marchează ca neinventariabil)
app.patch('/api/ingredients/:id/hide', checkAdminAuth, async (req, res) => {
    const ingredientId = req.params.id;

    try {
        const db = await dbPromise;
        
        // Obține informații despre ingredient
        const ingredientInfo = await new Promise((resolve, reject) => {
            db.get('SELECT name, is_hidden FROM ingredients WHERE id = ?', [ingredientId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });

        if (!ingredientInfo) {
            return res.status(404).json({ 
                error: 'Ingredientul nu a fost găsit' 
            });
        }

        if (ingredientInfo.is_hidden === 1) {
            return res.status(400).json({ 
                error: 'Ingredientul este deja ascuns' 
            });
        }

        // Ascunde ingredientul
        await new Promise((resolve, reject) => {
            db.run('UPDATE ingredients SET is_hidden = 1 WHERE id = ?', [ingredientId], function(err) {
                if (err) reject(err);
                else resolve(this.changes);
            });
        });

        // Invalidate cache
        menuCache.lastUpdated = 0;

        console.log(`👻 Ingredient ascuns cu ID: ${ingredientId} (${ingredientInfo.name})`);
        res.json({
            success: true,
            message: `Ingredientul "${ingredientInfo.name}" a fost ascuns (neinventariabil)`
        });
    } catch (error) {
        console.error('❌ Eroare la ascunderea ingredientului:', error);
        res.status(500).json({ error: 'Eroare la ascunderea ingredientului', details: error.message });
    }
});

