// POST /api/menu/add - Adaugă un produs nou în meniu
app.post('/api/menu/add', checkAdminAuth, async (req, res) => {
    try {
        const { name, category, price, description, weight, allergens } = req.body;
        
        // Validări
        if (!name || !category || price === undefined || price === null) {
            return res.status(400).json({
                success: false,
                error: 'Numele, categoria și prețul sunt obligatorii'
            });
        }
        
        if (price <= 0) {
            return res.status(400).json({
                success: false,
                error: 'Prețul trebuie să fie mai mare decât 0'
            });
        }
        
        const db = await dbPromise;
        
        // Verifică dacă produsul există deja
        const existingProduct = await new Promise((resolve, reject) => {
            db.get('SELECT id FROM menu WHERE name = ?', [name.trim()], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (existingProduct) {
            return res.status(409).json({
                success: false,
                error: 'Un produs cu acest nume există deja'
            });
        }
        
        // Adaugă produsul în baza de date
        const result = await new Promise((resolve, reject) => {
            db.run(`
                INSERT INTO menu (name, category, price, description, weight, allergens, is_vegetarian, is_spicy, is_takeout_only)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
            `, [
                name.trim(),
                category.trim(),
                price,
                description ? description.trim() : '',
                weight || '1 porție',
                allergens || '',
                false, // is_vegetarian - default false
                false, // is_spicy - default false  
                false  // is_takeout_only - default false
            ], function(err) {
                if (err) reject(err);
                else resolve({ id: this.lastID, changes: this.changes });
            });
        });
        
        console.log(`✅ Produs nou adăugat: "${name}" (ID: ${result.id}) în categoria "${category}"`);
        
        // Reîncarcă cache-ul meniului
        await loadMenuCache();
        
        res.json({
            success: true,
            message: 'Produsul a fost adăugat cu succes',
            productId: result.id,
            product: {
                id: result.id,
                name: name.trim(),
                category: category.trim(),
                price: price,
                description: description ? description.trim() : '',
                weight: weight || '1 porție',
                allergens: allergens || '',
                is_vegetarian: false,
                is_spicy: false,
                is_takeout_only: false
            }
        });
        
    } catch (error) {
        console.error('❌ Eroare la adăugarea produsului:', error.message);
        res.status(500).json({
            success: false,
            error: 'Eroare server intern',
            message: error.message
        });
    }
});

// ==================== FUNCȚII PENTRU CALCULUL PREȚURILOR ====================

/**
 * Calculează prețul sugestiv pentru un produs pe baza rețetei sale
 * @param {number} productId - ID-ul produsului
 * @param {Database} db - Instanța bazei de date
 * @returns {Object} - Obiect cu prețul sugestiv și detalii
 */
async function calculateSuggestedPriceFromRecipe(productId, db) {
    try {
        console.log(`💰 Calculare preț sugestiv pentru produsul ${productId}...`);
        
        // 1. Obține toate rețetele pentru produs
        const recipes = await new Promise((resolve, reject) => {
            db.all(`
                SELECT 
                    r.quantity_needed, r.unit, r.waste_percentage, r.variable_consumption, r.item_type,
                    i.name as ingredient_name, i.cost_per_unit, i.unit as ingredient_unit
                FROM recipes r 
                LEFT JOIN ingredients i ON r.ingredient_id = i.id 
                WHERE r.product_id = ? AND r.item_type = 'ingredient'
            `, [productId], (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });

        if (recipes.length === 0) {
            return {
                suggested_price: 0,
                cost_breakdown: [],
                total_cost: 0,
                margin_percentage: 0,
                message: 'Nu există ingrediente în rețetă'
            };
        }

        // 2. Calculează costul total al ingredientelor
        let totalCost = 0;
        const costBreakdown = [];

        for (const recipe of recipes) {
            if (!recipe.cost_per_unit) {
                console.log(`⚠️ Cost lipsă pentru ingredient: ${recipe.ingredient_name}`);
                continue;
            }

            // Calculează cantitatea brută (inclusiv deșeul)
            let grossQuantity = recipe.quantity_needed;
            if (recipe.waste_percentage > 0) {
                const wasteFactor = 1 - (recipe.waste_percentage / 100);
                grossQuantity = recipe.quantity_needed / wasteFactor;
            }

            // Calculează costul pentru acest ingredient
            const ingredientCost = grossQuantity * recipe.cost_per_unit;
            totalCost += ingredientCost;

            costBreakdown.push({
                ingredient: recipe.ingredient_name,
                quantity: recipe.quantity_needed,
                unit: recipe.unit,
                waste_percentage: recipe.waste_percentage,
                gross_quantity: grossQuantity,
                cost_per_unit: recipe.cost_per_unit,
                total_cost: ingredientCost
            });
        }

        // 3. Aplică marjă de profit sugestivă (150% = marjă de 50%)
        const marginPercentage = 150; // 150% din cost = 50% marjă
        const suggestedPrice = Math.round(totalCost * (marginPercentage / 100) * 100) / 100;

        console.log(`💰 Preț sugestiv calculat: ${suggestedPrice} RON (cost: ${totalCost} RON, marjă: ${marginPercentage}%)`);

        return {
            suggested_price: suggestedPrice,
            cost_breakdown: costBreakdown,
            total_cost: Math.round(totalCost * 100) / 100,
            margin_percentage: marginPercentage,
            margin_amount: Math.round((suggestedPrice - totalCost) * 100) / 100,
            message: `Preț sugestiv bazat pe ${recipes.length} ingrediente`
        };

    } catch (error) {
        console.error('❌ Eroare la calcularea prețului sugestiv:', error.message);
        return {
            suggested_price: 0,
            cost_breakdown: [],
            total_cost: 0,
            margin_percentage: 0,
            error: error.message
        };
    }
}

