// Adaugă o rețetă nouă (cu suport F.T.P. complet)
app.post('/api/recipes', checkAdminAuth, async (req, res) => {
    try {
        console.log('📋 Request pentru adăugare rețetă...');
        const { 
            product_id, ingredient_id, ingredient_name, quantity_needed, unit, 
            waste_percentage = 0, variable_consumption = null, item_type = 'ingredient' 
        } = req.body;

        // Validare: trebuie să aibă fie ingredient_id, fie ingredient_name
        if (!product_id || (!ingredient_id && !ingredient_name) || !quantity_needed || !unit) {
            res.status(400).json({ error: 'Câmpurile product_id, ingredient (id sau name), quantity și unit sunt obligatorii' });
            return;
        }

        const db = await dbPromise;
        let finalIngredientId = ingredient_id;
        let newIngredientCreated = false;

        // 1. Dacă avem ingredient_name (ingredient nou), îl creăm automat
        if (!ingredient_id && ingredient_name) {
            console.log(`✨ Ingredient NOU detectat: "${ingredient_name}" - creez automat...`);
            
            // Detectează categoria pe bază de cuvinte cheie
            const detectCategory = (name) => {
                const nameLower = name.toLowerCase();
                if (nameLower.match(/mozzarella|parmezan|cașcaval|brânză|unt|smântână|iaurt/)) return 'Lactate';
                if (nameLower.match(/pui|vită|porc|carne|șuncă|bacon|cârnați/)) return 'Carne';
                if (nameLower.match(/roșii|ceapă|usturoi|ardei|salată|morcov|cartofi/)) return 'Legume';
                if (nameLower.match(/oregano|busuioc|sare|piper|condiment/)) return 'Condimente';
                if (nameLower.match(/făină|paste|orez|pâine/)) return 'Panificație';
                if (nameLower.match(/ulei|sos|ketchup|maioneză/)) return 'Sosuri';
                return 'Diverse';
            };
            
            const category = detectCategory(ingredient_name);
            
            // Creează ingredientul
            const createResult = await new Promise((resolve, reject) => {
                db.run(
                    `INSERT INTO ingredients (name, category, unit, allergens, cost_per_unit) VALUES (?, ?, ?, NULL, 0)`,
                    [ingredient_name, category, unit],
                    function(err) {
                        if (err) reject(err);
                        else resolve({ id: this.lastID });
                    }
                );
            });
            
            finalIngredientId = createResult.id;
            newIngredientCreated = true;
            
            // Populează stocul automat cu cantitate 0
            await new Promise((resolve, reject) => {
                db.run(
                    `INSERT INTO stocks (ingredient_id, quantity, unit, last_updated) VALUES (?, 0, ?, CURRENT_TIMESTAMP)`,
                    [finalIngredientId, unit],
                    (err) => {
                        if (err) reject(err);
                        else resolve();
                    }
                );
            });
            
            console.log(`✅ Ingredient NOU creat: ID ${finalIngredientId}, Nume: "${ingredient_name}", Categorie: ${category}, Unitate: ${unit}`);
            console.log(`✅ Stoc populat automat pentru ingredientul #${finalIngredientId}`);
        } else if (ingredient_id) {
            // Verifică dacă ingredientul existent există
            const ingredient = await new Promise((resolve, reject) => {
                db.get('SELECT id, name, category, unit FROM ingredients WHERE id = ?', [ingredient_id], (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                });
            });

            if (!ingredient) {
                res.status(404).json({ error: `Ingredientul cu ID ${ingredient_id} nu există` });
                return;
            }
        }

        // 2. Adaugă rețeta cu toate câmpurile F.T.P.
        const query = `
            INSERT OR REPLACE INTO recipes 
            (product_id, ingredient_id, quantity_needed, unit, waste_percentage, variable_consumption, item_type, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
        `;

        const result = await new Promise((resolve, reject) => {
            db.run(query, [
                product_id, finalIngredientId, quantity_needed, unit, 
                waste_percentage, variable_consumption, item_type
            ], function(err) {
                if (err) reject(err);
                else resolve({ id: this.lastID, changes: this.changes });
            });
        });

        console.log('✅ Rețetă adăugată cu ID:', result.id);

        // 3. Reîncarcă cache-ul meniului pentru sincronizare
        await loadMenuCache();

        // 4. Calculează prețul sugestiv pentru admin (nu îl impune automat)
        const suggestedPrice = await calculateSuggestedPriceFromRecipe(product_id, db);

        // 5. ✨ CALCUL AUTOMAT ALERGENI din ingrediente
        let calculatedAllergens = null;
        try {
            calculatedAllergens = await calculateAndUpdateProductAllergens(product_id, db);
            console.log(`✅ Alergeni recalculați pentru produsul #${product_id}: ${calculatedAllergens || 'niciunul'}`);
        } catch (allergenError) {
            console.error(`⚠️ Eroare la calcularea alergenilor (nu blochează salvarea):`, allergenError.message);
        }

        res.json({
            success: true,
            message: newIngredientCreated ? 'Rețeta și ingredientul nou au fost adăugate cu succes' : 'Rețeta a fost adăugată cu succes',
            recipe_id: result.id,
            ingredient_id: finalIngredientId,
            new_ingredient_created: newIngredientCreated,
            auto_sync: {
                menu_cache_reloaded: true,
                suggested_price_calculated: true,
                allergens_calculated: calculatedAllergens !== null,
                stock_created: newIngredientCreated
            },
            suggested_price: suggestedPrice,
            calculated_allergens: calculatedAllergens
        });

    } catch (error) {
        console.error('❌ Eroare la adăugarea rețetei:', error.message);
        res.status(500).json({ 
            success: false,
            error: 'Eroare server intern', 
            details: error.message 
        });
    }
});

