// Obține toate produsele cu alergenii lor (calculați și declarați)
app.get('/api/allergens/products', checkAdminAuth, async (req, res) => {
    try {
        const db = await dbPromise;

        // Obține toate produsele cu rețete
        const products = await new Promise((resolve, reject) => {
            db.all(`
                SELECT DISTINCT
                    m.id,
                    m.name,
                    m.category,
                    m.allergens as current_allergens,
                    m.allergens_en as current_allergens_en
                FROM menu m
                INNER JOIN recipes r ON m.id = r.product_id
                WHERE r.item_type = 'ingredient'
                ORDER BY m.name
            `, (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });

        // Pentru fiecare produs, calculează alergenii din ingrediente
        const productsWithCalculatedAllergens = await Promise.all(
            products.map(async (product) => {
                try {
                    // Obține ingredientele
                    const ingredients = await new Promise((resolve, reject) => {
                        db.all(`
                            SELECT i.allergens, i.potential_allergens
                            FROM recipes r
                            JOIN ingredients i ON r.ingredient_id = i.id
                            WHERE r.product_id = ? AND r.item_type = 'ingredient'
                        `, [product.id], (err, rows) => {
                            if (err) reject(err);
                            else resolve(rows || []);
                        });
                    });

                    // Calculează alergenii
                    const allergensSet = new Set();
                    for (const ingredient of ingredients) {
                        if (ingredient.allergens) {
                            ingredient.allergens.split(',').forEach(a => {
                                const allergen = a.trim();
                                if (allergen && allergen !== '0' && allergen !== '-') {
                                    allergensSet.add(allergen);
                                }
                            });
                        }
                    }

                    const calculated_allergens = Array.from(allergensSet).sort().join(', ');

                    // Compară cu alergenii declarați
                    const current = (product.current_allergens || '').toLowerCase().replace(/\s/g, '');
                    const calculated = calculated_allergens.toLowerCase().replace(/\s/g, '');
                    const has_difference = current !== calculated;

                    return {
                        ...product,
                        calculated_allergens,
                        has_difference,
                        ingredient_count: ingredients.length
                    };
                } catch (error) {
                    console.error(`Eroare la calcularea alergenilor pentru produsul ${product.id}:`, error);
                    return {
                        ...product,
                        calculated_allergens: '',
                        has_difference: false,
                        ingredient_count: 0,
                        error: error.message
                    };
                }
            })
        );

        res.json({
            success: true,
            products: productsWithCalculatedAllergens,
            total_products: productsWithCalculatedAllergens.length,
            products_with_differences: productsWithCalculatedAllergens.filter(p => p.has_difference).length
        });

    } catch (error) {
        console.error('❌ Eroare la obținerea produselor cu alergeni:', error);
        res.status(500).json({
            success: false,
            error: 'Eroare la obținerea produselor',
            details: error.message
        });
    }
});

