// Calculează stocurile necesare pentru o comandă
app.post('/api/recipes/calculate-stock', (req, res) => {
    const { order_items } = req.body;

    if (!order_items || !Array.isArray(order_items)) {
        res.status(400).json({ error: 'Lista de produse comandate este obligatorie' });
        return;
    }

    const stockCalculation = {};
    let totalCost = 0;

    // Pentru fiecare produs comandat
    order_items.forEach(item => {
        const { product_id, quantity } = item;
        
        // Obține rețeta pentru produs
        const recipeQuery = `
            SELECT 
                r.quantity_needed,
                r.unit,
                i.name as ingredient_name,
                i.current_stock,
                i.min_stock,
                i.cost_per_unit
            FROM recipes r
            JOIN ingredients i ON r.ingredient_id = i.id
            WHERE r.product_id = ?
        `;

        db.all(recipeQuery, [product_id], (err, recipeRows) => {
            if (err) {
                console.error('❌ Eroare la calculul stocului:', err);
                return;
            }

            recipeRows.forEach(recipe => {
                const neededQuantity = recipe.quantity_needed * quantity;
                const ingredientName = recipe.ingredient_name;

                if (!stockCalculation[ingredientName]) {
                    stockCalculation[ingredientName] = {
                        current_stock: recipe.current_stock,
                        min_stock: recipe.min_stock,
                        needed_quantity: 0,
                        cost_per_unit: recipe.cost_per_unit,
                        total_cost: 0
                    };
                }

                stockCalculation[ingredientName].needed_quantity += neededQuantity;
                stockCalculation[ingredientName].total_cost = 
                    stockCalculation[ingredientName].needed_quantity * recipe.cost_per_unit;
                totalCost += stockCalculation[ingredientName].total_cost;
            });
        });
    });

    // Verifică disponibilitatea stocurilor
    const stockStatus = Object.keys(stockCalculation).map(ingredientName => {
        const ingredient = stockCalculation[ingredientName];
        const availableAfterOrder = ingredient.current_stock - ingredient.needed_quantity;
        
        return {
            ingredient_name: ingredientName,
            current_stock: ingredient.current_stock,
            needed_quantity: ingredient.needed_quantity,
            available_after_order: availableAfterOrder,
            status: availableAfterOrder < ingredient.min_stock ? 'insufficient' : 'sufficient',
            cost: ingredient.total_cost
        };
    });

    res.json({
        success: true,
        stock_calculation: stockCalculation,
        stock_status: stockStatus,
        total_cost: totalCost,
        can_fulfill_order: stockStatus.every(item => item.status === 'sufficient')
    });
});

// 🔥 Actualizează stocurile după o comandă (VERSIUNE ÎMBUNĂTĂȚITĂ cu Tranzacții)
app.post('/api/recipes/update-stock', async (req, res) => {
    const { order_items, order_id } = req.body;

    if (!order_items || !Array.isArray(order_items)) {
        res.status(400).json({ error: 'Lista de produse comandate este obligatorie' });
        return;
    }

    try {
        const db = await dbPromise;
        
        // PASUL 1: Calculează totalul ingredientelor necesare pentru întreaga comandă
        const ingredientsMap = new Map(); // Format: ingredient_id -> {quantity, cost_per_unit}
        
        // Folosim Promise.all pentru a aștepta toate query-urile de rețete
        const recipePromises = order_items.map(item => {
            return new Promise((resolve, reject) => {
                const { product_id, quantity } = item;
                
                const recipeQuery = `
                    SELECT 
                        r.quantity_needed,
                        r.ingredient_id,
                        i.name as ingredient_name,
                        i.cost_per_unit,
                        i.current_stock
                    FROM recipes r
                    JOIN ingredients i ON r.ingredient_id = i.id
                    WHERE r.product_id = ?
                `;

                db.all(recipeQuery, [product_id], (err, recipeRows) => {
                    if (err) {
                        console.error(`❌ Eroare la obținerea rețetei pentru produsul ${product_id}:`, err);
                        return reject(err);
                    }

                    if (!recipeRows || recipeRows.length === 0) {
                        console.warn(`⚠️ Produsul ${product_id} nu are rețetă definită - stocul NU va fi scăzut`);
                    }

                    recipeRows.forEach(recipe => {
                        const neededQuantity = recipe.quantity_needed * quantity;
                        
                        if (ingredientsMap.has(recipe.ingredient_id)) {
                            // Ingredient deja în map - adaugă la cantitate
                            const existing = ingredientsMap.get(recipe.ingredient_id);
                            existing.quantity += neededQuantity;
                        } else {
                            // Ingredient nou
                            ingredientsMap.set(recipe.ingredient_id, {
                                quantity: neededQuantity,
                                cost_per_unit: recipe.cost_per_unit,
                                name: recipe.ingredient_name,
                                current_stock: recipe.current_stock
                            });
                        }
                    });

                    resolve();
                });
            });
        });

        // Așteaptă ca toate rețetele să fie procesate
        await Promise.all(recipePromises);

        // PASUL 2: Convertește Map în array pentru funcția decreaseIngredientStock
        const ingredientsToDecrease = Array.from(ingredientsMap.entries()).map(([id, data]) => ({
            ingredient_id: parseInt(id),
            quantity: data.quantity
        }));

        if (ingredientsToDecrease.length === 0) {
            console.log(`⚠️ Comanda ${order_id} nu conține produse cu rețete - niciun stoc scăzut`);
            return res.json({
                success: true,
                message: 'Comanda nu conține produse cu ingrediente definite',
                total_cost: 0,
                updates_count: 0
            });
        }

        console.log(`🔍 Comanda #${order_id}: Se scad ${ingredientsToDecrease.length} ingrediente din stoc`);

        // PASUL 3: Scade stocul folosind funcția tranzacțională
        await decreaseIngredientStock(ingredientsToDecrease, null);

        // PASUL 4: Adaugă în istoric (pentru tracking)
        const totalCost = Array.from(ingredientsMap.values())
            .reduce((sum, data) => sum + (data.quantity * data.cost_per_unit), 0);

        // Adaugă intrări în stock_history pentru fiecare ingredient
        const historyPromises = ingredientsToDecrease.map(ing => {
            return new Promise((resolve, reject) => {
                const ingredientData = ingredientsMap.get(ing.ingredient_id);
                const previousStock = ingredientData.current_stock;
                const newStock = previousStock - ing.quantity;
                
                db.run(`INSERT INTO stock_history 
                    (ingredient_id, change_type, quantity_change, previous_stock, new_stock, reason, order_id)
                    VALUES (?, 'order', ?, ?, ?, 'Comandă procesată', ?)`,
                    [ing.ingredient_id, -ing.quantity, previousStock, newStock, order_id], 
                    function(err) {
                        if (err) {
                            console.error('❌ Eroare la adăugarea în istoric:', err);
                            // Nu blochez procesul pentru erori de istoric
                        }
                        resolve();
                    });
            });
        });

        await Promise.all(historyPromises);

        console.log(`✅ Comanda #${order_id}: Stocuri actualizate cu succes (${ingredientsToDecrease.length} ingrediente, cost total: ${totalCost.toFixed(2)} RON)`);

        res.json({
            success: true,
            message: 'Stocurile au fost actualizate cu succes',
            total_cost: totalCost,
            updates_count: ingredientsToDecrease.length
        });

    } catch (error) {
        console.error(`❌ EROARE CRITICĂ la actualizarea stocurilor pentru comanda ${order_id}:`, error.message);
        res.status(500).json({ 
            error: 'Eroare la actualizarea stocurilor',
            details: error.message,
            order_id: order_id
        });
    }
});

