// Endpoint pentru predicții și alertă automată
app.get('/api/analytics/cancellation-predictions', async (req, res) => {
  const lang = (req.query.lang || 'ro').toLowerCase();
  
  console.log('🔮 Cancellation predictions requested');
  
  const db = await dbPromise;
  
  // Analizează tendințele din ultimele 30 de zile
  const thirtyDaysAgo = new Date();
  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
  
  const predictionQuery = `
    SELECT 
      DATE(timestamp) as date,
      COUNT(*) as total_orders,
      SUM(CASE WHEN status = 'cancelled' THEN 1 ELSE 0 END) as cancelled_orders,
      0 as avg_cancel_time
    FROM orders 
    WHERE timestamp >= ?
    GROUP BY DATE(timestamp)
    ORDER BY date DESC
    LIMIT 30
  `;
  
  const stockQuery = `
    SELECT 
      m.name,
      ps.current_stock,
      ps.min_stock,
      0 as cancellations_due_to_stock
    FROM menu m
    LEFT JOIN product_stock ps ON m.id = ps.product_id
    WHERE ps.current_stock <= ps.min_stock
    GROUP BY m.id, m.name, ps.current_stock, ps.min_stock
    LIMIT 20
  `;
  
  try {
    const [dailyData, lowStockProducts] = await Promise.all([
      new Promise((resolve, reject) => {
        db.all(predictionQuery, [thirtyDaysAgo.toISOString()], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      }),
      new Promise((resolve, reject) => {
        db.all(stockQuery, [], (err, rows) => {
          if (err) reject(err);
          else resolve(rows || []);
        });
      })
    ]);
    
    // Calculează tendințele
    const recentData = dailyData.slice(0, 7); // Ultimele 7 zile
    const olderData = dailyData.slice(7, 14); // Zilele 8-14
    
    const recentAvgRate = recentData.length > 0 ? 
      recentData.reduce((sum, day) => sum + (day.cancelled_orders / day.total_orders), 0) / recentData.length : 0;
    
    const olderAvgRate = olderData.length > 0 ? 
      olderData.reduce((sum, day) => sum + (day.cancelled_orders / day.total_orders), 0) / olderData.length : 0;
    
    const trend = recentAvgRate > olderAvgRate ? 'increasing' : 
                  recentAvgRate < olderAvgRate ? 'decreasing' : 'stable';
    
    const trendPercentage = olderAvgRate > 0 ? 
      Math.abs(((recentAvgRate - olderAvgRate) / olderAvgRate) * 100) : 0;
    
    // Identifică alertări
    const alerts = [];
    
    // Alertă pentru rate de anulare crescătoare
    if (trend === 'increasing' && trendPercentage > 20) {
      alerts.push({
        type: 'high_cancellation_rate',
        severity: 'warning',
        message: `Rate de anulare în creștere cu ${trendPercentage.toFixed(1)}% în ultimele 7 zile`,
        current_rate: (recentAvgRate * 100).toFixed(2) + '%',
        previous_rate: (olderAvgRate * 100).toFixed(2) + '%'
      });
    }
    
    // Alertă pentru produse cu stoc scăzut
    lowStockProducts.forEach(product => {
      if (product.cancellations_due_to_stock > 0) {
        alerts.push({
          type: 'low_stock_cancellations',
          severity: 'critical',
          message: `${product.name} - ${product.cancellations_due_to_stock} anulări din cauza stocului scăzut`,
          product_name: product.name,
          current_stock: product.current_stock,
          min_stock: product.min_stock,
          cancellations: product.cancellations_due_to_stock
        });
      }
    });
    
    // Alertă pentru timp mediu de anulare scăzut
    const avgCancelTime = recentData.reduce((sum, day) => sum + (day.avg_cancel_time || 0), 0) / recentData.length;
    if (avgCancelTime < 1) { // Mai puțin de 1 minut
      alerts.push({
        type: 'fast_cancellations',
        severity: 'info',
        message: `Timp mediu de anulare foarte scăzut: ${avgCancelTime.toFixed(1)} minute`,
        avg_time: avgCancelTime
      });
    }
    
    const result = {
      analysis_period: {
        start: thirtyDaysAgo.toISOString(),
        end: new Date().toISOString(),
        days_analyzed: dailyData.length
      },
      trend_analysis: {
        current_rate: (recentAvgRate * 100).toFixed(2) + '%',
        previous_rate: (olderAvgRate * 100).toFixed(2) + '%',
        trend: trend,
        change_percentage: trendPercentage.toFixed(1) + '%',
        trend_description: trend === 'increasing' ? 'Rate în creștere' : 
                          trend === 'decreasing' ? 'Rate în scădere' : 'Rate stabile'
      },
      predictions: {
        next_week_rate: trend === 'increasing' ? 
          ((recentAvgRate * 1.1) * 100).toFixed(2) + '%' :
          trend === 'decreasing' ?
          ((recentAvgRate * 0.9) * 100).toFixed(2) + '%' :
          (recentAvgRate * 100).toFixed(2) + '%',
        confidence: trendPercentage > 30 ? 'high' : trendPercentage > 15 ? 'medium' : 'low'
      },
      alerts: alerts,
      recommendations: [
        trend === 'increasing' ? 'Monitorizează motivele de anulare și îmbunătățește serviciul' : null,
        lowStockProducts.length > 0 ? 'Actualizează stocurile pentru produsele cu stoc scăzut' : null,
        avgCancelTime < 2 ? 'Analizează procesul de plasare a comenzilor pentru a reduce anulările rapide' : null
      ].filter(Boolean)
    };
    
    console.log('🔮 Cancellation predictions generated:', {
      trend: result.trend_analysis.trend,
      alerts_count: result.alerts.length,
      recommendations_count: result.recommendations.length
    });
    
    res.json(result);
    
  } catch (error) {
    console.error('❌ Error generating cancellation predictions:', error);
    res.status(500).json({ error: 'Eroare la generarea predicțiilor de anulare' });
  }
});

// Endpoint pentru integrarea cu sistemul de stocuri
app.get('/api/analytics/stock-cancellation-correlation', async (req, res) => {
  const lang = (req.query.lang || 'ro').toLowerCase();
  
  console.log('🔗 Stock-cancellation correlation analysis requested');
  
  const db = await dbPromise;
  
  // Query pentru a analiza comenzile anulate din ultimele 30 de zile
  const correlationQuery = `
    SELECT 
      m.id,
      m.name,
      m.category,
      COALESCE(ps.current_stock, 0) as current_stock,
      COALESCE(ps.min_stock, 0) as min_stock,
      COUNT(DISTINCT o.id) as total_cancellations,
      COUNT(DISTINCT CASE WHEN ps.current_stock <= ps.min_stock THEN o.id END) as stock_related_cancellations,
      COALESCE(SUM(o.total), 0) as cancelled_value
    FROM menu m
    LEFT JOIN product_stock ps ON m.id = ps.product_id
    LEFT JOIN orders o ON o.status = 'cancelled' 
      AND o.timestamp >= datetime('now', '-30 days')
      AND o.items LIKE '%' || m.name || '%'
    WHERE o.status = 'cancelled' OR ps.current_stock <= ps.min_stock
    GROUP BY m.id, m.name, m.category, ps.current_stock, ps.min_stock
    HAVING total_cancellations > 0 OR ps.current_stock <= ps.min_stock
    ORDER BY total_cancellations DESC, cancelled_value DESC
    LIMIT 50
  `;
  
  try {
    db.all(correlationQuery, [], (err, rows) => {
      if (err) {
        console.error('❌ Error in stock-cancellation correlation query:', err);
        return res.status(500).json({ error: 'Eroare la analiza corelației stoc-anulare' });
      }
      
      const analysis = (rows || []).map(row => {
        const stockRatio = row.min_stock > 0 ? row.current_stock / row.min_stock : 0;
        const stockRelatedRate = row.total_cancellations > 0 ? 
          (row.stock_related_cancellations / row.total_cancellations) * 100 : 0;
        
        let riskLevel = 'low';
        if (stockRatio < 0.5 || stockRelatedRate > 50) {
          riskLevel = 'high';
        } else if (stockRatio < 1 || stockRelatedRate > 25) {
          riskLevel = 'medium';
        }
        
        return {
          product_id: row.id,
          name: row.name,
          category: row.category,
          current_stock: row.current_stock,
          min_stock: row.min_stock,
          stock_ratio: stockRatio.toFixed(2),
          total_cancellations: row.total_cancellations,
          stock_related_cancellations: row.stock_related_cancellations,
          stock_related_rate: stockRelatedRate.toFixed(2) + '%',
          cancelled_value: row.cancelled_value || 0,
          risk_level: riskLevel,
          recommendations: [
            stockRatio < 0.5 ? 'Stoc critic - actualizează urgent' : null,
            stockRelatedRate > 50 ? 'Anulări frecvente din cauza stocului - verifică disponibilitatea' : null,
            row.total_cancellations > 10 ? 'Produs cu multe anulări - analizează calitatea sau prețul' : null
          ].filter(Boolean)
        };
      });
      
      const summary = {
        total_products_analyzed: analysis.length,
        high_risk_products: analysis.filter(p => p.risk_level === 'high').length,
        medium_risk_products: analysis.filter(p => p.risk_level === 'medium').length,
        low_risk_products: analysis.filter(p => p.risk_level === 'low').length,
        total_cancelled_value: analysis.reduce((sum, p) => sum + p.cancelled_value, 0),
        avg_stock_related_rate: analysis.length > 0 ? 
          (analysis.reduce((sum, p) => sum + parseFloat(p.stock_related_rate), 0) / analysis.length).toFixed(2) + '%' : '0%'
      };
      
      const result = {
        analysis_date: new Date().toISOString(),
        summary: summary,
        products: analysis,
        high_risk_products: analysis.filter(p => p.risk_level === 'high').map(p => ({
          product_name: p.name,
          category: p.category,
          cancellation_count: p.total_cancellations,
          cancelled_value: p.cancelled_value,
          risk_level: p.risk_level
        })),
        recommendations: [
          summary.high_risk_products > 0 ? `Actualizează urgent stocul pentru ${summary.high_risk_products} produse cu risc ridicat` : null,
          summary.avg_stock_related_rate > '30%' ? 'Implementează verificare automată de stoc înainte de afișarea produselor' : null,
          summary.total_cancelled_value > 1000 ? 'Valoarea anulărilor este semnificativă - analizează procesul de gestionare a stocurilor' : null
        ].filter(Boolean)
      };
      
      console.log('🔗 Stock-cancellation correlation analysis completed:', {
        products_analyzed: result.summary.total_products_analyzed,
        high_risk: result.summary.high_risk_products,
        total_value_lost: result.summary.total_cancelled_value
      });
      
      res.json(result);
    });
    
  } catch (error) {
    console.error('❌ Error in stock-cancellation correlation analysis:', error);
    res.status(500).json({ error: 'Eroare la analiza corelației stoc-anulare' });
  }
});

// Funcție pentru găsirea produsului cel mai scump
function findMostExpensiveItem(items) {
  if (!items || items.length === 0) {
    return null;
  }

  return items.reduce((mostExpensive, current) => {
    const currentTotal = current.price * current.quantity;
    const mostExpensiveTotal = mostExpensive.price * mostExpensive.quantity;
    return currentTotal > mostExpensiveTotal ? current : mostExpensive;
  });
}

/**
 * Preluarea datelor agregate de comenzi și metrici pentru export, pe baza filtrelor de dată.
 * @param {string} startDate - Data de început (YYYY-MM-DD), poate fi null.
 * @param {string} endDate - Data de sfârșit (YYYY-MM-DD), poate fi null.
 * @param {string} period - Perioada rapidă ('today', 'yesterday', 'last7days', etc.).
 * @returns {Promise<Array<Object>>} O listă detaliată a comenzilor din perioada specificată.
 */
async function getFilteredOrdersForExport(startDate, endDate, period) {
    console.log('🔍 getFilteredOrdersForExport called:', { startDate, endDate, period });
    const db = await dbPromise;
    let whereClause = "WHERE 1=1";
    let params = [];

    // 1. Logica de rezolvare a intervalului de dată
    if (period === 'today') {
        // Folosim logica din getTodayOrders pentru a calcula intervalul 08:00 - 03:00
        const now = new Date();
        const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
        const startTime = new Date(today.getTime() + 8 * 60 * 60 * 1000); // 08:00
        const endTime = new Date(today.getTime() + 27 * 60 * 60 * 1000); // 03:00 următoarea zi
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
    } else if (period === 'yesterday') {
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const startTime = new Date(yesterday.getFullYear(), yesterday.getMonth(), yesterday.getDate(), 8, 0, 0);
        const endTime = new Date(yesterday.getFullYear(), yesterday.getMonth(), yesterday.getDate() + 1, 3, 0, 0);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
    } else if (period === 'last7days') {
        const endTime = new Date();
        const startTime = new Date(endTime.getTime() - 7 * 24 * 60 * 60 * 1000);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
    } else if (period === 'last30days') {
        const endTime = new Date();
        const startTime = new Date(endTime.getTime() - 30 * 24 * 60 * 60 * 1000);
        
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startTime.toISOString());
        params.push(endTime.toISOString());
    } else if (startDate && endDate) {
        // Filtrare pe date complete (presupunem YYYY-MM-DD)
        whereClause += " AND timestamp >= ? AND timestamp <= ?";
        params.push(startDate + 'T00:00:00.000Z');
        params.push(endDate + 'T23:59:59.999Z');
    }

    // 2. Interogarea efectivă a bazei de date - folosim coloanele care există în tabela orders
    const sql = `
        SELECT 
            id, timestamp, total, status, is_paid, table_number, 
            completed_timestamp, delivered_timestamp, client_identifier 
        FROM orders 
        ${whereClause} 
        ORDER BY timestamp DESC
    `;

    console.log('🔍 SQL Query:', sql);
    console.log('🔍 Params:', params);
    
    return new Promise((resolve, reject) => {
        db.all(sql, params, (err, rows) => {
            if (err) {
                console.error('❌ SQL Error:', err);
                return reject(err);
            }
            console.log('🔍 Query result:', rows.length, 'rows');
            resolve(rows);
        });
    });
}

