// Obține mesele disponibile pentru o dată și oră specifică
app.get('/api/reservations/available-tables', async (req, res) => {
    try {
        const { date, time, partySize } = req.query;
        
        if (!date || !time) {
            return res.status(400).json({ error: 'Data și ora sunt obligatorii' });
        }
        
        const db = await dbPromise;
        
        // Verifică rezervările existente pentru data și ora specificate
        const reservationDateTime = new Date(`${date}T${time}`);
        const reservationEndTime = new Date(reservationDateTime.getTime() + 2 * 60 * 60 * 1000); // +2 ore
        
        const existingReservations = await new Promise((resolve, reject) => {
            db.all(`
                SELECT table_id FROM reservations 
                WHERE reservation_date = ? 
                AND reservation_time BETWEEN ? AND ?
                AND status IN ('pending', 'confirmed')
            `, [date, time, reservationEndTime.toTimeString().slice(0, 5)], (err, rows) => {
                if (err) reject(err);
                else resolve(rows);
            });
        });
        
        const occupiedTableIds = existingReservations.map(r => r.table_id);
        
        // Obține toate mesele disponibile
        const availableTables = await new Promise((resolve, reject) => {
            let sql = `
                SELECT id, table_number, capacity, location, is_active
                FROM tables 
                WHERE is_active = 1
            `;
            
            const params = [];
            
            if (partySize) {
                sql += ' AND capacity >= ?';
                params.push(parseInt(partySize));
            }
            
            db.all(sql, params, (err, rows) => {
                if (err) reject(err);
                else resolve(rows);
            });
        });
        
        // Marchează mesele ca disponibile sau ocupate
        const tablesWithAvailability = availableTables.map(table => ({
            ...table,
            is_available: !occupiedTableIds.includes(table.id)
        }));
        
        res.json(tablesWithAvailability);
        
    } catch (error) {
        console.error('Eroare la obținerea meselor disponibile:', error);
        res.status(500).json({ error: 'Eroare la obținerea meselor disponibile' });
    }
});

// Creează o rezervare nouă
app.post('/api/reservations', async (req, res) => {
    try {
        console.log('📥 Rezervare primită - req.body:', req.body);
        
        const {
            tableId,
            customerName,
            customerPhone,
            customerEmail,
            reservationDate,
            reservationTime,
            partySize,
            specialRequests
        } = req.body;
        
        console.log('📋 Câmpuri extrase:', { 
            tableId, customerName, customerPhone, customerEmail, 
            reservationDate, reservationTime, partySize, specialRequests 
        });
        
        // Validare date obligatorii (tableId este opțional)
        if (!customerName || !customerPhone || !reservationDate || !reservationTime || !partySize) {
            console.error('❌ Validare eșuată - câmpuri lipsă:', {
                customerName: !!customerName,
                customerPhone: !!customerPhone,
                reservationDate: !!reservationDate,
                reservationTime: !!reservationTime,
                partySize: !!partySize
            });
            return res.status(400).json({ 
                success: false, 
                error: 'Toate câmpurile obligatorii trebuie completate (nume, telefon, dată, oră, persoane)' 
            });
        }
        
        // Validare dată și oră (permitem rezervări cu minim 30 minute în avans)
        const reservationDateTime = new Date(`${reservationDate}T${reservationTime}`);
        const now = new Date();
        const minDateTime = new Date(now.getTime() + 30 * 60 * 1000); // 30 minute în viitor
        
        if (reservationDateTime < minDateTime) {
            return res.status(400).json({ 
                success: false, 
                error: 'Rezervarea trebuie să fie cu cel puțin 30 minute în avans' 
            });
        }
        
        // Obține mesele disponibile
        const availableTables = await getAvailableTables(reservationDate, reservationTime, partySize);
        
        // Determină masa de folosit
        let finalTableId = tableId;
        if (!finalTableId) {
            // Alege automat prima masă disponibilă
            const firstAvailable = availableTables.find(t => t.is_available);
            if (!firstAvailable) {
                return res.status(400).json({ 
                    success: false, 
                    error: 'Nu există mese disponibile pentru data și ora specificate' 
                });
            }
            finalTableId = firstAvailable.id;
        } else {
            // Verifică dacă masa selectată este disponibilă
            const selectedTable = availableTables.find(table => table.id === parseInt(finalTableId));
            if (!selectedTable || !selectedTable.is_available) {
                return res.status(400).json({ 
                    success: false, 
                    error: 'Masa selectată nu este disponibilă pentru data și ora specificate' 
                });
            }
        }
        
        // Generează cod de confirmare
        const confirmationCode = `RES-${Date.now().toString().slice(-6)}`;
        
        const db = await dbPromise;
        
        // Inserează rezervarea în baza de date
        const result = await new Promise((resolve, reject) => {
            db.run(`
                INSERT INTO reservations (
                    table_id, customer_name, customer_phone, customer_email,
                    reservation_date, reservation_time, party_size, 
                    special_requests, confirmation_code, status, created_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?)
            `, [
                finalTableId, customerName, customerPhone, customerEmail,
                reservationDate, reservationTime, partySize,
                specialRequests || null, confirmationCode, new Date().toISOString()
            ], function(err) {
                if (err) reject(err);
                else resolve({ id: this.lastID });
            });
        });
        
        // Obține numărul mesei pentru răspuns
        const tableInfo = availableTables.find(t => t.id === parseInt(finalTableId));
        
        res.json({
            success: true,
            reservation: {
                id: result.id,
                confirmation_code: confirmationCode,
                customer_name: customerName,
                customer_phone: customerPhone,
                customer_email: customerEmail,
                reservation_date: reservationDate,
                reservation_time: reservationTime,
                party_size: partySize,
                table_number: tableInfo ? tableInfo.table_number : null,
                special_requests: specialRequests
            },
            message: 'Rezervarea a fost creată cu succes'
        });
        
    } catch (error) {
        console.error('Eroare la crearea rezervării:', error);
        res.status(500).json({ 
            success: false, 
            error: 'Eroare la crearea rezervării' 
        });
    }
});

// Obține toate rezervările cu filtrare opțională
app.get('/api/reservations', async (req, res) => {
    try {
        const { date, status } = req.query;
        
        const db = await dbPromise;
        
        let sql = `
            SELECT r.*, t.table_number, t.capacity, t.location
            FROM reservations r
            LEFT JOIN tables t ON r.table_id = t.id
        `;
        
        const params = [];
        const conditions = [];
        
        if (date) {
            conditions.push('r.reservation_date = ?');
            params.push(date);
        }
        
        if (status) {
            conditions.push('r.status = ?');
            params.push(status);
        }
        
        if (conditions.length > 0) {
            sql += ' WHERE ' + conditions.join(' AND ');
        }
        
        sql += ' ORDER BY r.reservation_date DESC, r.reservation_time DESC';
        
        const reservations = await new Promise((resolve, reject) => {
            db.all(sql, params, (err, rows) => {
                if (err) reject(err);
                else resolve(rows);
            });
        });
        
        res.json(reservations);
        
    } catch (error) {
        console.error('Eroare la obținerea rezervărilor:', error);
        res.status(500).json({ error: 'Eroare la obținerea rezervărilor' });
    }
});

