// Actualizează statusul unei rezervări
app.put('/api/reservations/:id/status', async (req, res) => {
    try {
        const { id } = req.params;
        const { status } = req.body;
        
        if (!status || !['pending', 'confirmed', 'cancelled', 'completed'].includes(status)) {
            return res.status(400).json({ 
                success: false, 
                error: 'Status invalid' 
            });
        }
        
        const db = await dbPromise;
        
        const result = await new Promise((resolve, reject) => {
            db.run(`
                UPDATE reservations 
                SET status = ?, updated_at = ?
                WHERE id = ?
            `, [status, new Date().toISOString(), id], function(err) {
                if (err) reject(err);
                else resolve({ changes: this.changes });
            });
        });
        
        if (result.changes === 0) {
            return res.status(404).json({ 
                success: false, 
                error: 'Rezervarea nu a fost găsită' 
            });
        }
        
        res.json({
            success: true,
            message: 'Statusul rezervării a fost actualizat cu succes'
        });
        
    } catch (error) {
        console.error('Eroare la actualizarea statusului rezervării:', error);
        res.status(500).json({ 
            success: false, 
            error: 'Eroare la actualizarea statusului rezervării' 
        });
    }
});

