// POST /api/verify-pin - Verifică PIN-ul pentru autentificarea staff-ului
app.post('/api/verify-pin', async (req, res) => {
  try {
    const { pin } = req.body;
    
    if (!pin) {
      return res.status(400).json({
        success: false,
        error: 'PIN-ul este obligatoriu'
      });
    }
    
    // PIN-uri valide pentru staff
    const validPins = {
      '5555': 'admin',        // PIN principal pentru admin
      '1234': 'bar',          // PIN pentru bar
      '5678': 'kitchen',      // PIN pentru bucătărie
      '9012': 'delivery',     // PIN pentru livrare
      '3456': 'waiter',       // PIN pentru ospătari
      '7890': 'supervisor'    // PIN pentru supervisor
    };
    
    if (validPins[pin]) {
      console.log(`✅ PIN valid: ${pin} pentru rolul: ${validPins[pin]}`);
      res.json({
        success: true,
        role: validPins[pin],
        message: 'Autentificare reușită'
      });
    } else {
      console.log(`❌ PIN invalid: ${pin}`);
      res.status(401).json({
        success: false,
        error: 'PIN incorect'
      });
    }
    
  } catch (error) {
    console.error('❌ Eroare la verificarea PIN-ului:', error);
    res.status(500).json({
      success: false,
      error: 'Eroare la verificarea PIN-ului'
    });
  }
});

// ==================== RAPOARTE FISCALE X, Z ȘI LUNARE ====================

// GET /api/reports/x - Raport X (intermediar zilnic - fără închidere)
app.get('/api/reports/x', async (req, res) => {
  try {
    const db = await dbPromise;
    const today = new Date().toISOString().split('T')[0];
    
    // Obține toate bonurile fiscale din ziua curentă
    const receipts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          fr.*,
          o.type as order_type,
          o.table_number,
          o.client_identifier
        FROM fiscal_receipts fr
        LEFT JOIN orders o ON fr.order_id = o.id
        WHERE DATE(fr.issue_date) = ?
        ORDER BY fr.issue_date ASC
      `, [today], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // Calculează totaluri
    const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
    const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
    const totalVAT = receipts.reduce((sum, r) => sum + r.vat_amount, 0);
    const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
    
    // Grupare pe categorii (aproximativ din orders)
    const orderIds = receipts.map(r => r.order_id).filter(id => id);
    
    res.json({
      success: true,
      reportType: 'X',
      reportDate: today,
      timestamp: new Date().toISOString(),
      summary: {
        totalReceipts: receipts.length,
        totalAmount: parseFloat(totalAmount.toFixed(2)),
        totalCash: parseFloat(totalCash.toFixed(2)),
        totalCard: parseFloat(totalCard.toFixed(2)),
        totalVAT: parseFloat(totalVAT.toFixed(2)),
        netAmount: parseFloat((totalAmount - totalVAT).toFixed(2))
      },
      receipts: receipts.map(r => ({
        receiptNumber: r.receipt_number,
        amount: r.total_amount,
        vat: r.vat_amount,
        paymentMethod: r.payment_method,
        time: r.issue_date
      })),
      note: 'Raport X - Intermediar (nu închide ziua)'
    });
    
  } catch (error) {
    console.error('❌ Eroare Raport X:', error);
    res.status(500).json({ 
      success: false, 
      error: 'Eroare la generarea raportului X' 
    });
  }
});

// GET /api/reports/z - Raport Z (închidere zilnică - resetare contor)
app.get('/api/reports/z', async (req, res) => {
  try {
    const db = await dbPromise;
    const today = new Date().toISOString().split('T')[0];
    
    // Verifică dacă există deja raport Z pentru azi
    const existingZ = await new Promise((resolve, reject) => {
      db.get(`
        SELECT * FROM daily_z_reports WHERE report_date = ?
      `, [today], (err, row) => {
        if (err && !err.message.includes('no such table')) reject(err);
        else resolve(row);
      });
    });
    
    if (existingZ) {
      return res.json({
        success: true,
        reportType: 'Z',
        reportDate: today,
        alreadyGenerated: true,
        data: existingZ,
        note: 'Raport Z deja generat pentru astăzi'
      });
    }
    
    // Obține toate bonurile fiscale din ziua curentă
    const receipts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          fr.*,
          o.type as order_type,
          o.items
        FROM fiscal_receipts fr
        LEFT JOIN orders o ON fr.order_id = o.id
        WHERE DATE(fr.issue_date) = ? AND fr.is_fiscal = 1
        ORDER BY fr.issue_date ASC
      `, [today], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // Calculează totaluri
    const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
    const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
    const totalVAT = receipts.reduce((sum, r) => sum + r.vat_amount, 0);
    const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
    
    // Analiză pe categorii
    const categorySales = {};
    for (const receipt of receipts) {
      if (receipt.items) {
        try {
          const items = JSON.parse(receipt.items);
          for (const item of items) {
            const category = item.category || 'Altele';
            if (!categorySales[category]) {
              categorySales[category] = { count: 0, total: 0 };
            }
            categorySales[category].count += item.quantity || 1;
            categorySales[category].total += (item.price || 0) * (item.quantity || 1);
          }
        } catch (e) {
          // Skip dacă items nu e JSON valid
        }
      }
    }
    
    const reportData = {
      report_date: today,
      total_receipts: receipts.length,
      total_amount: parseFloat(totalAmount.toFixed(2)),
      total_cash: parseFloat(totalCash.toFixed(2)),
      total_card: parseFloat(totalCard.toFixed(2)),
      total_vat: parseFloat(totalVAT.toFixed(2)),
      net_amount: parseFloat((totalAmount - totalVAT).toFixed(2)),
      first_receipt: receipts.length > 0 ? receipts[0].receipt_number : null,
      last_receipt: receipts.length > 0 ? receipts[receipts.length - 1].receipt_number : null,
      generated_at: new Date().toISOString()
    };
    
    // Salvează raportul Z în baza de date (pentru a nu se genera de 2 ori)
    try {
      await new Promise((resolve, reject) => {
        db.run(`
          CREATE TABLE IF NOT EXISTS daily_z_reports (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            report_date DATE UNIQUE NOT NULL,
            total_receipts INTEGER,
            total_amount REAL,
            total_cash REAL,
            total_card REAL,
            total_vat REAL,
            net_amount REAL,
            first_receipt TEXT,
            last_receipt TEXT,
            generated_at DATETIME,
            generated_by TEXT
          )
        `, (err) => {
          if (err) reject(err);
          else resolve();
        });
      });
      
      await new Promise((resolve, reject) => {
        db.run(`
          INSERT INTO daily_z_reports (
            report_date, total_receipts, total_amount, total_cash, total_card,
            total_vat, net_amount, first_receipt, last_receipt, generated_at
          ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `, [
          reportData.report_date,
          reportData.total_receipts,
          reportData.total_amount,
          reportData.total_cash,
          reportData.total_card,
          reportData.total_vat,
          reportData.net_amount,
          reportData.first_receipt,
          reportData.last_receipt,
          reportData.generated_at
        ], (err) => {
          if (err) reject(err);
          else resolve();
        });
      });
    } catch (saveError) {
      console.warn('⚠️ Nu s-a putut salva raportul Z:', saveError.message);
    }
    
    res.json({
      success: true,
      reportType: 'Z',
      reportDate: today,
      summary: {
        totalReceipts: reportData.total_receipts,
        totalAmount: reportData.total_amount,
        totalCash: reportData.total_cash,
        totalCard: reportData.total_card,
        totalVAT: reportData.total_vat,
        netAmount: reportData.net_amount
      },
      period: {
        firstReceipt: reportData.first_receipt,
        lastReceipt: reportData.last_receipt,
        startTime: receipts.length > 0 ? receipts[0].issue_date : null,
        endTime: receipts.length > 0 ? receipts[receipts.length - 1].issue_date : null
      },
      categorySales: Object.entries(categorySales).map(([cat, data]) => ({
        category: cat,
        quantity: data.count,
        total: parseFloat(data.total.toFixed(2))
      })),
      receipts: receipts.map(r => ({
        number: r.receipt_number,
        amount: r.total_amount,
        vat: r.vat_amount,
        method: r.payment_method,
        time: r.issue_date
      })),
      note: 'Raport Z - Închidere zilnică (salvat în daily_z_reports)'
    });
    
  } catch (error) {
    console.error('❌ Eroare Raport Z:', error);
    res.status(500).json({ 
      success: false, 
      error: 'Eroare la generarea raportului Z' 
    });
  }
});

// GET /api/reports/monthly - Raport lunar
app.get('/api/reports/monthly', async (req, res) => {
  try {
    const { year, month } = req.query;
    const db = await dbPromise;
    
    const currentYear = year || new Date().getFullYear();
    const currentMonth = month || (new Date().getMonth() + 1);
    
    // Obține toate bonurile din luna specificată
    const receipts = await new Promise((resolve, reject) => {
      db.all(`
        SELECT 
          fr.*,
          o.type as order_type
        FROM fiscal_receipts fr
        LEFT JOIN orders o ON fr.order_id = o.id
        WHERE strftime('%Y', fr.issue_date) = ? 
        AND strftime('%m', fr.issue_date) = ?
        AND fr.is_fiscal = 1
        ORDER BY fr.issue_date ASC
      `, [currentYear.toString(), currentMonth.toString().padStart(2, '0')], (err, rows) => {
        if (err) reject(err);
        else resolve(rows || []);
      });
    });
    
    // Calculează totaluri
    const totalCash = receipts.filter(r => r.payment_method === 'cash').reduce((sum, r) => sum + r.total_amount, 0);
    const totalCard = receipts.filter(r => r.payment_method === 'card').reduce((sum, r) => sum + r.total_amount, 0);
    const totalVAT = receipts.reduce((sum, r) => sum + r.vat_amount, 0);
    const totalAmount = receipts.reduce((sum, r) => sum + r.total_amount, 0);
    
    // Grupare pe zile
    const dailyStats = {};
    receipts.forEach(r => {
      const day = r.issue_date.split('T')[0];
      if (!dailyStats[day]) {
        dailyStats[day] = { receipts: 0, amount: 0, vat: 0 };
      }
      dailyStats[day].receipts++;
      dailyStats[day].amount += r.total_amount;
      dailyStats[day].vat += r.vat_amount;
    });
    
    // Grupare pe metode de plată
    const paymentMethods = {
      cash: { count: 0, amount: 0 },
      card: { count: 0, amount: 0 }
    };
    
    receipts.forEach(r => {
      const method = r.payment_method || 'cash';
      if (!paymentMethods[method]) {
        paymentMethods[method] = { count: 0, amount: 0 };
      }
      paymentMethods[method].count++;
      paymentMethods[method].amount += r.total_amount;
    });
    
    res.json({
      success: true,
      reportType: 'MONTHLY',
      period: {
        year: parseInt(currentYear),
        month: parseInt(currentMonth),
        monthName: new Date(currentYear, currentMonth - 1).toLocaleString('ro-RO', { month: 'long' })
      },
      summary: {
        totalReceipts: receipts.length,
        totalAmount: parseFloat(totalAmount.toFixed(2)),
        totalCash: parseFloat(totalCash.toFixed(2)),
        totalCard: parseFloat(totalCard.toFixed(2)),
        totalVAT: parseFloat(totalVAT.toFixed(2)),
        netAmount: parseFloat((totalAmount - totalVAT).toFixed(2)),
        averageReceiptValue: receipts.length > 0 ? parseFloat((totalAmount / receipts.length).toFixed(2)) : 0
      },
      dailyBreakdown: Object.entries(dailyStats).map(([date, stats]) => ({
        date,
        receipts: stats.receipts,
        amount: parseFloat(stats.amount.toFixed(2)),
        vat: parseFloat(stats.vat.toFixed(2))
      })).sort((a, b) => a.date.localeCompare(b.date)),
      paymentMethods: Object.entries(paymentMethods).map(([method, stats]) => ({
        method,
        count: stats.count,
        amount: parseFloat(stats.amount.toFixed(2)),
        percentage: receipts.length > 0 ? parseFloat(((stats.count / receipts.length) * 100).toFixed(2)) : 0
      })),
      note: 'Raport lunar - toate bonurile fiscale din perioada specificată'
    });
    
  } catch (error) {
    console.error('❌ Eroare Raport Lunar:', error);
    res.status(500).json({ 
      success: false, 
      error: 'Eroare la generarea raportului lunar' 
    });
  }
});

