// Apply promotion code
app.post('/api/promotions/apply', async (req, res) => {
    try {
        const { promo_code, order_amount, order_items } = req.body;
        
        if (!promo_code) {
            return res.status(400).json({ 
                success: false, 
                error: 'Codul promoțional este obligatoriu' 
            });
        }
        
        const db = await dbPromise;
        
        // Find promotion
        const promotion = await new Promise((resolve, reject) => {
            db.get(`
                SELECT * FROM promotions 
                WHERE promo_code = ? 
                AND is_active = 1 
                AND (start_date IS NULL OR start_date <= datetime('now'))
                AND (end_date IS NULL OR end_date >= datetime('now'))
                AND (usage_limit IS NULL OR usage_count < usage_limit)
            `, [promo_code], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!promotion) {
            return res.status(404).json({ 
                success: false, 
                error: 'Cod promoțional invalid sau expirat' 
            });
        }
        
        // Check minimum order amount
        if (promotion.min_order_amount && order_amount < promotion.min_order_amount) {
            return res.status(400).json({ 
                success: false, 
                error: `Valoarea minimă a comenzii este ${promotion.min_order_amount} RON` 
            });
        }
        
        // Calculate discount
        let discountAmount = 0;
        switch (promotion.discount_type) {
            case 'percentage':
                discountAmount = order_amount * (promotion.discount_value / 100);
                if (promotion.max_discount) {
                    discountAmount = Math.min(discountAmount, promotion.max_discount);
                }
                break;
            case 'fixed':
                discountAmount = promotion.discount_value;
                break;
            case 'buy_x_get_y':
                // Implementation for buy X get Y logic
                discountAmount = 0; // Placeholder
                break;
        }
        
        res.json({
            success: true,
            promotion: {
                id: promotion.id,
                title: promotion.title,
                description: promotion.description,
                discount_type: promotion.discount_type,
                discount_value: promotion.discount_value,
                discount_amount: discountAmount,
                promo_code: promotion.promo_code
            }
        });
        
    } catch (error) {
        console.error('❌ Error applying promotion:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

