// 1. Submit feedback
app.post('/api/feedback/submit', async (req, res) => {
    try {
        const {
            order_id,
            table_number,
            customer_phone,
            customer_email,
            rating,
            food_quality,
            service_quality,
            ambiance,
            cleanliness,
            value_for_money,
            comments,
            suggestions,
            would_recommend
        } = req.body;
        
        const db = await dbPromise;
        
        // Validare rating
        if (!rating || rating < 1 || rating > 5) {
            return res.status(400).json({ 
                success: false, 
                error: 'Rating-ul trebuie să fie între 1 și 5' 
            });
        }
        
        // Salvează feedback-ul
        const feedbackResult = await new Promise((resolve, reject) => {
            db.run(`
                INSERT INTO customer_feedback (
                    order_id, table_number, customer_phone, customer_email,
                    rating, food_quality, service_quality, ambiance, 
                    cleanliness, value_for_money, comments, suggestions,
                    would_recommend, feedback_timestamp
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now', 'localtime'))
            `, [
                order_id, table_number, customer_phone, customer_email,
                rating, food_quality, service_quality, ambiance,
                cleanliness, value_for_money, comments, suggestions,
                would_recommend
            ], function(err) {
                if (err) reject(err);
                else resolve({ insertId: this.lastID });
            });
        });
        
        // Actualizează statisticile zilnice
        await updateDailySatisfactionStats(db);
        
        // Verifică dacă sunt probleme care necesită atenție
        if (rating <= 2) {
            await new Promise((resolve, reject) => {
                db.run(`
                    INSERT INTO customer_issues (
                        feedback_id, issue_type, issue_description, priority, status
                    ) VALUES (?, ?, ?, ?, ?)
                `, [
                    feedbackResult.insertId,
                    'low_rating',
                    `Rating scăzut: ${rating}/5. Comentarii: ${comments || 'N/A'}`,
                    rating === 1 ? 'high' : 'medium',
                    'open'
                ], function(err) {
                    if (err) reject(err);
                    else resolve();
                });
            });
        }
        
        res.json({
            success: true,
            feedback_id: feedbackResult.insertId,
            message: 'Feedback-ul a fost trimis cu succes! Mulțumim pentru timpul acordat.',
            incentive: rating >= 4 ? 'Reducere 10% la următoarea comandă!' : null
        });
        
    } catch (error) {
        console.error('❌ Error submitting feedback:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// 2. Get satisfaction statistics
app.get('/api/feedback/stats', async (req, res) => {
    try {
        const { period = '30' } = req.query;
        const db = await dbPromise;
        
        // Statistici generale
        const generalStats = await new Promise((resolve, reject) => {
            db.get(`
                SELECT 
                    COUNT(*) as total_feedback,
                    AVG(rating) as avg_rating,
                    AVG(food_quality) as avg_food_quality,
                    AVG(service_quality) as avg_service_quality,
                    AVG(ambiance) as avg_ambiance,
                    AVG(cleanliness) as avg_cleanliness,
                    AVG(value_for_money) as avg_value_for_money,
                    SUM(CASE WHEN would_recommend = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(*) as recommendation_rate,
                    SUM(CASE WHEN rating >= 4 THEN 1 ELSE 0 END) as positive_feedback,
                    SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as negative_feedback
                FROM customer_feedback 
                WHERE feedback_timestamp >= datetime('now', '-${period} days')
            `, (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        // Statistici pe zile
        const dailyStats = await new Promise((resolve, reject) => {
            db.all(`
                SELECT 
                    DATE(feedback_timestamp) as date,
                    COUNT(*) as daily_feedback,
                    AVG(rating) as daily_avg_rating,
                    SUM(CASE WHEN rating >= 4 THEN 1 ELSE 0 END) as daily_positive,
                    SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as daily_negative
                FROM customer_feedback 
                WHERE feedback_timestamp >= datetime('now', '-${period} days')
                GROUP BY DATE(feedback_timestamp)
                ORDER BY date DESC
            `, (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });
        
        // Probleme deschise
        const openIssues = await new Promise((resolve, reject) => {
            db.all(`
                SELECT 
                    ci.*,
                    cf.rating,
                    cf.comments,
                    cf.table_number
                FROM customer_issues ci
                JOIN customer_feedback cf ON ci.feedback_id = cf.id
                WHERE ci.status = 'open'
                ORDER BY ci.priority DESC, ci.created_at DESC
            `, (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });
        
        res.json({
            success: true,
            period: `${period} days`,
            general_stats: generalStats,
            daily_stats: dailyStats,
            open_issues: openIssues,
            summary: {
                total_feedback: generalStats.total_feedback || 0,
                avg_rating: Math.round((generalStats.avg_rating || 0) * 10) / 10,
                recommendation_rate: Math.round((generalStats.recommendation_rate || 0) * 10) / 10,
                positive_rate: Math.round(((generalStats.positive_feedback || 0) / (generalStats.total_feedback || 1)) * 100),
                negative_rate: Math.round(((generalStats.negative_feedback || 0) / (generalStats.total_feedback || 1)) * 100),
                open_issues_count: openIssues.length
            }
        });
        
    } catch (error) {
        console.error('❌ Error fetching feedback stats:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

