// 4. Update daily satisfaction stats
async function updateDailySatisfactionStats(db) {
    try {
        const today = new Date().toISOString().split('T')[0];
        
        const stats = await new Promise((resolve, reject) => {
            db.get(`
                SELECT 
                    COUNT(*) as total_feedback,
                    AVG(rating) as avg_rating,
                    AVG(food_quality) as avg_food_quality,
                    AVG(service_quality) as avg_service_quality,
                    AVG(ambiance) as avg_ambiance,
                    AVG(cleanliness) as avg_cleanliness,
                    AVG(value_for_money) as avg_value_for_money,
                    SUM(CASE WHEN would_recommend = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(*) as recommendation_rate,
                    SUM(CASE WHEN rating >= 4 THEN 1 ELSE 0 END) as positive_feedback,
                    SUM(CASE WHEN rating <= 2 THEN 1 ELSE 0 END) as negative_feedback
                FROM customer_feedback 
                WHERE DATE(feedback_timestamp) = ?
            `, [today], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (stats && stats.total_feedback > 0) {
            await new Promise((resolve, reject) => {
                db.run(`
                    INSERT OR REPLACE INTO satisfaction_stats (
                        date, total_feedback, avg_rating, avg_food_quality,
                        avg_service_quality, avg_ambiance, avg_cleanliness,
                        avg_value_for_money, recommendation_rate,
                        positive_feedback, negative_feedback
                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                `, [
                    today, stats.total_feedback, stats.avg_rating,
                    stats.avg_food_quality, stats.avg_service_quality,
                    stats.avg_ambiance, stats.avg_cleanliness,
                    stats.avg_value_for_money, stats.recommendation_rate,
                    stats.positive_feedback, stats.negative_feedback
                ], function(err) {
                    if (err) reject(err);
                    else resolve();
                });
            });
        }
    } catch (error) {
        console.error('❌ Error updating daily stats:', error);
    }
}

