// 1. API endpoint pentru calcul total comandă
app.get('/api/orders/:orderId/calculate-total', async (req, res) => {
    try {
        const { orderId } = req.params;
        const db = await dbPromise;
        
        // Găsește comanda cu toate item-urile
        const order = await new Promise((resolve, reject) => {
            db.get(`
                SELECT items, total
                FROM orders
                WHERE id = ?
            `, [orderId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!order) {
            return res.status(404).json({ success: false, error: 'Comanda nu a fost găsită' });
        }
        
        // Parsează item-urile din JSON
        let items = [];
        try {
            items = JSON.parse(order.items || '[]');
        } catch (error) {
            console.error('Error parsing order items:', error);
            items = [];
        }
        
        // Completează finalPrice din meniu dacă lipsește
        for (let item of items) {
            if (!item.finalPrice && item.productId) {
                const menuItem = await new Promise((resolve, reject) => {
                    db.get('SELECT price FROM menu WHERE id = ?', [item.productId], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
                if (menuItem) {
                    item.finalPrice = menuItem.price;
                }
            }
        }
        
        // Calculează subtotal
        const subtotal = items.reduce((sum, item) => {
            if (item.isFree) return sum;
            return sum + (item.quantity * (item.finalPrice || 0));
        }, 0);
        
        // Calculează TVA (11% România - cota redusă pentru alimente)
        const vatRate = 0.11;
        const vatAmount = subtotal * vatRate;
        
        // Total final
        const total = subtotal + vatAmount;
        
        res.json({
            success: true,
            subtotal: subtotal.toFixed(2),
            vat_rate: (vatRate * 100).toFixed(0) + '%',
            vat_amount: vatAmount.toFixed(2),
            total: total.toFixed(2),
            items_count: items.length
        });
        
    } catch (error) {
        console.error('❌ Error calculating total:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// 2. API endpoint pentru închidere masă și plată
app.post('/api/orders/:orderId/close-and-pay', async (req, res) => {
    try {
        const { orderId } = req.params;
        const { 
            payment_method,  // 'cash' sau 'card'
            amount_paid,     // suma primită
            tip_amount,      // bacșiș (opțional)
            split_count,     // număr persoane pentru split bill
            notes           // note (opțional)
        } = req.body;
        const db = await dbPromise;
        
        // Validare
        if (!payment_method || !amount_paid) {
            return res.status(400).json({ 
                success: false, 
                error: 'payment_method și amount_paid sunt obligatorii' 
            });
        }
        
        // Calculează totalul
        const order = await new Promise((resolve, reject) => {
            db.get(`
                SELECT items, total
                FROM orders
                WHERE id = ?
            `, [orderId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!order) {
            return res.status(404).json({ success: false, error: 'Comanda nu a fost găsită' });
        }
        
        // Parsează item-urile din JSON
        let items = [];
        try {
            items = JSON.parse(order.items || '[]');
        } catch (error) {
            console.error('Error parsing order items:', error);
            items = [];
        }
        
        // Completează finalPrice din meniu dacă lipsește
        for (let item of items) {
            if (!item.finalPrice && item.productId) {
                const menuItem = await new Promise((resolve, reject) => {
                    db.get('SELECT price FROM menu WHERE id = ?', [item.productId], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
                if (menuItem) {
                    item.finalPrice = menuItem.price;
                }
            }
        }
        
        const subtotal = items.reduce((sum, item) => {
            if (item.isFree) return sum;
            return sum + (item.quantity * (item.finalPrice || 0));
        }, 0);
        
        const vatAmount = subtotal * 0.11; // TVA 11% alimente
        const total = subtotal + vatAmount;
        
        // Calculează rest
        const change = amount_paid - total;
        
        if (change < 0) {
            return res.status(400).json({ 
                success: false, 
                error: 'Suma plătită este insuficientă',
                required: total.toFixed(2),
                paid: amount_paid.toFixed(2)
            });
        }
        
        // Salvează plata în baza de date
        const paymentResult = await new Promise((resolve, reject) => {
            db.run(`
                INSERT INTO payments (
                    order_id,
                    payment_method,
                    subtotal,
                    vat_amount,
                    total_amount,
                    amount_paid,
                    change_amount,
                    tip_amount,
                    split_count,
                    payment_timestamp,
                    notes
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, datetime('now', 'localtime'), ?)
            `, [
                orderId,
                payment_method,
                subtotal,
                vatAmount,
                total,
                amount_paid,
                change,
                tip_amount || 0,
                split_count || 1,
                notes || null
            ], function(err) {
                if (err) reject(err);
                else resolve({ insertId: this.lastID });
            });
        });
        
        // Actualizează statusul comenzii la 'paid'
        await new Promise((resolve, reject) => {
            db.run(`
                UPDATE orders 
                SET status = 'paid', 
                    closed_at = datetime('now', 'localtime')
                WHERE id = ?
            `, [orderId], (err) => {
                if (err) reject(err);
                else resolve();
            });
        });
        
        // Marchează masa ca liberă
        await new Promise((resolve, reject) => {
            db.run(`
                UPDATE tables 
                SET status = 'available', 
                    current_order_id = NULL 
                WHERE table_number = (SELECT table_number FROM orders WHERE id = ?)
            `, [orderId], (err) => {
                if (err) reject(err);
                else resolve();
            });
        });
        
        // 🆕 SCADE STOCURILE PENTRU COMANDĂ (02 NOV 2025)
        let stockResult = null;
        try {
            stockResult = await decrementStockForOrder(orderId);
            console.log(`✅ Stocuri scăzute pentru comanda ${orderId}:`, stockResult.decremented.length, 'ingrediente');
            if (stockResult.warnings.length > 0) {
                console.warn(`⚠️ Avertizări stoc pentru comanda ${orderId}:`, stockResult.warnings);
            }
        } catch (error) {
            console.error(`❌ Eroare la scăderea stocurilor pentru comanda ${orderId}:`, error);
            // Nu blocăm plata dacă scăderea stocurilor eșuează - doar logăm eroarea
        }
        
        res.json({
            success: true,
            payment_id: paymentResult.insertId,
            order_id: orderId,
            subtotal: subtotal.toFixed(2),
            vat: vatAmount.toFixed(2),
            total: total.toFixed(2),
            paid: amount_paid.toFixed(2),
            change: change.toFixed(2),
            tip: (tip_amount || 0).toFixed(2),
            payment_method: payment_method,
            stock_decremented: stockResult ? stockResult.decremented.length : 0,
            stock_warnings: stockResult ? stockResult.warnings : []
        });
        
    } catch (error) {
        console.error('❌ Error processing payment:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// 3. API pentru split bill
app.post('/api/orders/:orderId/split-bill', async (req, res) => {
    try {
        const { orderId } = req.params;
        const { split_count } = req.body; // câte persoane împart bonul
        const db = await dbPromise;
        
        if (!split_count || split_count < 2) {
            return res.status(400).json({ 
                success: false, 
                error: 'split_count trebuie să fie minim 2' 
            });
        }
        
        // Calculează totalul
        const order = await new Promise((resolve, reject) => {
            db.get(`
                SELECT items, total
                FROM orders
                WHERE id = ?
            `, [orderId], (err, row) => {
                if (err) reject(err);
                else resolve(row);
            });
        });
        
        if (!order) {
            return res.status(404).json({ success: false, error: 'Comanda nu a fost găsită' });
        }
        
        // Parsează item-urile din JSON
        let items = [];
        try {
            items = JSON.parse(order.items || '[]');
        } catch (error) {
            console.error('Error parsing order items:', error);
            items = [];
        }
        
        // Completează finalPrice din meniu dacă lipsește
        for (let item of items) {
            if (!item.finalPrice && item.productId) {
                const menuItem = await new Promise((resolve, reject) => {
                    db.get('SELECT price FROM menu WHERE id = ?', [item.productId], (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    });
                });
                if (menuItem) {
                    item.finalPrice = menuItem.price;
                }
            }
        }
        
        const subtotal = items.reduce((sum, item) => {
            if (item.isFree) return sum;
            return sum + (item.quantity * (item.finalPrice || 0));
        }, 0);
        
        const vatAmount = subtotal * 0.11; // TVA 11% alimente
        const total = subtotal + vatAmount;
        
        // Împarte bonul
        const perPerson = total / split_count;
        
        res.json({
            success: true,
            total: total.toFixed(2),
            split_count: split_count,
            per_person: perPerson.toFixed(2),
            breakdown: {
                subtotal: subtotal.toFixed(2),
                vat: vatAmount.toFixed(2),
                total: total.toFixed(2)
            }
        });
        
    } catch (error) {
        console.error('❌ Error splitting bill:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

// 4. API pentru istoric plăți
app.get('/api/payments/history', async (req, res) => {
    try {
        const { limit = 50, offset = 0 } = req.query;
        const db = await dbPromise;
        
        const payments = await new Promise((resolve, reject) => {
            db.all(`
                SELECT 
                    p.*,
                    o.table_number,
                    o.client_identifier,
                    o.total as order_total
                FROM payments p
                LEFT JOIN orders o ON p.order_id = o.id
                ORDER BY p.payment_timestamp DESC
                LIMIT ? OFFSET ?
            `, [parseInt(limit), parseInt(offset)], (err, rows) => {
                if (err) reject(err);
                else resolve(rows || []);
            });
        });
        
        res.json({
            success: true,
            payments: payments,
            count: payments.length
        });
        
    } catch (error) {
        console.error('❌ Error fetching payment history:', error);
        res.status(500).json({ success: false, error: error.message });
    }
});

