// 🌐 TRANSLATION SYSTEM V3.0.0 - API ENDPOINTS
// ========================================

/**
 * POST /api/missing-translations
 * 
 * Receives missing translation keys reported by frontend
 * Stores them in missing-translations.json for manual translation
 */
app.post('/api/missing-translations', async (req, res) => {
    try {
        const { keys, language, page, timestamp } = req.body;
        
        // Validate input
        if (!keys || !Array.isArray(keys) || keys.length === 0) {
            return res.status(400).json({
                success: false,
                error: 'Invalid request: keys array is required'
            });
        }
        
        const missingTranslationsPath = path.join(__dirname, 'missing-translations.json');
        
        // Load existing missing translations
        let missingTranslations = [];
        if (fs.existsSync(missingTranslationsPath)) {
            try {
                const content = fs.readFileSync(missingTranslationsPath, 'utf8');
                missingTranslations = JSON.parse(content);
            } catch (parseError) {
                console.warn('[Missing Translations] Error parsing existing file, starting fresh:', parseError.message);
                missingTranslations = [];
            }
        }
        
        // Add new keys (avoid duplicates)
        const existingKeys = new Set(missingTranslations.map(item => item.key));
        let newKeysCount = 0;
        
        keys.forEach(key => {
            if (!existingKeys.has(key)) {
                missingTranslations.push({
                    key,
                    language: language || 'unknown',
                    page: page || 'unknown',
                    timestamp: timestamp || new Date().toISOString(),
                    status: 'reported',
                    notes: ''
                });
                existingKeys.add(key);
                newKeysCount++;
            }
        });
        
        // Save updated file
        fs.writeFileSync(
            missingTranslationsPath,
            JSON.stringify(missingTranslations, null, 2),
            'utf8'
        );
        
        console.log(`[Missing Translations] Recorded ${newKeysCount} new keys (${keys.length} total received)`);
        
        res.json({
            success: true,
            message: `${newKeysCount} new missing keys recorded`,
            keys_recorded: newKeysCount,
            total_keys: keys.length
        });
        
    } catch (error) {
        console.error('[Missing Translations] Error:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * GET /api/missing-translations
 * 
 * Returns all missing translations
 * Optional query params: ?status=reported|in_progress|completed
 */
app.get('/api/missing-translations', async (req, res) => {
    try {
        const { status } = req.query;
        
        const missingTranslationsPath = path.join(__dirname, 'missing-translations.json');
        
        if (!fs.existsSync(missingTranslationsPath)) {
            return res.json({
                success: true,
                translations: [],
                count: 0
            });
        }
        
        const content = fs.readFileSync(missingTranslationsPath, 'utf8');
        let translations = JSON.parse(content);
        
        // Filter by status if provided
        if (status) {
            translations = translations.filter(t => t.status === status);
        }
        
        res.json({
            success: true,
            translations,
            count: translations.length
        });
        
    } catch (error) {
        console.error('[Missing Translations] Error fetching:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * PUT /api/missing-translations/:key
 * 
 * Update status/notes for a missing translation
 */
app.put('/api/missing-translations/:key', async (req, res) => {
    try {
        const { key } = req.params;
        const { status, notes } = req.body;
        
        const missingTranslationsPath = path.join(__dirname, 'missing-translations.json');
        
        if (!fs.existsSync(missingTranslationsPath)) {
            return res.status(404).json({
                success: false,
                error: 'No missing translations file found'
            });
        }
        
        const content = fs.readFileSync(missingTranslationsPath, 'utf8');
        const translations = JSON.parse(content);
        
        // Find and update the translation
        const translation = translations.find(t => t.key === key);
        
        if (!translation) {
            return res.status(404).json({
                success: false,
                error: 'Translation key not found'
            });
        }
        
        if (status) translation.status = status;
        if (notes !== undefined) translation.notes = notes;
        translation.updated_at = new Date().toISOString();
        
        // Save updated file
        fs.writeFileSync(
            missingTranslationsPath,
            JSON.stringify(translations, null, 2),
            'utf8'
        );
        
        res.json({
            success: true,
            translation
        });
        
    } catch (error) {
        console.error('[Missing Translations] Error updating:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * DELETE /api/missing-translations/clear-completed
 * 
 * Delete all completed translations (MUST be before /:key route to avoid conflict)
 */
app.delete('/api/missing-translations/clear-completed', async (req, res) => {
    try {
        const missingTranslationsPath = path.join(__dirname, 'missing-translations.json');
        
        if (!fs.existsSync(missingTranslationsPath)) {
            return res.json({
                success: true,
                deleted: 0
            });
        }
        
        const content = fs.readFileSync(missingTranslationsPath, 'utf8');
        const translations = JSON.parse(content);
        
        // Filter out completed translations
        const initialCount = translations.length;
        const remaining = translations.filter(t => t.status !== 'completed');
        const deletedCount = initialCount - remaining.length;
        
        // Save updated file
        fs.writeFileSync(
            missingTranslationsPath,
            JSON.stringify(remaining, null, 2),
            'utf8'
        );
        
        console.log(`[Missing Translations] Deleted ${deletedCount} completed translations`);
        
        res.json({
            success: true,
            deleted: deletedCount
        });
        
    } catch (error) {
        console.error('[Missing Translations] Error clearing completed:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * DELETE /api/missing-translations/:key
 * 
 * Delete a single translation by key (used when marking as completed/already translated)
 */
app.delete('/api/missing-translations/:key', async (req, res) => {
    try {
        const { key } = req.params;
        
        const missingTranslationsPath = path.join(__dirname, 'missing-translations.json');
        
        if (!fs.existsSync(missingTranslationsPath)) {
            return res.json({
                success: true,
                message: 'No translations file found'
            });
        }
        
        const content = fs.readFileSync(missingTranslationsPath, 'utf8');
        const translations = JSON.parse(content);
        
        // Filter out the translation with the specified key
        const remaining = translations.filter(t => t.key !== key);
        
        // Save updated file
        fs.writeFileSync(
            missingTranslationsPath,
            JSON.stringify(remaining, null, 2),
            'utf8'
        );
        
        console.log(`[Missing Translations] Deleted translation: ${key}`);
        
        res.json({
            success: true,
            deleted: key
        });
        
    } catch (error) {
        console.error('[Missing Translations] Error deleting translation:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

