// 📷 BARCODE SCANNING API
// ========================================

/**
 * GET /api/barcode/lookup
 * Lookup barcode and return product/ingredient info
 */
app.get('/api/barcode/lookup', async (req, res) => {
    try {
        const { code, mode } = req.query;

        if (!code) {
            return res.status(400).json({
                success: false,
                error: 'Barcode code is required'
            });
        }

        console.log(`📷 [BARCODE] Lookup: ${code}, Mode: ${mode}`);

        const db = await dbPromise;
        let item = null;

        // Search based on mode
        if (mode === 'product' || mode === 'inventory') {
            // Search in menu table
            item = await new Promise((resolve, reject) => {
                db.get(
                    `SELECT id, name, category, price, stock_management, image_url 
                     FROM menu 
                     WHERE barcode = ? OR ean = ? OR sku = ?`,
                    [code, code, code],
                    (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    }
                );
            });

            if (item) {
                // Get stock info
                const stock = await new Promise((resolve, reject) => {
                    db.get(
                        `SELECT SUM(current_stock) as total_stock 
                         FROM product_stock 
                         WHERE product_id = ?`,
                        [item.id],
                        (err, row) => {
                            if (err) reject(err);
                            else resolve(row);
                        }
                    );
                });

                item.stock = stock?.total_stock || 0;
                item.unit = 'buc';
            }
        } else if (mode === 'ingredient' || mode === 'nir') {
            // Search in ingredients table
            item = await new Promise((resolve, reject) => {
                db.get(
                    `SELECT id, name, category, unit, current_stock, cost_per_unit as price 
                     FROM ingredients 
                     WHERE barcode = ? OR ean = ? OR sku = ?`,
                    [code, code, code],
                    (err, row) => {
                        if (err) reject(err);
                        else resolve(row);
                    }
                );
            });

            if (item) {
                item.stock = item.current_stock;
            }
        }

        if (item) {
            console.log(`✅ [BARCODE] Found: ${item.name}`);
            res.json({
                success: true,
                item: item
            });
        } else {
            console.log(`❌ [BARCODE] Not found: ${code}`);
            res.json({
                success: false,
                error: 'Item not found',
                code: code
            });
        }

    } catch (error) {
        console.error('❌ [BARCODE] Lookup error:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * POST /api/barcode/assign
 * Assign barcode to product or ingredient
 */
app.post('/api/barcode/assign', async (req, res) => {
    try {
        const { itemId, itemType, barcode, ean, sku } = req.body;

        if (!itemId || !itemType || !barcode) {
            return res.status(400).json({
                success: false,
                error: 'Item ID, type, and barcode are required'
            });
        }

        console.log(`📷 [BARCODE] Assign ${barcode} to ${itemType} #${itemId}`);

        const db = await dbPromise;
        const table = itemType === 'product' ? 'menu' : 'ingredients';

        await new Promise((resolve, reject) => {
            db.run(
                `UPDATE ${table} 
                 SET barcode = ?, ean = ?, sku = ? 
                 WHERE id = ?`,
                [barcode, ean || null, sku || null, itemId],
                function(err) {
                    if (err) reject(err);
                    else resolve(this);
                }
            );
        });

        console.log(`✅ [BARCODE] Assigned successfully`);

        res.json({
            success: true,
            message: 'Barcode assigned successfully'
        });

    } catch (error) {
        console.error('❌ [BARCODE] Assign error:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

