// 👨‍🍳 WAITER PERFORMANCE REPORTS API
// ========================================

/**
 * GET /api/reports/waiters
 * Get waiter performance statistics
 */
app.get('/api/reports/waiters', async (req, res) => {
    try {
        const { startDate, endDate, waiterId } = req.query;

        console.log(`📊 [WAITER REPORTS] Request: ${startDate} to ${endDate}, Waiter: ${waiterId || 'all'}`);

        const db = await dbPromise;

        // Build WHERE clause
        let whereConditions = ["status = 'paid'"];
        let params = [];

        if (startDate) {
            whereConditions.push("DATE(timestamp) >= ?");
            params.push(startDate);
        }
        if (endDate) {
            whereConditions.push("DATE(timestamp) <= ?");
            params.push(endDate);
        }
        if (waiterId) {
            whereConditions.push("waiter_id = ?");
            params.push(waiterId);
        }

        const whereClause = whereConditions.join(' AND ');

        // Get waiter statistics
        const stats = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    w.id as waiter_id,
                    w.name as waiter_name,
                    COUNT(o.id) as total_orders,
                    SUM(o.total) as total_revenue,
                    AVG(o.total) as avg_order_value,
                    MIN(o.total) as min_order,
                    MAX(o.total) as max_order,
                    COUNT(DISTINCT DATE(o.timestamp)) as days_worked
                 FROM waiters w
                 LEFT JOIN orders o ON w.id = o.waiter_id AND ${whereClause}
                 WHERE w.active = 1
                 GROUP BY w.id, w.name
                 ORDER BY total_revenue DESC`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        // Get daily breakdown for each waiter
        const dailyStats = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    w.id as waiter_id,
                    DATE(o.timestamp) as date,
                    COUNT(o.id) as orders,
                    SUM(o.total) as revenue
                 FROM waiters w
                 LEFT JOIN orders o ON w.id = o.waiter_id AND ${whereClause}
                 WHERE w.active = 1
                 GROUP BY w.id, DATE(o.timestamp)
                 ORDER BY date DESC`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        // Get top products per waiter
        const topProducts = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    w.id as waiter_id,
                    json_extract(value, '$.name') as product_name,
                    COUNT(*) as times_sold,
                    SUM(CAST(json_extract(value, '$.price') AS REAL) * CAST(json_extract(value, '$.quantity') AS INTEGER)) as revenue
                 FROM waiters w
                 LEFT JOIN orders o ON w.id = o.waiter_id AND ${whereClause}
                 LEFT JOIN json_each(o.items) 
                 WHERE w.active = 1 AND value IS NOT NULL
                 GROUP BY w.id, json_extract(value, '$.name')
                 ORDER BY w.id, times_sold DESC`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        console.log(`✅ [WAITER REPORTS] Found ${stats.length} waiters`);

        res.json({
            success: true,
            stats: stats.map(s => ({
                ...s,
                total_revenue: s.total_revenue || 0,
                total_orders: s.total_orders || 0,
                avg_order_value: s.avg_order_value || 0,
                min_order: s.min_order || 0,
                max_order: s.max_order || 0,
                days_worked: s.days_worked || 0
            })),
            dailyStats: dailyStats,
            topProducts: topProducts
        });

    } catch (error) {
        console.error('❌ [WAITER REPORTS] Error:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

/**
 * GET /api/reports/waiters/:id/details
 * Get detailed statistics for specific waiter
 */
app.get('/api/reports/waiters/:id/details', async (req, res) => {
    try {
        const { id } = req.params;
        const { startDate, endDate } = req.query;

        console.log(`📊 [WAITER DETAILS] Waiter #${id}, ${startDate} to ${endDate}`);

        const db = await dbPromise;

        // Get waiter info
        const waiter = await new Promise((resolve, reject) => {
            db.get(
                `SELECT id, name, pin, active, created_at FROM waiters WHERE id = ?`,
                [id],
                (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                }
            );
        });

        if (!waiter) {
            return res.status(404).json({
                success: false,
                error: 'Waiter not found'
            });
        }

        // Build WHERE clause
        let whereConditions = [`waiter_id = ?`, `status = 'paid'`];
        let params = [id];

        if (startDate) {
            whereConditions.push("DATE(timestamp) >= ?");
            params.push(startDate);
        }
        if (endDate) {
            whereConditions.push("DATE(timestamp) <= ?");
            params.push(endDate);
        }

        const whereClause = whereConditions.join(' AND ');

        // Overall stats
        const overallStats = await new Promise((resolve, reject) => {
            db.get(
                `SELECT 
                    COUNT(id) as total_orders,
                    SUM(total) as total_revenue,
                    AVG(total) as avg_order_value,
                    MIN(total) as min_order,
                    MAX(total) as max_order
                 FROM orders
                 WHERE ${whereClause}`,
                params,
                (err, row) => {
                    if (err) reject(err);
                    else resolve(row);
                }
            );
        });

        // Hourly distribution
        const hourlyStats = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    strftime('%H', timestamp) as hour,
                    COUNT(id) as orders,
                    SUM(total) as revenue
                 FROM orders
                 WHERE ${whereClause}
                 GROUP BY hour
                 ORDER BY hour`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        // Daily stats
        const dailyStats = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    DATE(timestamp) as date,
                    COUNT(id) as orders,
                    SUM(total) as revenue
                 FROM orders
                 WHERE ${whereClause}
                 GROUP BY DATE(timestamp)
                 ORDER BY date DESC
                 LIMIT 30`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        // Top 10 products
        const topProducts = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    json_extract(value, '$.name') as product_name,
                    json_extract(value, '$.category') as category,
                    COUNT(*) as times_sold,
                    SUM(CAST(json_extract(value, '$.quantity') AS INTEGER)) as total_quantity,
                    SUM(CAST(json_extract(value, '$.price') AS REAL) * CAST(json_extract(value, '$.quantity') AS INTEGER)) as revenue
                 FROM orders
                 LEFT JOIN json_each(items)
                 WHERE ${whereClause} AND value IS NOT NULL
                 GROUP BY json_extract(value, '$.name'), json_extract(value, '$.category')
                 ORDER BY times_sold DESC
                 LIMIT 10`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        // Recent orders
        const recentOrders = await new Promise((resolve, reject) => {
            db.all(
                `SELECT 
                    id,
                    table_number,
                    total,
                    timestamp,
                    items
                 FROM orders
                 WHERE ${whereClause}
                 ORDER BY timestamp DESC
                 LIMIT 20`,
                params,
                (err, rows) => {
                    if (err) reject(err);
                    else resolve(rows);
                }
            );
        });

        console.log(`✅ [WAITER DETAILS] Stats for ${waiter.name}`);

        res.json({
            success: true,
            waiter: waiter,
            stats: {
                overall: overallStats,
                hourly: hourlyStats,
                daily: dailyStats,
                topProducts: topProducts,
                recentOrders: recentOrders.map(o => ({
                    ...o,
                    items: JSON.parse(o.items)
                }))
            }
        });

    } catch (error) {
        console.error('❌ [WAITER DETAILS] Error:', error);
        res.status(500).json({
            success: false,
            error: error.message
        });
    }
});

