// fs și path sunt deja require-uite mai sus (linia 61 și implicit în nodejs)

/**
 * GET /api/config
 * Returnează configurația white-label (branding + restaurant)
 * Fără autentificare - folosit la load pagină
 */
app.get('/api/config', (req, res) => {
    try {
        const brandingPath = path.join(__dirname, 'config', 'branding.json');
        const restaurantPath = path.join(__dirname, 'config', 'restaurant.json');
        
        let branding = {};
        let restaurant = {};
        
        // Load branding.json
        if (fs.existsSync(brandingPath)) {
            const brandingData = fs.readFileSync(brandingPath, 'utf8');
            branding = JSON.parse(brandingData);
        } else {
            console.warn('⚠️  branding.json not found, using defaults');
        }
        
        // Load restaurant.json
        if (fs.existsSync(restaurantPath)) {
            const restaurantData = fs.readFileSync(restaurantPath, 'utf8');
            restaurant = JSON.parse(restaurantData);
        } else {
            console.warn('⚠️  restaurant.json not found, using defaults');
        }
        
        res.json({
            success: true,
            data: {
                branding,
                restaurant
            }
        });
    } catch (error) {
        console.error('[Config API] Error loading config:', error);
        res.status(500).json({
            success: false,
            error: 'Failed to load configuration'
        });
    }
});

